    #[test]
    fn mv_inner_chains_on_shared_reader() {
        // After §7.5.2 finishes, a sentinel byte appended to the
        // packet must still be readable via the shared reader. This
        // confirms the procedure stops at the right bit position.
        let nmbs = 1u32;
        let (nbs, luma, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let bcoded = vec![1u8; nbs as usize];
        let mbmodes = vec![MacroBlockMode::InterMv];

        let mut w = BitWriter::new();
        w.put(0, 1); // MVMODE=0
        write_mv_huffman_component(&mut w, 1); // 3 bits
        write_mv_huffman_component(&mut w, 1); // 3 bits
                                               // Total = 7 bits. Pad one bit to align to byte and emit 0xAB.
        w.put(0, 1); // pad to byte boundary
        w.put(0xAB, 8);
        let bytes = w.finish();

        let mut r = BitReader::new(&bytes);
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let _out = decode_macroblock_motion_vectors_inner(
            &mut r,
            FrameType::Inter,
            PixelFormat::Yuv420,
            nbs,
            nmbs,
            &bcoded,
            &mbmodes,
            &luma,
            ChromaBlockLayout { cb: &cb, cr: &cr },
        )
        .unwrap();
        // Consume the pad bit, then read the 0xAB sentinel.
        let _pad = r.read_bits(1, "pad").unwrap();
        let sentinel = r.read_bits(8, "sentinel").unwrap();
        assert_eq!(sentinel, 0xAB);
    }

    #[test]
    fn mv_intra_does_not_consume_bits() {
        // An intra frame must not consume the MVMODE bit (or anything
        // else). Use a packet whose first bit is 1 so we'd notice a
        // spurious read.
        let nmbs = 1u32;
        let (nbs, luma, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let bcoded = vec![1u8; nbs as usize];
        let mbmodes = vec![MacroBlockMode::Intra];
        let packet = vec![0xFFu8];

        let mut r = BitReader::new(&packet);
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let _ = decode_macroblock_motion_vectors_inner(
            &mut r,
            FrameType::Intra,
            PixelFormat::Yuv420,
            nbs,
            nmbs,
            &bcoded,
            &mbmodes,
            &luma,
            ChromaBlockLayout { cb: &cb, cr: &cr },
        )
        .unwrap();
        // No bits consumed.
        let next = r.read_bits(8, "sentinel").unwrap();
        assert_eq!(next, 0xFF);
    }

    #[test]
    fn mv_uncoded_luma_in_non_four_mode_does_not_overwrite_chroma() {
        // Step 3(g) iterates "each coded block bi". Uncoded blocks
        // (BCODED[bi]==0) should retain their (0, 0) default even when
        // the macroblock has an MV (e.g. INTER_MV with some chroma
        // uncoded).
        let nmbs = 1u32;
        let (nbs, luma, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let mut bcoded = vec![1u8; nbs as usize];
        // Mark the chroma Cb block uncoded.
        bcoded[cb_o[0][0] as usize] = 0;
        let mbmodes = vec![MacroBlockMode::InterMv];

        let mut w = BitWriter::new();
        w.put(0, 1);
        write_mv_huffman_component(&mut w, 6);
        write_mv_huffman_component(&mut w, -6);
        let bytes = w.finish();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let out = decode_macroblock_motion_vectors(
            &bytes,
            FrameType::Inter,
            PixelFormat::Yuv420,
            nbs,
            nmbs,
            &bcoded,
            &mbmodes,
            &luma,
            ChromaBlockLayout { cb: &cb, cr: &cr },
        )
        .unwrap();
        // Coded luma: propagated.
        for k in 0..4 {
            assert_eq!(out[luma[0][k] as usize], MotionVector::new(6, -6));
        }
        // Uncoded Cb: still zero.
        assert_eq!(out[cb_o[0][0] as usize], MotionVector::ZERO);
        // Coded Cr: propagated.
        assert_eq!(out[cr_o[0][0] as usize], MotionVector::new(6, -6));
    }

    // =================================================================
    // §7.6 Block-Level qi Decode tests
    // =================================================================

    /// VP3 fallback path (NQIS=1): the outer loop is empty, no bits
    /// are read, and every QIIS[bi] is 0.
    #[test]
    fn block_level_qi_nqis_1_short_circuits_no_bits_consumed() {
        let bcoded = vec![1u8, 1, 0, 1, 0];
        // Sentinel byte that MUST NOT be consumed.
        let packet = [0xffu8; 4];
        let qiis =
            decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 1).expect("nqis=1 path");
        assert_eq!(qiis, vec![0, 0, 0, 0, 0]);

        // Confirm via the inner that the reader did not consume any
        // bits (read one bit and assert it's the MSb of the first
        // sentinel byte).
        let mut r = BitReader::new(&packet);
        let _ = decode_block_level_qi_inner(&mut r, bcoded.len() as u32, &bcoded, 1).unwrap();
        let b = r.read_bits(1, "sentinel").unwrap();
        assert_eq!(b, 1, "no bits should have been consumed");
    }

    /// NQIS=2 happy path: one long-run pass; coded blocks get bits,
    /// uncoded blocks stay at 0.
    #[test]
    fn block_level_qi_nqis_2_assigns_per_coded_block() {
        // bi=0 coded; bi=1 uncoded; bi=2 coded; bi=3 coded; bi=4
        // uncoded; bi=5 coded.
        let bcoded = vec![1u8, 0, 1, 1, 0, 1];
        // Pass 0: NBITS = 4 coded blocks. Choose the per-coded-block
        // bits in coded order to be [0, 1, 0, 1] → final QIIS values
        // for the coded blocks are [0, 1, 0, 1] (uncoded keep 0).
        let mut w = BitWriter::new();
        encode_long_run_runs(&mut w, &[0, 1, 0, 1]);
        let packet = w.finish();
        let qiis = decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 2).unwrap();
        // bi index ......... 0  1  2  3  4  5
        // coded? ........... y  n  y  y  n  y
        // pass-0 bit ....... 0     1  0     1
        assert_eq!(qiis, vec![0, 0, 1, 0, 0, 1]);
    }

    /// NQIS=3 happy path: two long-run passes, the second restricted
    /// to blocks promoted out of the first.
    #[test]
    fn block_level_qi_nqis_3_chains_two_passes() {
        // 6 coded blocks.
        let bcoded = vec![1u8; 6];
        let mut w = BitWriter::new();
        // Pass 0: NBITS = 6. Bits in coded order: [0, 1, 0, 1, 1, 0].
        // After pass 0, QIIS = [0, 1, 0, 1, 1, 0].
        encode_long_run_runs(&mut w, &[0, 1, 0, 1, 1, 0]);
        // Pass 1: NBITS = #{bi : BCODED=1 AND QIIS==1} = 3 (bi=1, 3, 4).
        // Bits in coded order of those 3 blocks: [1, 0, 1].
        // After pass 1, QIIS[1] += 1 = 2, QIIS[3] += 0 = 1, QIIS[4] += 1 = 2.
        encode_long_run_runs(&mut w, &[1, 0, 1]);
        let packet = w.finish();
        let qiis = decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 3).unwrap();
        // Final: bi=0 → 0, bi=1 → 2, bi=2 → 0, bi=3 → 1, bi=4 → 2, bi=5 → 0
        assert_eq!(qiis, vec![0, 2, 0, 1, 2, 0]);
    }

    /// Step 2(a) only counts coded blocks: an uncoded block's QIIS
    /// stays at 0 even if the pass-0 long-run string skips over it.
    #[test]
    fn block_level_qi_uncoded_blocks_stay_at_zero() {
        // bi 0 1 2 3 4 5 6 7
        //    y n y n y n y n  (every other one coded)
        let bcoded = vec![1u8, 0, 1, 0, 1, 0, 1, 0];
        // Pass 0: NBITS = 4 (only the four coded blocks).
        let mut w = BitWriter::new();
        encode_long_run_runs(&mut w, &[1, 1, 1, 1]);
        let packet = w.finish();
        let qiis = decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 2).unwrap();
        // All four coded promoted to 1; all four uncoded stay at 0.
        assert_eq!(qiis, vec![1, 0, 1, 0, 1, 0, 1, 0]);
    }

    /// NQIS=3 where the first pass leaves NO blocks at qii=1 → the
    /// second pass has NBITS=0 and consumes no bits.
    #[test]
    fn block_level_qi_nqis_3_second_pass_can_be_empty() {
        let bcoded = vec![1u8; 4];
        let mut w = BitWriter::new();
        // Pass 0: all four bits zero → every coded block stays at 0.
        encode_long_run_runs(&mut w, &[0, 0, 0, 0]);
        // Pass 1: NBITS = #{BCODED=1 AND QIIS==1} = 0 → no encoding.
        // Append a sentinel byte to verify no bits get consumed.
        let mut packet = w.finish();
        packet.push(0xaa);
        let qiis = decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 3).unwrap();
        assert_eq!(qiis, vec![0, 0, 0, 0]);
    }

    /// nbs=0 (no blocks): every pass tallies NBITS=0 and no bits are
    /// consumed regardless of nqis.
    #[test]
    fn block_level_qi_zero_nbs_short_circuits() {
        let qiis = decode_block_level_qi(&[], 0, &[], 1).unwrap();
        assert_eq!(qiis, Vec::<u8>::new());
        let qiis = decode_block_level_qi(&[], 0, &[], 3).unwrap();
        assert_eq!(qiis, Vec::<u8>::new());
    }

    /// Bcoded length mismatch error.
    #[test]
    fn block_level_qi_rejects_bcoded_length_mismatch() {
        let err = decode_block_level_qi(&[], 4, &[1, 1, 1], 1).unwrap_err();
        assert_eq!(
            err,
            Error::BlockLevelQiBcodedLenMismatch {
                bcoded_len: 3,
                nbs: 4,
            }
        );
    }

    /// nqis out-of-range rejects (both 0 and >MAX).
    #[test]
    fn block_level_qi_rejects_nqis_out_of_range() {
        let err = decode_block_level_qi(&[], 0, &[], 0).unwrap_err();
        assert_eq!(err, Error::BlockLevelQiNqisOutOfRange { nqis: 0 });
        let err = decode_block_level_qi(&[], 0, &[], 4).unwrap_err();
        assert_eq!(err, Error::BlockLevelQiNqisOutOfRange { nqis: 4 });
    }

    /// Truncation mid-pass-0 long-run surfaces as a TruncatedHeader
    /// from the §7.2.1 layer.
    #[test]
    fn block_level_qi_truncation_in_pass_0_is_reported() {
        let bcoded = vec![1u8; 4];
        // Empty packet → the very first BIT read by §7.2.1 must fail.
        let err = decode_block_level_qi(&[], bcoded.len() as u32, &bcoded, 2).unwrap_err();
        match err {
            Error::TruncatedHeader { field: _ } => {}
            other => panic!("expected TruncatedHeader, got {other:?}"),
        }
    }

    /// Truncation mid-pass-1 long-run (pass-0 fully decoded; pass-1
    /// runs out) also surfaces.
    #[test]
    fn block_level_qi_truncation_in_pass_1_is_reported() {
        let bcoded = vec![1u8; 4];
        let mut w = BitWriter::new();
        // Pass 0: full 4-bit string that promotes every block to 1.
        encode_long_run_runs(&mut w, &[1, 1, 1, 1]);
        // Intentionally do NOT encode pass 1. The §7.2.1 inner reads
        // BIT (and then walks RLEN) — the first read fails.
        let packet = w.finish();
        let err = decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 3).unwrap_err();
        match err {
            Error::TruncatedHeader { field: _ } => {}
            other => panic!("expected TruncatedHeader, got {other:?}"),
        }
    }

    /// Shared-reader chaining contract: after `decode_block_level_qi_inner`
    /// returns, the same BitReader is still positioned correctly so the
    /// caller can keep reading downstream.
    #[test]
    fn block_level_qi_inner_chains_on_shared_reader() {
        let bcoded = vec![1u8; 4];
        let mut w = BitWriter::new();
        // Pass 0 only, NQIS=2, all bits zero.
        encode_long_run_runs(&mut w, &[0, 0, 0, 0]);
        // Sentinel pattern that should land on the next bit boundary.
        // Append seven 1-bits then five 0-bits = 12 bits.
        for _ in 0..7 {
            w.put(1, 1);
        }
        for _ in 0..5 {
            w.put(0, 1);
        }
        let packet = w.finish();
        let mut r = BitReader::new(&packet);
        let qiis = decode_block_level_qi_inner(&mut r, bcoded.len() as u32, &bcoded, 2).unwrap();
        assert_eq!(qiis, vec![0, 0, 0, 0]);
        // Now read 12 more bits — should be seven 1s then five 0s.
        let after = r.read_bits(12, "sentinel").unwrap();
        // Bits in order: 1111111 00000 → 0b1111_1110_0000 = 0xfe0
        assert_eq!(after, 0b1111_1110_0000);
    }

    /// Error::Display rendering for the two new variants.
    #[test]
    fn block_level_qi_error_displays_render() {
        let s = format!(
            "{}",
            Error::BlockLevelQiBcodedLenMismatch {
                bcoded_len: 7,
                nbs: 5,
            }
        );
        assert!(s.contains("§7.6"));
        assert!(s.contains("bcoded length 7"));
        assert!(s.contains("nbs 5"));

        let s = format!("{}", Error::BlockLevelQiNqisOutOfRange { nqis: 9 });
        assert!(s.contains("§7.6"));
        assert!(s.contains("NQIS=9"));
        assert!(s.contains("1..=3"));
    }

    /// NQIS=3 where pass 1's bit-tally is fed by an interleaved
    /// pattern: confirm that coded order (ascending `bi`) is the
    /// iteration order, not the order of bcoded entries.
    #[test]
    fn block_level_qi_nqis_3_iterates_in_coded_order() {
        // bcoded: y n y y y n y n  → 5 coded blocks
        let bcoded = vec![1u8, 0, 1, 1, 1, 0, 1, 0];
        let mut w = BitWriter::new();
        // Pass 0 over 5 coded blocks (bi = 0,2,3,4,6) with bits
        // [1, 0, 1, 0, 1] → QIIS[0,2,3,4,6] = [1, 0, 1, 0, 1].
        encode_long_run_runs(&mut w, &[1, 0, 1, 0, 1]);
        // Pass 1 NBITS = #{BCODED=1 AND QIIS==1} = 3 (bi=0, 3, 6) in
        // coded order. Bits [0, 1, 0] → QIIS[0]+=0=1, QIIS[3]+=1=2,
        // QIIS[6]+=0=1.
        encode_long_run_runs(&mut w, &[0, 1, 0]);
        let packet = w.finish();
        let qiis = decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 3).unwrap();
        assert_eq!(qiis, vec![1, 0, 0, 2, 0, 0, 1, 0]);
    }

    /// All blocks uncoded: every pass sees NBITS=0 even when NQIS=3.
    #[test]
    fn block_level_qi_all_uncoded_consumes_no_bits() {
        let bcoded = vec![0u8; 5];
        // No bits encoded; a sentinel byte verifies nothing is consumed.
        let packet = [0xffu8; 2];
        let mut r = BitReader::new(&packet);
        let qiis = decode_block_level_qi_inner(&mut r, bcoded.len() as u32, &bcoded, 3).unwrap();
        assert_eq!(qiis, vec![0, 0, 0, 0, 0]);
        // 16 sentinel bits should still be intact.
        let v = r.read_bits(16, "sentinel").unwrap();
        assert_eq!(v, 0xffff);
    }

    /// Realistic mix at NQIS=2 spanning the long-run RSTART boundaries
    /// (RSTART=10 covers run lengths 10..=17). Confirms a multi-run
    /// long-run encoding survives the round-trip through §7.6.
    #[test]
    fn block_level_qi_long_run_multi_run_round_trip() {
        // 24 coded blocks.
        let bcoded = vec![1u8; 24];
        let mut w = BitWriter::new();
        // Pass 0: 10 zeros then 14 ones (two long-run records,
        // RSTART=10 chosen for both).
        let pass0: Vec<u8> = std::iter::repeat(0)
            .take(10)
            .chain(std::iter::repeat(1).take(14))
            .collect();
        encode_long_run_runs(&mut w, &pass0);
        let packet = w.finish();
        let qiis = decode_block_level_qi(&packet, bcoded.len() as u32, &bcoded, 2).unwrap();
        // The first 10 stay at 0; the remaining 14 promote to 1.
        let mut expected = vec![0u8; 10];
        expected.extend(std::iter::repeat(1).take(14));
        assert_eq!(qiis, expected);
    }

    // =================================================================
    // §7.7.1 EOB Token Decode tests
    // =================================================================

    /// Build a fresh `(tis, ncoeffs, coeffs)` tuple sized for `nbs`
    /// blocks, with sentinel values that make later "untouched" /
    /// "zero-filled" assertions unambiguous.
    fn fresh_eob_state(nbs: usize) -> (Vec<u8>, Vec<u8>, Vec<[i16; 64]>) {
        let tis = vec![0u8; nbs];
        // NCOEFFS sentinel is 0xff so the procedure's step-9 write is
        // detectable even when TIS[bi] happens to be 0.
        let ncoeffs = vec![0xffu8; nbs];
        // COEFFS sentinel is -777 (not zero) so step 8's zero-fill is
        // distinguishable from "no write happened".
        let coeffs = vec![[-777i16; 64]; nbs];
        (tis, ncoeffs, coeffs)
    }

    /// Token 0..=2 ride §7.7.1 steps 1..=3: EOBS is a fixed
    /// 1/2/3, no extra bits are read.
    #[test]
    fn eob_token_constant_runs_consume_no_bits() {
        for (token, expected_run) in [(0u8, 1u64), (1, 2), (2, 3)] {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(4);
            // Empty packet — the procedure must not read any bits.
            let eobs =
                decode_eob_token(&[], token, 4, 2, 5, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
            // Step 11: EOBS -= 1.
            assert_eq!(eobs, expected_run - 1);
            // Step 8: COEFFS[2][5..=63] zeroed; [0..5] untouched (still
            // sentinel).
            for (ti, &v) in coeffs[2].iter().enumerate().take(5) {
                assert_eq!(v, -777, "ti={ti}");
            }
            for (ti_off, &v) in coeffs[2][5..64].iter().enumerate() {
                let ti = 5 + ti_off;
                assert_eq!(v, 0, "ti={ti}");
            }
            // Other blocks untouched.
            for bi in [0, 1, 3] {
                assert_eq!(coeffs[bi], [-777i16; 64]);
                assert_eq!(ncoeffs[bi], 0xff);
                assert_eq!(tis[bi], 0);
            }
            // Step 9: NCOEFFS[bi] = TIS[bi] (which was 0 at entry).
            assert_eq!(ncoeffs[2], 0);
            // Step 10: TIS[bi] = 64.
            assert_eq!(tis[2], 64);
        }
    }

    /// Token 3 reads a 2-bit payload then adds 4. The four values it
    /// can produce are 4, 5, 6, 7 (then minus the step-11 decrement).
    #[test]
    fn eob_token_3_two_bit_payload_round_trip() {
        for payload in 0u32..4 {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(2);
            // Pack the 2-bit payload as the most significant bits of one
            // byte (the MSb-first §5.2 reader consumes the MSb first).
            let byte = ((payload & 0b11) << 6) as u8;
            let packet = [byte];
            let eobs = decode_eob_token(&packet, 3, 2, 0, 63, &mut tis, &mut ncoeffs, &mut coeffs)
                .unwrap();
            assert_eq!(eobs, payload as u64 + 4 - 1, "payload={payload}");
            // Step 8 at ti=63 zero-fills exactly one coefficient.
            assert_eq!(coeffs[0][63], 0);
            for (ti, &v) in coeffs[0].iter().enumerate().take(63) {
                assert_eq!(v, -777, "ti={ti}");
            }
        }
    }

    /// Token 4 reads a 3-bit payload then adds 8 → range 8..=15.
    #[test]
    fn eob_token_4_three_bit_payload_round_trip() {
        for payload in 0u32..8 {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(1);
            let byte = ((payload & 0b111) << 5) as u8;
            let packet = [byte];
            let eobs =
                decode_eob_token(&packet, 4, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
            assert_eq!(eobs, payload as u64 + 8 - 1, "payload={payload}");
        }
    }

    /// Token 5 reads a 4-bit payload then adds 16 → range 16..=31.
    #[test]
    fn eob_token_5_four_bit_payload_round_trip() {
        for payload in 0u32..16 {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(1);
            let byte = ((payload & 0b1111) << 4) as u8;
            let packet = [byte];
            let eobs =
                decode_eob_token(&packet, 5, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
            assert_eq!(eobs, payload as u64 + 16 - 1, "payload={payload}");
        }
    }

    /// Token 6 with a non-zero payload returns the payload verbatim
    /// (modulo step 11's decrement); range 1..=4095.
    #[test]
    fn eob_token_6_non_zero_payload_returns_literal() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(1);
        // Payload = 0b1010_1010_1010 = 2730.
        let packet = [0b1010_1010, 0b1010_0000];
        let eobs =
            decode_eob_token(&packet, 6, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
        assert_eq!(eobs, 2730 - 1);
    }

    /// Token 6 with a *zero* 12-bit payload triggers the §7.7.1 step
    /// 7(b) sentinel: EOBS becomes the count of blocks bj with
    /// TIS[bj] < 64, *including the current block* (TIS[bi] is still <
    /// 64 at this point because step 10 has not yet run).
    #[test]
    fn eob_token_6_zero_payload_counts_remaining_blocks() {
        // 5 blocks: blocks 0..=3 still have TIS < 64; block 4 has
        // already been pinned (TIS=64 from a prior pass).
        let mut tis = vec![0u8, 0, 0, 0, 64];
        let mut ncoeffs = vec![0xffu8; 5];
        let mut coeffs = vec![[-777i16; 64]; 5];
        // Zero 12-bit payload.
        let packet = [0u8, 0];
        let eobs =
            decode_eob_token(&packet, 6, 5, 1, 10, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
        // 4 blocks have TIS < 64 entering the call → EOBS = 4; step 11
        // decrements to 3.
        assert_eq!(eobs, 3);
        // Step 10 ran AFTER the count, pinning block 1.
        assert_eq!(tis, vec![0, 64, 0, 0, 64]);
    }

    /// Token-out-of-range rejection: every value 7..=255 must reject.
    #[test]
    fn eob_token_rejects_token_above_six() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(1);
        for token in 7u8..=20 {
            let r = decode_eob_token(&[], token, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs);
            assert_eq!(r, Err(Error::EobTokenOutOfRange { token }), "token={token}");
        }
    }

    /// `bi` out of range rejection.
    #[test]
    fn eob_token_rejects_bi_equal_or_greater_than_nbs() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(4);
        let r = decode_eob_token(&[], 0, 4, 4, 0, &mut tis, &mut ncoeffs, &mut coeffs);
        assert_eq!(
            r,
            Err(Error::EobTokenBlockIndexOutOfRange { bi: 4, nbs: 4 })
        );
        let r = decode_eob_token(&[], 0, 4, 99, 0, &mut tis, &mut ncoeffs, &mut coeffs);
        assert_eq!(
            r,
            Err(Error::EobTokenBlockIndexOutOfRange { bi: 99, nbs: 4 })
        );
    }

    /// `ti` out of range rejection.
    #[test]
    fn eob_token_rejects_ti_above_63() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(1);
        for ti in 64u8..=127 {
            let r = decode_eob_token(&[], 0, 1, 0, ti, &mut tis, &mut ncoeffs, &mut coeffs);
            assert_eq!(r, Err(Error::EobTokenIndexOutOfRange { ti }), "ti={ti}");
        }
    }

    /// State-slice length mismatch rejections, one per slice.
    #[test]
    fn eob_token_rejects_state_length_mismatch() {
        // TIS too short.
        {
            let mut tis = vec![0u8; 3];
            let mut ncoeffs = vec![0u8; 4];
            let mut coeffs = vec![[0i16; 64]; 4];
            let r = decode_eob_token(&[], 0, 4, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs);
            assert_eq!(
                r,
                Err(Error::EobTokenStateLenMismatch {
                    which: EobTokenStateSlice::Tis,
                    got: 3,
                    nbs: 4
                })
            );
        }
        // NCOEFFS too short.
        {
            let mut tis = vec![0u8; 4];
            let mut ncoeffs = vec![0u8; 2];
            let mut coeffs = vec![[0i16; 64]; 4];
            let r = decode_eob_token(&[], 0, 4, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs);
            assert_eq!(
                r,
                Err(Error::EobTokenStateLenMismatch {
                    which: EobTokenStateSlice::Ncoeffs,
                    got: 2,
                    nbs: 4
                })
            );
        }
        // COEFFS too short.
        {
            let mut tis = vec![0u8; 4];
            let mut ncoeffs = vec![0u8; 4];
            let mut coeffs = vec![[0i16; 64]; 1];
            let r = decode_eob_token(&[], 0, 4, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs);
            assert_eq!(
                r,
                Err(Error::EobTokenStateLenMismatch {
                    which: EobTokenStateSlice::Coeffs,
                    got: 1,
                    nbs: 4
                })
            );
        }
    }

    /// Truncation surfaces from the extra-bits paths on each of tokens
    /// 3, 4, 5, 6.
    #[test]
    fn eob_token_truncation_on_extra_bits() {
        for token in 3u8..=6 {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(1);
            // Empty packet → the very first extra-bits read fails.
            let r = decode_eob_token(&[], token, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs);
            match r {
                Err(Error::TruncatedHeader { .. }) => {}
                other => panic!("token={token} expected TruncatedHeader, got {other:?}"),
            }
            // No partial state should land: TIS is still 0 (step 10
            // has not run) and COEFFS is still sentinel.
            assert_eq!(tis[0], 0);
            assert_eq!(coeffs[0], [-777i16; 64]);
        }
    }

    /// Step-8 boundary check: ti=0 zero-fills the full block.
    #[test]
    fn eob_token_zero_fills_from_ti_zero() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(2);
        let eobs = decode_eob_token(&[], 0, 2, 1, 0, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
        assert_eq!(eobs, 0);
        // Every coefficient of block 1 is zero-filled.
        assert_eq!(coeffs[1], [0i16; 64]);
        // Block 0 untouched.
        assert_eq!(coeffs[0], [-777i16; 64]);
    }

    /// Step-9 captures the pre-call TIS value, not the post-step-10
    /// pinned 64. Exercised by pre-seeding TIS[bi] with a non-zero
    /// value before the call.
    #[test]
    fn eob_token_step9_captures_pre_call_tis() {
        let mut tis = vec![0u8, 17];
        let mut ncoeffs = vec![0xffu8; 2];
        let mut coeffs = vec![[-777i16; 64]; 2];
        let _ = decode_eob_token(&[], 0, 2, 1, 20, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
        // §7.7.1 step 9: NCOEFFS[bi] = TIS[bi] (which was 17 *before*
        // step 10 ran).
        assert_eq!(ncoeffs[1], 17);
        // §7.7.1 step 10 then pinned TIS[bi] = 64.
        assert_eq!(tis[1], 64);
    }

    /// Display rendering for each new §7.7.1 error variant carries the
    /// section number so log messages bisect cleanly to the spec.
    #[test]
    fn eob_token_error_display_carries_section_number() {
        let e = Error::EobTokenOutOfRange { token: 7 };
        let s = format!("{e}");
        assert!(s.contains("§7.7.1"), "got: {s}");
        assert!(s.contains("TOKEN=7"), "got: {s}");

        let e = Error::EobTokenBlockIndexOutOfRange { bi: 4, nbs: 4 };
        let s = format!("{e}");
        assert!(s.contains("§7.7.1"), "got: {s}");
        assert!(s.contains("bi=4"), "got: {s}");

        let e = Error::EobTokenIndexOutOfRange { ti: 99 };
        let s = format!("{e}");
        assert!(s.contains("§7.7.1"), "got: {s}");
        assert!(s.contains("ti=99"), "got: {s}");

        let e = Error::EobTokenStateLenMismatch {
            which: EobTokenStateSlice::Tis,
            got: 3,
            nbs: 4,
        };
        let s = format!("{e}");
        assert!(s.contains("§7.7.1"), "got: {s}");
        assert!(s.contains("Tis"), "got: {s}");
    }

    /// The shared-`BitReader` chaining contract: after the inner
    /// procedure returns, the next read picks up exactly where §7.7.1
    /// left off. Exercised on token 3 (2 bits of extra-bits payload)
    /// followed by a sentinel byte.
    #[test]
    fn eob_token_inner_leaves_reader_at_correct_offset() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_eob_state(1);
        // Two payload bits = b11 (the high two bits of byte 0), then
        // six tail bits in the same byte set to 0b101010, then a fresh
        // byte = 0xFF as a sentinel.
        let packet = [0b1110_1010, 0xff];
        let mut r = BitReader::new(&packet);
        let eobs = decode_eob_token_inner(&mut r, 3, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap();
        // Payload was 0b11 = 3 → EOBS = 3 + 4 - 1 = 6.
        assert_eq!(eobs, 6);
        // Next 6 bits of byte 0 = 0b101010, then the byte 0xFF sentinel.
        let tail = r.read_bits(6, "tail").unwrap();
        assert_eq!(tail, 0b101010);
        let sentinel = r.read_bits(8, "sentinel").unwrap();
        assert_eq!(sentinel, 0xff);
    }

    /// Token 6 zero-payload "all-remaining" interpretation: every
    /// already-pinned block is excluded; including the current block
    /// in the tally is the spec's wording ("the size of the remaining
    /// coded blocks").
    #[test]
    fn eob_token_6_zero_payload_excludes_pinned_blocks() {
        // 8 blocks: 0..=2 pinned (TIS=64), 3..=7 still in play.
        let mut tis = vec![64u8, 64, 64, 0, 0, 0, 0, 0];
        let mut ncoeffs = vec![0xffu8; 8];
        let mut coeffs = vec![[0i16; 64]; 8];
        // Zero 12-bit payload (token 6 sentinel).
        let packet = [0u8, 0];
        let eobs =
            decode_eob_token(&packet, 6, 8, 3, 0, &mut tis, &mut ncoeffs, &mut coeffs).unwrap();
        // 5 blocks (3..=7) qualify; step 11 decrements → 4.
        assert_eq!(eobs, 4);
        // Only block 3 was pinned by this call.
        assert_eq!(tis, vec![64, 64, 64, 64, 0, 0, 0, 0]);
    }

    // ---------------------------------------------------------------
    // §6.4.1 Loop Filter Limit Table Decode tests.
    //
    // Spec body recovered in `docs/video/theora/theora-6.4.1-lflims.md`
    // from the spec's own LaTeX source. The procedure reads `NBITS`
    // (3 bits) once, then for each `qi` in 0..=63 reads `LFLIMS[qi]`
    // as an `NBITS`-bit unsigned integer.
    //
    // The fixtures below construct §6.4.1 payloads bit-by-bit using
    // the same MSb-first packing the `BitReader` consumes (most
    // significant bit of byte 0 first). This avoids needing a live
    // setup-header payload and exercises the decoder against
    // synthetic inputs whose expected output is by construction.
    // ---------------------------------------------------------------

    /// Helper: pack `(value, nbits)` slots MSb-first into the smallest
    /// `Vec<u8>` that fits, zero-padding the final byte's tail bits.
    fn pack_msb_first(slots: &[(u32, u32)]) -> Vec<u8> {
        let total_bits: u32 = slots.iter().map(|(_, n)| n).sum();
        let total_bytes = total_bits.div_ceil(8) as usize;
        let mut out = vec![0u8; total_bytes];
        let mut bit_cursor: usize = 0;
        for &(value, nbits) in slots {
            for i in (0..nbits).rev() {
                let bit = (value >> i) & 1;
                let byte_idx = bit_cursor / 8;
                let bit_idx = 7 - (bit_cursor % 8);
                out[byte_idx] |= (bit as u8) << bit_idx;
                bit_cursor += 1;
            }
        }
        out
    }

    /// NBITS=0 is a corner case the spec body permits: the read is
    /// zero-bit-wide per entry, so every `LFLIMS[qi]` is forced to 0.
    /// Total bit cost = 3 + 64*0 = 3 bits. The next 5 bits of byte 0
    /// are free for whatever §6.4.2 wants to do with them.
    #[test]
    fn lflims_nbits_zero_yields_all_zeros() {
        // Single byte: NBITS=0 in the top 3 bits, then 5 don't-care
        // bits set to 1 to make sure they are not consumed.
        let packet = [0b000_11111];
        let lflims = decode_loop_filter_limit_table(&packet).unwrap();
        assert_eq!(lflims, [0u8; 64]);
    }

    /// NBITS=5 (5-bit values) suffices to encode the Appendix B.2 VP3
    /// hardcoded LFLIMS table — its maximum entry is 30, well below
    /// 2^5 - 1 = 31. The decoded table must match `LFLIMS_VP3` byte
    /// for byte; this confirms both the §6.4.1 transcription and the
    /// Appendix B.2 table at the same time.
    #[test]
    fn lflims_nbits_5_roundtrips_vp3_table() {
        // NBITS=5 then 64 × 5-bit values from LFLIMS_VP3.
        let mut slots: Vec<(u32, u32)> = vec![(5, 3)];
        for &v in LFLIMS_VP3.iter() {
            slots.push((v as u32, 5));
        }
        let packet = pack_msb_first(&slots);
        let lflims = decode_loop_filter_limit_table(&packet).unwrap();
        assert_eq!(lflims, LFLIMS_VP3);
    }

    /// NBITS=7 covers the full 7-bit output width declared by §6.4.1.
    /// Round-tripping a table that uses the full 0..=127 range
    /// confirms the decoder does not narrow or clamp.
    #[test]
    fn lflims_nbits_7_roundtrips_full_range() {
        // Construct a synthetic table with `qi` as the value
        // (0..=63), then bump some entries to >63 to exercise the
        // top half of the 7-bit range.
        let mut expected = [0u8; 64];
        for (qi, slot) in expected.iter_mut().enumerate() {
            *slot = ((qi * 2) as u8) & 0x7f; // 0, 2, ... up to 126.
        }
        let mut slots: Vec<(u32, u32)> = vec![(7, 3)];
        for &v in expected.iter() {
            slots.push((v as u32, 7));
        }
        let packet = pack_msb_first(&slots);
        let lflims = decode_loop_filter_limit_table(&packet).unwrap();
        assert_eq!(lflims, expected);
    }

    /// Total bit cost: a NBITS=3 payload reads `3 + 64*3 = 195` bits,
    /// which spans 25 bytes (the last 5 bits of byte 24 are unused).
    /// A 24-byte buffer is therefore insufficient and must surface
    /// the truncation error the shared `BitReader` raises.
    #[test]
    fn lflims_truncated_payload_errors() {
        // 195 bits would need 25 bytes; give 24 with NBITS=3 packed.
        let mut slots: Vec<(u32, u32)> = vec![(3, 3)];
        for _ in 0..64 {
            slots.push((5, 3));
        }
        let mut packet = pack_msb_first(&slots);
        packet.truncate(24);
        let err = decode_loop_filter_limit_table(&packet).unwrap_err();
        assert!(
            matches!(err, Error::TruncatedHeader { field: "LFLIMS" }),
            "got: {err:?}"
        );
    }

    /// Truncation while reading `NBITS` itself (an empty payload)
    /// reports the `LFLIMS NBITS` field so the failure pinpoints the
    /// step-1 read rather than the step-2 loop.
    #[test]
    fn lflims_truncated_at_nbits_errors() {
        let packet: [u8; 0] = [];
        let err = decode_loop_filter_limit_table(&packet).unwrap_err();
        assert!(
            matches!(
                err,
                Error::TruncatedHeader {
                    field: "LFLIMS NBITS"
                }
            ),
            "got: {err:?}"
        );
    }

    /// The shared-`BitReader` chaining contract for §6.4.1: after the
    /// inner procedure returns, the next read picks up exactly where
    /// the procedure left off. This is what lets a future
    /// `parse_setup_header` chain §6.4.1 → §6.4.2 → §6.4.4 on the
    /// same reader without re-aligning at byte boundaries.
    #[test]
    fn lflims_inner_leaves_reader_at_correct_offset() {
        // NBITS=3 → reads 3 + 64*3 = 195 bits.
        let mut slots: Vec<(u32, u32)> = vec![(3, 3)];
        for _ in 0..64 {
            slots.push((1, 3));
        }
        // Add a 5-bit tail in byte 24 (bits 4..=0) and a sentinel
        // byte to verify both partial-byte and next-byte continuation.
        slots.push((0b10110, 5));
        slots.push((0xab, 8));
        let packet = pack_msb_first(&slots);
        let mut r = BitReader::new(&packet);
        let lflims = decode_lflims_inner(&mut r).unwrap();
        assert_eq!(lflims, [1u8; 64]);
        // Reader is now mid-byte 24 at bit-position 4 (zero-indexed
        // from the MSb). Read the 5-bit tail then the sentinel.
        let tail = r.read_bits(5, "tail").unwrap();
        assert_eq!(tail, 0b10110);
        let sentinel = r.read_bits(8, "sentinel").unwrap();
        assert_eq!(sentinel, 0xab);
    }

    /// All entries reach the 7-bit ceiling (`2^7 - 1 = 127`) when
    /// NBITS=7 — the maximum addressable value the §6.4.1 output
    /// table allows. Confirms no upper-bound truncation.
    #[test]
    fn lflims_nbits_7_all_max_value() {
        let mut slots: Vec<(u32, u32)> = vec![(7, 3)];
        for _ in 0..64 {
            slots.push((127, 7));
        }
        let packet = pack_msb_first(&slots);
        let lflims = decode_loop_filter_limit_table(&packet).unwrap();
        assert_eq!(lflims, [127u8; 64]);
    }

    // ===================================================================
    // §7.7.2 Coefficient Token Decode tests
    // ===================================================================

    /// Reusable starting state for §7.7.2 tests. NCOEFFS sentinel is
    /// 0xff so step-c writes are detectable when TIS[bi] happens to be
    /// 0. COEFFS sentinel is -777 so the per-token writes are visible
    /// against the background.
    fn fresh_coeff_state(nbs: usize) -> (Vec<u8>, Vec<u8>, Vec<[i16; 64]>) {
        let tis = vec![0u8; nbs];
        let ncoeffs = vec![0xffu8; nbs];
        let coeffs = vec![[-777i16; 64]; nbs];
        (tis, ncoeffs, coeffs)
    }

    /// TOKEN=7 reads a 3-bit `RLEN`, adds 1, then zero-fills that many
    /// entries. NCOEFFS[bi] is NOT updated (pure-zero-run exception).
    /// All eight `RLEN_RAW` values 0..=7 produce runs 1..=8.
    #[test]
    fn coeff_token_7_short_zero_run() {
        for rlen_raw in 0u32..8 {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(2);
            let byte = ((rlen_raw & 0b111) << 5) as u8;
            let kind =
                decode_coefficient_token(&[byte], 7, 2, 1, 0, &mut tis, &mut ncoeffs, &mut coeffs)
                    .unwrap();
            assert_eq!(kind, CoefficientTokenKind::ZeroRun);
            let rlen = rlen_raw + 1;
            // Block 1's first `rlen` slots are zeroed; everything past
            // that retains the -777 sentinel.
            for (ti, &v) in coeffs[1].iter().enumerate() {
                if (ti as u32) < rlen {
                    assert_eq!(v, 0, "rlen_raw={rlen_raw} ti={ti}");
                } else {
                    assert_eq!(v, -777, "rlen_raw={rlen_raw} ti={ti}");
                }
            }
            assert_eq!(tis[1], rlen as u8);
            // NCOEFFS[bi] untouched per §7.7.2's pure-zero-run note.
            assert_eq!(ncoeffs[1], 0xff);
        }
    }

    /// TOKEN=8 reads a 6-bit RLEN+1, range 1..=64. The boundary case
    /// RLEN=64 starting from ti=0 must succeed (writes exactly 64
    /// zeros, TIS advances to 64).
    #[test]
    fn coeff_token_8_long_zero_run_to_block_end() {
        // 6-bit RLEN_RAW = 63 (0b111_111) → run of 64.
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // 6 bits, MSb-first: 0b111111_xx (top 6 of byte).
        let byte = 0b1111_1100u8;
        let kind =
            decode_coefficient_token(&[byte], 8, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
                .unwrap();
        assert_eq!(kind, CoefficientTokenKind::ZeroRun);
        assert_eq!(tis[0], 64);
        assert_eq!(ncoeffs[0], 0xff);
        assert_eq!(coeffs[0], [0i16; 64]);
    }

    /// TOKEN=9..=12 write a fixed coefficient and consume zero extra
    /// bits. NCOEFFS[bi] is set to the post-step TIS[bi].
    #[test]
    fn coeff_token_9_through_12_fixed_singles() {
        for (token, expected) in [(9u8, 1i16), (10, -1), (11, 2), (12, -2)] {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(2);
            // Empty packet — these tokens read no extra bits.
            let kind =
                decode_coefficient_token(&[], token, 2, 0, 7, &mut tis, &mut ncoeffs, &mut coeffs)
                    .unwrap();
            assert_eq!(kind, CoefficientTokenKind::Single);
            assert_eq!(coeffs[0][7], expected, "token={token}");
            // Other entries unchanged.
            assert_eq!(coeffs[0][6], -777);
            assert_eq!(coeffs[0][8], -777);
            assert_eq!(tis[0], 8);
            assert_eq!(ncoeffs[0], 8);
        }
    }

    /// TOKEN=13..=16 read a 1-bit SIGN and write ±MAG with
    /// MAG = 3, 4, 5, 6. The SIGN bit polarity is "zero → positive".
    #[test]
    fn coeff_token_13_through_16_fixed_mag_sign() {
        for (token, mag) in [(13u8, 3i16), (14, 4), (15, 5), (16, 6)] {
            for sign in 0u8..=1 {
                let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
                // SIGN bit at MSb of byte 0.
                let byte = sign << 7;
                let _ = decode_coefficient_token(
                    &[byte],
                    token,
                    1,
                    0,
                    0,
                    &mut tis,
                    &mut ncoeffs,
                    &mut coeffs,
                )
                .unwrap();
                let expected = if sign == 0 { mag } else { -mag };
                assert_eq!(coeffs[0][0], expected, "token={token} sign={sign}");
                assert_eq!(tis[0], 1);
                assert_eq!(ncoeffs[0], 1);
            }
        }
    }

    /// TOKEN=17 reads SIGN (1 bit) + MAG (1 bit) + offset 7 → ±7..=8.
    #[test]
    fn coeff_token_17_sign_one_bit_mag() {
        for sign in 0u8..=1 {
            for mag_raw in 0u8..=1 {
                let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
                // SIGN at bit 7, MAG at bit 6.
                let byte = (sign << 7) | (mag_raw << 6);
                let _ = decode_coefficient_token(
                    &[byte],
                    17,
                    1,
                    0,
                    0,
                    &mut tis,
                    &mut ncoeffs,
                    &mut coeffs,
                )
                .unwrap();
                let mag = mag_raw as i16 + 7;
                let expected = if sign == 0 { mag } else { -mag };
                assert_eq!(coeffs[0][0], expected, "sign={sign} mag_raw={mag_raw}");
            }
        }
    }

    /// TOKEN=22 reads SIGN (1 bit) + MAG (9 bits) + offset 69 → range
    /// ±69..=580. Exercises the largest single-coefficient token.
    #[test]
    fn coeff_token_22_ten_bit_payload_round_trip() {
        // MAG_RAW = 0x1FF (511) → MAG = 580. SIGN = 1 → -580.
        // 10 bits total, MSb-first: 1_1_1111_1111_xxxxxx.
        // Byte 0 = 0b1_1_1_1_1_1_1_1 (sign=1, mag bits 8..2 all 1).
        // Byte 1 = 0b1_1_xxxxxx (mag bits 1..0 = 1,1).
        let packet = [0b1111_1111u8, 0b1100_0000u8];
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        let _ = decode_coefficient_token(&packet, 22, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap();
        assert_eq!(coeffs[0][0], -580);
        assert_eq!(tis[0], 1);
        assert_eq!(ncoeffs[0], 1);
    }

    /// TOKEN=23..=27 are "N zeros + ±1" with fixed run lengths
    /// 1..=5. Tests the run-plus-one structural branch including the
    /// run-then-coefficient write order.
    #[test]
    fn coeff_token_23_through_27_fixed_run_plus_one() {
        for (token, run) in [(23u8, 1usize), (24, 2), (25, 3), (26, 4), (27, 5)] {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
            // SIGN = 0 → +1.
            let kind = decode_coefficient_token(
                &[0u8],
                token,
                1,
                0,
                10,
                &mut tis,
                &mut ncoeffs,
                &mut coeffs,
            )
            .unwrap();
            assert_eq!(kind, CoefficientTokenKind::RunPlusOne);
            // Zero run at COEFFS[0][10..10+run].
            assert!(
                coeffs[0][10..10 + run].iter().all(|&v| v == 0),
                "token={token}"
            );
            // Trailing +1 at COEFFS[0][10+run].
            assert_eq!(coeffs[0][10 + run], 1, "token={token}");
            // TIS advanced by run+1.
            assert_eq!(tis[0] as usize, 10 + run + 1);
            assert_eq!(ncoeffs[0] as usize, 10 + run + 1);
        }
    }

    /// TOKEN=28 reads SIGN + 2-bit RLEN, then writes RLEN+6 zeros
    /// followed by trailing ±1. Boundaries: RLEN range 6..=9.
    #[test]
    fn coeff_token_28_run_range_6_to_9() {
        for rlen_raw in 0u32..4 {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
            // SIGN=1 (negative trailing -1), 2-bit RLEN_RAW.
            // Bits: SIGN at bit 7, RLEN at bits 6..5.
            let byte = (0b1u8 << 7) | (((rlen_raw & 0b11) << 5) as u8);
            let _ =
                decode_coefficient_token(&[byte], 28, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
                    .unwrap();
            let run = rlen_raw + 6;
            assert!(
                coeffs[0][..run as usize].iter().all(|&v| v == 0),
                "rlen_raw={rlen_raw}"
            );
            assert_eq!(coeffs[0][run as usize], -1, "rlen_raw={rlen_raw}");
            assert_eq!(tis[0] as u32, run + 1);
            assert_eq!(ncoeffs[0] as u32, run + 1);
        }
    }

    /// TOKEN=29 reads SIGN + 3-bit RLEN, then writes RLEN+10 zeros
    /// followed by trailing ±1. Boundary: RLEN range 10..=17.
    #[test]
    fn coeff_token_29_run_range_10_to_17() {
        for rlen_raw in 0u32..8 {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
            // SIGN=0 (positive). 4 bits = SIGN(1) + RLEN(3); pack at top.
            let byte = ((rlen_raw & 0b111) << 4) as u8;
            let _ =
                decode_coefficient_token(&[byte], 29, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
                    .unwrap();
            let run = rlen_raw + 10;
            assert!(
                coeffs[0][..run as usize].iter().all(|&v| v == 0),
                "rlen_raw={rlen_raw}"
            );
            assert_eq!(coeffs[0][run as usize], 1, "rlen_raw={rlen_raw}");
            assert_eq!(tis[0] as u32, run + 1);
            assert_eq!(ncoeffs[0] as u32, run + 1);
        }
    }

    /// TOKEN=30 is "one zero + ±MAG" with MAG = 2..=3. SIGN/MAG bits
    /// are 2 of the 3 read; no RLEN field.
    #[test]
    fn coeff_token_30_one_zero_plus_signed_mag() {
        for sign in 0u8..=1 {
            for mag_raw in 0u8..=1 {
                let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
                let byte = (sign << 7) | (mag_raw << 6);
                let _ = decode_coefficient_token(
                    &[byte],
                    30,
                    1,
                    0,
                    5,
                    &mut tis,
                    &mut ncoeffs,
                    &mut coeffs,
                )
                .unwrap();
                let mag = (mag_raw as i16) + 2;
                let expected = if sign == 0 { mag } else { -mag };
                // First a zero at ti=5, then ±MAG at ti=6.
                assert_eq!(coeffs[0][5], 0);
                assert_eq!(coeffs[0][6], expected);
                assert_eq!(tis[0], 7);
                assert_eq!(ncoeffs[0], 7);
            }
        }
    }

    /// TOKEN=31 reads SIGN + MAG (1 bit, +2) + RLEN (1 bit, +2):
    /// `2..=3` zeros followed by `±2..=3`.
    #[test]
    fn coeff_token_31_signed_mag_with_run() {
        for sign in 0u8..=1 {
            for mag_raw in 0u8..=1 {
                for rlen_raw in 0u8..=1 {
                    let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
                    // Layout: SIGN(1) | MAG(1) | RLEN(1) at top 3 bits.
                    let byte = (sign << 7) | (mag_raw << 6) | (rlen_raw << 5);
                    let _ = decode_coefficient_token(
                        &[byte],
                        31,
                        1,
                        0,
                        0,
                        &mut tis,
                        &mut ncoeffs,
                        &mut coeffs,
                    )
                    .unwrap();
                    let mag = (mag_raw as i16) + 2;
                    let expected = if sign == 0 { mag } else { -mag };
                    let run = (rlen_raw as usize) + 2;
                    assert!(coeffs[0][..run].iter().all(|&v| v == 0));
                    assert_eq!(coeffs[0][run], expected);
                    assert_eq!(tis[0] as usize, run + 1);
                    assert_eq!(ncoeffs[0] as usize, run + 1);
                }
            }
        }
    }

    /// Argument validation: tokens 0..=6 belong to §7.7.1 and must be
    /// rejected by §7.7.2; tokens 32..=255 are out of band entirely.
    #[test]
    fn coeff_token_rejects_out_of_range_token() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        for token in 0u8..=6 {
            let err =
                decode_coefficient_token(&[], token, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
                    .unwrap_err();
            assert_eq!(err, Error::CoefficientTokenOutOfRange { token });
        }
        for token in [32u8, 64, 99, 200, 255] {
            let err =
                decode_coefficient_token(&[], token, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
                    .unwrap_err();
            assert_eq!(err, Error::CoefficientTokenOutOfRange { token });
        }
    }

    /// Argument validation: `bi >= nbs` and `ti > 63` reject with
    /// dedicated typed errors.
    #[test]
    fn coeff_token_rejects_index_out_of_range() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(2);
        let err = decode_coefficient_token(&[], 9, 2, 2, 0, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap_err();
        assert_eq!(
            err,
            Error::CoefficientTokenBlockIndexOutOfRange { bi: 2, nbs: 2 }
        );

        let err = decode_coefficient_token(&[], 9, 2, 0, 64, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap_err();
        assert_eq!(err, Error::CoefficientTokenIndexOutOfRange { ti: 64 });
    }

    /// Argument validation: the three state slices must each have
    /// length exactly `nbs`. Each mismatch surfaces with a typed
    /// `CoefficientTokenStateSlice` discriminant.
    #[test]
    fn coeff_token_rejects_state_length_mismatch() {
        // TIS too short.
        let mut tis = vec![0u8; 1];
        let mut ncoeffs = vec![0xffu8; 2];
        let mut coeffs = vec![[-777i16; 64]; 2];
        let err = decode_coefficient_token(&[], 9, 2, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap_err();
        assert_eq!(
            err,
            Error::CoefficientTokenStateLenMismatch {
                which: CoefficientTokenStateSlice::Tis,
                got: 1,
                nbs: 2,
            }
        );

        // NCOEFFS too long.
        let mut tis = vec![0u8; 2];
        let mut ncoeffs = vec![0xffu8; 3];
        let mut coeffs = vec![[-777i16; 64]; 2];
        let err = decode_coefficient_token(&[], 9, 2, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap_err();
        assert_eq!(
            err,
            Error::CoefficientTokenStateLenMismatch {
                which: CoefficientTokenStateSlice::Ncoeffs,
                got: 3,
                nbs: 2,
            }
        );

        // COEFFS too short.
        let mut tis = vec![0u8; 2];
        let mut ncoeffs = vec![0xffu8; 2];
        let mut coeffs = vec![[-777i16; 64]; 1];
        let err = decode_coefficient_token(&[], 9, 2, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap_err();
        assert_eq!(
            err,
            Error::CoefficientTokenStateLenMismatch {
                which: CoefficientTokenStateSlice::Coeffs,
                got: 1,
                nbs: 2,
            }
        );
    }

    /// §7.7.2 MUST-NOT clause: tokens that bring TIS[bi] past 64 fail
    /// closed. TOKEN=8 with RLEN=64 starting from ti=1 is the
    /// tightest illegal case — it would produce TIS=65.
    #[test]
    fn coeff_token_8_overflow_rejects() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // 6-bit RLEN_RAW = 63 (max) → run of 64. Starting from ti=1
        // would push TIS to 65 > 64.
        let byte = 0b1111_1100u8;
        let err =
            decode_coefficient_token(&[byte], 8, 1, 0, 1, &mut tis, &mut ncoeffs, &mut coeffs)
                .unwrap_err();
        assert_eq!(
            err,
            Error::CoefficientTokenWouldOverflowBlock {
                token: 8,
                ti: 1,
                new_tis: 65,
            }
        );
        // State arrays untouched on overflow.
        assert_eq!(tis[0], 0);
        assert_eq!(ncoeffs[0], 0xff);
        assert_eq!(coeffs[0][0], -777);
    }

    /// Run-plus-one tokens (e.g. TOKEN=29 with RLEN=17) also surface
    /// the overflow when the trailing coefficient would land past
    /// index 63. RLEN=17 + ti=47 → new TIS = 47+17+1 = 65 > 64.
    #[test]
    fn coeff_token_29_run_overflow_rejects() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // SIGN=0, RLEN_RAW=7 → run=17.
        let byte = (0b111u8) << 4;
        let err =
            decode_coefficient_token(&[byte], 29, 1, 0, 47, &mut tis, &mut ncoeffs, &mut coeffs)
                .unwrap_err();
        assert_eq!(
            err,
            Error::CoefficientTokenWouldOverflowBlock {
                token: 29,
                ti: 47,
                new_tis: 65,
            }
        );
    }

    /// Single-coefficient writes at ti = 63 are legal: TIS advances to
    /// 64 exactly (the same pinned state §7.7.1 step 10 produces). No
    /// overflow because §7.7.2's MUST-NOT clause only applies to
    /// multi-coefficient tokens.
    #[test]
    fn coeff_token_9_at_ti_63_pins_block() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        let kind = decode_coefficient_token(&[], 9, 1, 0, 63, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap();
        assert_eq!(kind, CoefficientTokenKind::Single);
        assert_eq!(coeffs[0][63], 1);
        assert_eq!(tis[0], 64);
        assert_eq!(ncoeffs[0], 64);
    }

    /// TOKEN=7 with RLEN=8 starting from ti=56 reaches exactly 64 — the
    /// largest legal zero-run terminal-position case. No overflow.
    #[test]
    fn coeff_token_7_reaches_block_end_exactly() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // RLEN_RAW=7 (max) → run=8.
        let byte = (0b111u8) << 5;
        let kind =
            decode_coefficient_token(&[byte], 7, 1, 0, 56, &mut tis, &mut ncoeffs, &mut coeffs)
                .unwrap();
        assert_eq!(kind, CoefficientTokenKind::ZeroRun);
        assert!(coeffs[0][56..64].iter().all(|&v| v == 0));
        assert_eq!(tis[0], 64);
        // NCOEFFS untouched per pure-zero-run rule.
        assert_eq!(ncoeffs[0], 0xff);
    }

    /// Truncation surfaces with a TruncatedHeader carrying a §7.7.2
    /// field name so log messages bisect cleanly to the spec.
    #[test]
    fn coeff_token_truncation_on_payload() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // TOKEN=22 needs 10 bits (1 SIGN + 9 MAG). Empty packet → trunc.
        let err = decode_coefficient_token(&[], 22, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
            .unwrap_err();
        match err {
            Error::TruncatedHeader { field } => {
                assert!(field.contains("§7.7.2"), "got: {field}");
                assert!(field.contains("TOKEN=22"), "got: {field}");
            }
            other => panic!("expected TruncatedHeader, got {other:?}"),
        }
    }

    /// Display rendering for each new §7.7.2 error variant carries the
    /// section number so log lines bisect cleanly to the spec.
    #[test]
    fn coeff_token_error_display_carries_section_number() {
        let e = Error::CoefficientTokenOutOfRange { token: 0 };
        let s = format!("{e}");
        assert!(s.contains("§7.7.2"), "got: {s}");
        assert!(s.contains("TOKEN=0"), "got: {s}");

        let e = Error::CoefficientTokenBlockIndexOutOfRange { bi: 4, nbs: 4 };
        let s = format!("{e}");
        assert!(s.contains("§7.7.2"), "got: {s}");

        let e = Error::CoefficientTokenIndexOutOfRange { ti: 64 };
        let s = format!("{e}");
        assert!(s.contains("§7.7.2"), "got: {s}");

        let e = Error::CoefficientTokenStateLenMismatch {
            which: CoefficientTokenStateSlice::Coeffs,
            got: 3,
            nbs: 4,
        };
        let s = format!("{e}");
        assert!(s.contains("§7.7.2"), "got: {s}");
        assert!(s.contains("Coeffs"), "got: {s}");

        let e = Error::CoefficientTokenWouldOverflowBlock {
            token: 8,
            ti: 1,
            new_tis: 65,
        };
        let s = format!("{e}");
        assert!(s.contains("§7.7.2"), "got: {s}");
        assert!(s.contains("TOKEN=8"), "got: {s}");
        assert!(s.contains("65"), "got: {s}");
    }

    /// Shared-`BitReader` chaining contract: after the inner procedure
    /// returns, the next read picks up exactly where §7.7.2 left off.
    /// Exercised on TOKEN=22 (10 bits of payload) followed by a
    /// sentinel byte.
    #[test]
    fn coeff_token_inner_leaves_reader_at_correct_offset() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // 10 bits of TOKEN=22 payload = 1_111111111 (sign=1, mag=511 →
        // MAG=580, signed → -580). Then 6 tail bits = 0b101010, then a
        // fresh 0xFF sentinel byte.
        let packet = [0b1111_1111u8, 0b1110_1010u8, 0xff];
        let mut r = BitReader::new(&packet);
        let _ = decode_coefficient_token_inner(
            &mut r,
            22,
            1,
            0,
            0,
            &mut tis,
            &mut ncoeffs,
            &mut coeffs,
        )
        .unwrap();
        assert_eq!(coeffs[0][0], -580);
        // 16 bits consumed → byte 2 next. The 6 unused bits in byte 1
        // (lsb of mag is bit 6, then 6 remain) were... actually let me
        // re-verify: we read 10 bits = byte0 (8 bits) + 2 bits of byte
        // 1. Tail bits in byte 1 = 6 bits 0b101010. Then sentinel byte
        // 2 = 0xff.
        let tail = r.read_bits(6, "tail").unwrap();
        assert_eq!(tail, 0b101010);
        let sentinel = r.read_bits(8, "sentinel").unwrap();
        assert_eq!(sentinel, 0xff);
    }

    /// TOKEN=18 reads 3 bits total (SIGN + 2-bit MAG). With sign=0 and
    /// mag_raw=3 the result is +12 (MAG = 3 + 9). Confirms the offset
    /// addition.
    #[test]
    fn coeff_token_18_two_bit_mag_offset_9() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // SIGN=0, MAG_RAW=3 → MAG = 12.
        // Bits: 0_11_xxxxx = 0b0110_0000.
        let _ = decode_coefficient_token(
            &[0b0110_0000u8],
            18,
            1,
            0,
            0,
            &mut tis,
            &mut ncoeffs,
            &mut coeffs,
        )
        .unwrap();
        assert_eq!(coeffs[0][0], 12);
    }

    /// TOKEN=19 reads 4 bits total: SIGN + 3-bit MAG, offset 13.
    /// MAG_RAW=7 + SIGN=1 → -20.
    #[test]
    fn coeff_token_19_three_bit_mag_offset_13() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // SIGN=1, MAG_RAW=7. Bits: 1_111_xxxx = 0b1111_0000.
        let _ = decode_coefficient_token(
            &[0b1111_0000u8],
            19,
            1,
            0,
            0,
            &mut tis,
            &mut ncoeffs,
            &mut coeffs,
        )
        .unwrap();
        assert_eq!(coeffs[0][0], -20);
    }

    /// TOKEN=20 reads 5 bits: SIGN + 4-bit MAG, offset 21. The lowest
    /// magnitude is 21 (mag_raw=0); the highest is 36 (mag_raw=15).
    #[test]
    fn coeff_token_20_range_endpoints() {
        for (mag_raw, sign, expected) in [(0u32, 0u8, 21i16), (15, 1, -36)] {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
            // 5 bits: SIGN(1) + MAG(4); pack at top.
            let byte = (((sign as u32) << 7) | ((mag_raw & 0xf) << 3)) as u8;
            let _ =
                decode_coefficient_token(&[byte], 20, 1, 0, 0, &mut tis, &mut ncoeffs, &mut coeffs)
                    .unwrap();
            assert_eq!(coeffs[0][0], expected, "mag_raw={mag_raw} sign={sign}");
        }
    }

    /// TOKEN=21 reads 6 bits: SIGN + 5-bit MAG, offset 37. Spot-check
    /// the midrange.
    #[test]
    fn coeff_token_21_midrange() {
        let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
        // SIGN=0, MAG_RAW=16 → MAG=53.
        // 6 bits: SIGN(1) + MAG(5); pack: 0_10000_xx = 0b0100_0000.
        let _ = decode_coefficient_token(
            &[0b0100_0000u8],
            21,
            1,
            0,
            0,
            &mut tis,
            &mut ncoeffs,
            &mut coeffs,
        )
        .unwrap();
        assert_eq!(coeffs[0][0], 53);
    }

    /// Each §7.7.2 token reads exactly as many bits as Table 7.38
    /// declares in the "Extra Bits" column. This regression catches a
    /// future edit that mis-orders SIGN/MAG/RLEN reads.
    #[test]
    fn coeff_token_bit_counts_match_table_7_38() {
        // (token, expected bits read after the token byte itself).
        for (token, expected_bits) in [
            (7u8, 3u32), // RLEN(3)
            (8, 6),      // RLEN(6)
            (9, 0),      // no extra
            (10, 0),
            (11, 0),
            (12, 0),
            (13, 1), // SIGN(1)
            (14, 1),
            (15, 1),
            (16, 1),
            (17, 2),  // SIGN(1) + MAG(1)
            (18, 3),  // SIGN(1) + MAG(2)
            (19, 4),  // SIGN(1) + MAG(3)
            (20, 5),  // SIGN(1) + MAG(4)
            (21, 6),  // SIGN(1) + MAG(5)
            (22, 10), // SIGN(1) + MAG(9)
            (23, 1),  // SIGN(1)
            (24, 1),
            (25, 1),
            (26, 1),
            (27, 1),
            (28, 3), // SIGN(1) + RLEN(2)
            (29, 4), // SIGN(1) + RLEN(3)
            (30, 2), // SIGN(1) + MAG(1)
            (31, 3), // SIGN(1) + MAG(1) + RLEN(1)
        ] {
            let (mut tis, mut ncoeffs, mut coeffs) = fresh_coeff_state(1);
            // Provide a generous 32-byte buffer of zeros — any token
            // can read its payload, and the tail-position telemetry
            // confirms the exact bit count.
            let packet = [0u8; 32];
            let mut r = BitReader::new(&packet);
            let _ = decode_coefficient_token_inner(
                &mut r,
                token,
                1,
                0,
                0,
                &mut tis,
                &mut ncoeffs,
                &mut coeffs,
            )
            .unwrap();
            // Compute how many bits the reader has advanced. byte_pos
            // and bit_pos let us reconstruct the total.
            let bits_consumed = (r.byte_pos as u32) * 8 + (7u32.wrapping_sub(r.bit_pos as u32));
            assert_eq!(
                bits_consumed, expected_bits,
                "TOKEN={token} expected {expected_bits} bits, got {bits_consumed}"
            );
        }
    }

    // =================================================================
    // §7.7.3 DCT Coefficient Decode tests
    // =================================================================

    /// Build an 80-element Huffman-table set where every table is the
    /// same single-leaf table that maps the empty code to `token`. The
    /// driver picks tables by `(HG, htiL|htiC)` so a single-leaf table
    /// in every slot lets the driver read TOKEN deterministically
    /// without forcing the test to lay out 80 distinct tables.
    ///
    /// Single-leaf tables are degenerate but spec-legal — the
    /// `HuffmanTable::lookup` doc explicitly calls out the "root is a
    /// leaf" shape — and our [`HuffmanTable::read_token`] handles it
    /// without consuming any bits, which is exactly what we want for a
    /// driver smoke test.
    fn make_uniform_hts(token: u8) -> Vec<HuffmanTable> {
        let entry = HuffmanEntry {
            code: 0,
            len: 0,
            token,
        };
        let table = HuffmanTable {
            entries: vec![entry],
            nodes: vec![HuffmanNode::Leaf { token }],
        };
        vec![table; NUM_HUFFMAN_TABLES]
    }

    /// Table 7.42 row check.
    #[test]
    fn huffman_table_group_table_7_42() {
        assert_eq!(huffman_table_group(0), 0);
        for ti in 1u8..=5 {
            assert_eq!(huffman_table_group(ti), 1, "ti={ti}");
        }
        for ti in 6u8..=14 {
            assert_eq!(huffman_table_group(ti), 2, "ti={ti}");
        }
        for ti in 15u8..=27 {
            assert_eq!(huffman_table_group(ti), 3, "ti={ti}");
        }
        for ti in 28u8..=63 {
            assert_eq!(huffman_table_group(ti), 4, "ti={ti}");
        }
    }

    /// `bcoded.len() != nbs` is caught at the input-validation gate
    /// before any state is allocated.
    #[test]
    fn dct_coefficients_rejects_bcoded_len_mismatch() {
        let hts = make_uniform_hts(0);
        let r = decode_dct_coefficients(&[], 4, 1, &[1u8, 0u8], &hts);
        match r {
            Err(Error::DctCoefficientBcodedLenMismatch { got, nbs }) => {
                assert_eq!(got, 2);
                assert_eq!(nbs, 4);
            }
            other => panic!("expected DctCoefficientBcodedLenMismatch, got {other:?}"),
        }
        // Display rendering carries the section tag.
        let s = format!(
            "{}",
            Error::DctCoefficientBcodedLenMismatch { got: 2, nbs: 4 }
        );
        assert!(s.contains("§7.7.3"));
    }

    /// `nmbs * 4 > nbs` is rejected — every macro-block carries four
    /// luma blocks, so `NLBS` exceeding `NBS` is a contradiction.
    #[test]
    fn dct_coefficients_rejects_nlbs_exceeds_nbs() {
        let hts = make_uniform_hts(0);
        // nmbs=2 ⇒ nlbs=8; nbs=4 ⇒ nlbs > nbs.
        let bcoded = vec![0u8; 4];
        let r = decode_dct_coefficients(&[], 4, 2, &bcoded, &hts);
        match r {
            Err(Error::DctCoefficientNlbsExceedsNbs { nmbs, nbs }) => {
                assert_eq!(nmbs, 2);
                assert_eq!(nbs, 4);
            }
            other => panic!("expected DctCoefficientNlbsExceedsNbs, got {other:?}"),
        }
    }

    /// `bcoded` all-zero short-circuit: the driver still reads the
    /// `htiL` + `htiC` at ti=0 and ti=1 (4+4+4+4 = 16 bits total), but
    /// performs no per-block work. EOBS stays zero (no token decoded),
    /// every TIS stays at 0, and the closure check skips uncoded
    /// blocks per the spec text.
    #[test]
    fn dct_coefficients_all_uncoded_reads_only_table_indices() {
        let hts = make_uniform_hts(0);
        // 16 bits = 2 bytes; payload value irrelevant (no token decode).
        let packet = [0u8, 0u8];
        let bcoded = vec![0u8; 4];
        let (coeffs, ncoeffs) = decode_dct_coefficients(&packet, 4, 1, &bcoded, &hts).unwrap();
        assert_eq!(coeffs.len(), 4);
        assert_eq!(ncoeffs.len(), 4);
        for bi in 0..4 {
            assert_eq!(coeffs[bi], [0i16; 64]);
            assert_eq!(ncoeffs[bi], 0);
        }
    }

    /// Drive a 1-block frame where TOKEN=0 (EOB run of length 1) at
    /// ti=0. Table 7.42 maps ti=0 to HG=0, so hti = 0; with a
    /// single-leaf HTS[0] mapping to TOKEN=0, the driver:
    ///   * reads htiL (4 bits) + htiC (4 bits) at ti=0 — 8 bits total
    ///   * picks HTS[0], reads zero bits to recognise TOKEN=0
    ///   * calls §7.7.1 with TOKEN=0 — zero-fills the entire block,
    ///     TIS=64, returns EOBS=0 (after the step-11 decrement of the
    ///     fixed run length 1)
    ///   * reads htiL (4 bits) + htiC (4 bits) at ti=1 — 8 more bits
    ///   * skips the per-block loop at every ti >= 1 because TIS=64
    ///
    /// Total bits read: 16. Block ends fully zero with TIS pinned.
    #[test]
    fn dct_coefficients_single_block_eob_run_token_0() {
        let hts = make_uniform_hts(0);
        let packet = [0u8, 0u8];
        let bcoded = vec![1u8];
        let (coeffs, ncoeffs) = decode_dct_coefficients(&packet, 1, 0, &bcoded, &hts).unwrap();
        assert_eq!(coeffs[0], [0i16; 64]);
        // Step 4(b)i runs once at ti=0 with NCOEFFS[0] = 0; the §7.7.1
        // step-9 write inside the token expander then sets NCOEFFS[0]
        // to the pre-call TIS (still 0).
        assert_eq!(ncoeffs[0], 0);
    }

    /// Drive a 1-block frame where the table maps the empty code to
    /// TOKEN=9 (the fixed `+1` single-coefficient token from §7.7.2).
    /// The driver iterates ti from 0 upward; at every ti where TIS=ti
    /// (which is every ti, given each token writes exactly one
    /// coefficient), it decodes TOKEN=9 and advances TIS by 1.
    /// Because TOKEN=9 has zero extra-bit payload (Table 7.38 column
    /// "Extra Bits" = 0) and the table itself consumes zero bits, the
    /// loop reads exactly 16 bits (the htiL/htiC at ti=0,1) and fills
    /// the entire 64-entry block with +1. At the end NCOEFFS=64 and
    /// TIS=64, satisfying the §7.7.3 closing-paragraph contract.
    #[test]
    fn dct_coefficients_single_block_full_token_9_fill() {
        let hts = make_uniform_hts(9);
        let packet = [0u8, 0u8];
        let bcoded = vec![1u8];
        let (coeffs, ncoeffs) = decode_dct_coefficients(&packet, 1, 0, &bcoded, &hts).unwrap();
        assert_eq!(coeffs[0], [1i16; 64]);
        assert_eq!(ncoeffs[0], 64);
    }

    // ----- §7.7 forward token encode round-trip (round 338) -----

    /// Encode a frame's quantized DCT coefficients with the §7.7 forward
    /// token writer, then decode them back through `decode_dct_
    /// coefficients` and confirm the coefficients survive the round
    /// trip exactly. Uses the full default Huffman tables (the fixture
    /// setup header), which carry every token.
    #[test]
    fn encode_dct_coefficients_round_trips_through_decoder() {
        let setup = decode_setup_header(&fixture_data::FIXTURE_SETUP_PACKET).unwrap();
        let hts = &setup.huffman_tables[..];

        // Eight coded blocks with nmbs=1 (nlbs=4): blocks 0..3 are luma
        // and use htiL, blocks 4..7 are chroma and use htiC, so the
        // round trip exercises both table selectors. Each block carries
        // a distinct coefficient profile.
        let nbs = 8u32;
        let nmbs = 1u32;
        let bcoded = vec![1u8; 8];
        let mut coeffs = vec![[0i16; 64]; 8];
        // Block 0: all zero.
        // Block 1: DC only.
        coeffs[1][0] = -37;
        // Block 2: DC + a few AC including a zero gap and large mag.
        coeffs[2][0] = 5;
        coeffs[2][1] = 1;
        coeffs[2][2] = -2;
        coeffs[2][7] = 100; // forces a zero run then a 9-bit-mag token
        coeffs[2][20] = -300;
        // Block 3 (luma): a single mid-range AC.
        coeffs[3][4] = 45;
        // Block 4 (chroma): DC + AC.
        coeffs[4][0] = 12;
        coeffs[4][5] = -6;
        // Block 5 (chroma): all zero.
        // Block 6 (chroma): tail AC only.
        coeffs[6][63] = 3;
        // Block 7 (chroma): full-range coefficients.
        coeffs[7][0] = 580;
        coeffs[7][1] = -580;

        let mut w = super::BitWriter::new();
        encode_dct_coefficients_inner(&mut w, nbs, nmbs, &bcoded, &coeffs, hts).unwrap();
        let bytes = w.into_bytes();

        let (decoded, _ncoeffs) = decode_dct_coefficients(&bytes, nbs, nmbs, &bcoded, hts).unwrap();
        for bi in 0..8 {
            assert_eq!(decoded[bi], coeffs[bi], "block {bi} coefficients differ");
        }
    }

    /// `best_huffman_selector` returns the §7.7.3 table selector whose
    /// summed code length is minimal over the 16 candidates, and never
    /// scores worse than the fixed-`0` selector it replaced.
    #[test]
    fn best_huffman_selector_minimizes_total_code_length() {
        let setup = SetupHeaderTables::vp3_defaults();
        let hts = &setup.huffman_tables[..];

        // A tally that concentrates on a single group/token: whichever
        // selector gives that token its shortest code must win.
        let mut tally = [[0u32; 32]; 5];
        // Group 4 (high-frequency AC), token 9 (single +1 coefficient),
        // emitted many times.
        tally[4][9] = 1000;
        let sel = best_huffman_selector(hts, &tally, 1..=4);

        // Independently find the selector minimizing len(hts[64+s], 9).
        let mut want = 0u8;
        let mut want_len = u8::MAX;
        for s in 0u8..16 {
            let (_, len) = huffman_code_for_token(&hts[64 + s as usize], 9).unwrap();
            if len < want_len {
                want_len = len;
                want = s;
            }
        }
        assert_eq!(sel, want, "selector must minimize the concentrated token");

        // The chosen selector is never worse than selector 0 over the
        // groups it covers (1..=4, the AC groups).
        let cost = |s: u8| -> u64 {
            (1..5)
                .map(|hg| {
                    let t = &hts[16 * hg + s as usize];
                    (0..32u8)
                        .map(|tok| {
                            let c = u64::from(tally[hg][tok as usize]);
                            if c == 0 {
                                0
                            } else {
                                c * u64::from(huffman_code_for_token(t, tok).unwrap().1)
                            }
                        })
                        .sum::<u64>()
                })
                .sum()
        };
        assert!(cost(sel) <= cost(0), "optimized selector never beaten by 0");

        // The DC-group decision is independent: a tally concentrated on
        // group 0 must pick the selector minimizing the *group-0* code
        // length, regardless of what the AC groups would prefer.
        let mut dc_tally = [[0u32; 32]; 5];
        dc_tally[0][22] = 1000;
        let dc_sel = best_huffman_selector(hts, &dc_tally, 0..=0);
        let mut want_dc = 0u8;
        let mut want_dc_len = u8::MAX;
        for s in 0u8..16 {
            let (_, len) = huffman_code_for_token(&hts[s as usize], 22).unwrap();
            if len < want_dc_len {
                want_dc_len = len;
                want_dc = s;
            }
        }
        assert_eq!(dc_sel, want_dc, "DC selector must minimize group 0 alone");
    }

    /// The frame token writer picks a size-optimizing `htiL` / `htiC`:
    /// on a token mix that favours a non-zero selector the coded frame
    /// is no larger than the fixed-`0` encoding, and it still decodes
    /// back to the exact coefficients.
    #[test]
    fn encode_dct_coefficients_selector_never_grows_frame() {
        let setup = SetupHeaderTables::vp3_defaults();
        let hts = &setup.huffman_tables[..];

        // Many coded blocks with a repeated token profile so a non-zero
        // selector can pay off.
        let nbs = 32u32;
        let nmbs = 8u32; // nlbs = 32 → all luma here; add chroma below.
        let bcoded = vec![1u8; nbs as usize];
        let mut coeffs = vec![[0i16; 64]; nbs as usize];
        for (bi, c) in coeffs.iter_mut().enumerate() {
            c[0] = if bi % 2 == 0 { 1 } else { -1 };
            c[5] = 2;
            c[18] = -1;
            c[40] = 1;
        }

        let mut w = super::BitWriter::new();
        encode_dct_coefficients_inner(&mut w, nbs, nmbs, &bcoded, &coeffs, hts).unwrap();
        let bytes = w.into_bytes();

        // Round-trips exactly through the decoder.
        let (decoded, _n) = decode_dct_coefficients(&bytes, nbs, nmbs, &bcoded, hts).unwrap();
        for bi in 0..nbs as usize {
            assert_eq!(decoded[bi], coeffs[bi], "block {bi}");
        }

        // The selector path is never larger than forcing selector 0. The
        // first byte's high nibble is htiL; if it is non-zero the
        // optimizer chose a different table — and either way the encoded
        // size must not exceed the fixed-0 cost computed from the tables.
        let mut tally = [[[0u32; 32]; 5]; 2];
        {
            let mut plan_idx = vec![0usize; nbs as usize];
            let mut tis = vec![0u8; nbs as usize];
            let plans: Vec<Vec<PlannedToken>> = coeffs
                .iter()
                .map(|c| plan_block_tokens(c).unwrap())
                .collect();
            for ti in 0u8..=63 {
                let hg = huffman_table_group(ti) as usize;
                for bi in 0..nbs as usize {
                    if tis[bi] != ti {
                        continue;
                    }
                    let pt = plans[bi][plan_idx[bi]];
                    plan_idx[bi] += 1;
                    tally[0][hg][pt.token as usize] += 1; // all luma here
                    tis[bi] = ((tis[bi] as u16 + pt.advance as u16).min(64)) as u8;
                }
            }
        }
        let dc_sel = best_huffman_selector(hts, &tally[0], 0..=0);
        let ac_sel = best_huffman_selector(hts, &tally[0], 1..=4);
        let group_cost = |hg: usize, s: u8| -> u64 {
            let t = &hts[16 * hg + s as usize];
            (0..32u8)
                .map(|tok| {
                    let c = u64::from(tally[0][hg][tok as usize]);
                    if c == 0 {
                        0
                    } else {
                        c * u64::from(huffman_code_for_token(t, tok).unwrap().1)
                    }
                })
                .sum::<u64>()
        };
        let split_cost =
            group_cost(0, dc_sel) + (1..5).map(|hg| group_cost(hg, ac_sel)).sum::<u64>();
        let fixed0_cost = (0..5).map(|hg| group_cost(hg, 0)).sum::<u64>();
        assert!(split_cost <= fixed0_cost);

        // The split decision is also never worse than the best *joint*
        // selector (the joint optimum applies one selector to all five
        // groups; the split search space contains every joint choice).
        let joint_best = (0u8..16)
            .map(|s| (0..5).map(|hg| group_cost(hg, s)).sum::<u64>())
            .min()
            .unwrap();
        assert!(split_cost <= joint_best);
    }

    /// The writer emits *independent* selector pairs at ti = 0 and
    /// ti = 1: a frame whose DC-group tokens prefer one table while its
    /// AC-group tokens prefer another carries two different pairs on
    /// the wire, and the stream still decodes back to the exact
    /// coefficients (the decoder re-reads the pair at ti = 1).
    #[test]
    fn encode_dct_coefficients_split_dc_ac_selectors_round_trip() {
        let setup = SetupHeaderTables::vp3_defaults();
        let hts = &setup.huffman_tables[..];

        // DC concentrated on large magnitudes (token 22), AC on ±1
        // (token 9): under the VP3 default tables these favour
        // different selectors within their groups.
        let nbs = 16u32;
        let nmbs = 4u32; // nlbs = 16 → all-luma frame.
        let bcoded = vec![1u8; nbs as usize];
        let mut coeffs = vec![[0i16; 64]; nbs as usize];
        for c in coeffs.iter_mut() {
            c[0] = 100; // token 22 in group 0.
            c[1] = 1; // token 9 in group 1.
            c[6] = 1; // token 9 in group 2.
        }

        let mut w = super::BitWriter::new();
        encode_dct_coefficients_inner(&mut w, nbs, nmbs, &bcoded, &coeffs, hts).unwrap();
        let bytes = w.into_bytes();

        // Round-trips exactly through the §7.7.3 decoder.
        let (decoded, _n) = decode_dct_coefficients(&bytes, nbs, nmbs, &bcoded, hts).unwrap();
        for bi in 0..nbs as usize {
            assert_eq!(decoded[bi], coeffs[bi], "block {bi}");
        }

        // Rebuild the frame's planned emission (visit list with EOB
        // runs coalesced, plus the written-token tally), then derive
        // the independent per-range optima and the exact bit count the
        // split emission must produce.
        let plan = plan_frame_tokens(nbs, nmbs, &bcoded, &coeffs).unwrap();
        let tally = &plan.tally[0]; // all-luma frame.
        let extra_bits: u64 = plan
            .visits
            .iter()
            .filter_map(|v| v.write.as_ref())
            .map(|pt| {
                (0..pt.n_extra as usize)
                    .map(|k| u64::from(pt.extra[k].1))
                    .sum::<u64>()
            })
            .sum();
        let want_dc = best_huffman_selector(hts, tally, 0..=0);
        let want_ac = best_huffman_selector(hts, tally, 1..=4);
        assert_ne!(
            want_dc, want_ac,
            "test profile must exercise diverging DC/AC selector preferences"
        );

        // htiL(ti=0) is the first nibble of the stream.
        assert_eq!(bytes[0] >> 4, want_dc, "ti=0 htiL nibble");

        // The total coded size must equal the split-selector cost
        // model exactly: 2 selector pairs (16 bits) + Huffman code
        // lengths under (DC table at group 0, AC table at groups
        // 1..=4) + the extra-bits payloads. This pins that the AC pair
        // written at ti = 1 — which is not byte-aligned — is the
        // optimized one (any other selector value has a different
        // summed code length for this profile).
        let sel_for = |hg: usize| if hg == 0 { want_dc } else { want_ac };
        let mut huff_bits: u64 = 0;
        for (hg, counts) in tally.iter().enumerate() {
            let t = &hts[16 * hg + sel_for(hg) as usize];
            for (tok, &c) in counts.iter().enumerate() {
                if c != 0 {
                    huff_bits +=
                        u64::from(c) * u64::from(huffman_code_for_token(t, tok as u8).unwrap().1);
                }
            }
        }
        let expected_bits = 16 + huff_bits + extra_bits;
        assert_eq!(
            bytes.len() as u64,
            expected_bits.div_ceil(8),
            "coded size must match the split-selector cost model"
        );
    }

    /// The token planner closes an all-zero block with a single EOB and
    /// a fully-populated block with single-coefficient tokens.
    #[test]
    fn plan_block_tokens_shapes() {
        // All-zero → one EOB token (token 0) consuming all 64 slots.
        let plan = plan_block_tokens(&[0i16; 64]).unwrap();
        assert_eq!(plan.len(), 1);
        assert_eq!(plan[0].token, 0);
        assert_eq!(plan[0].advance, 64);

        // DC-only +1 → single-coefficient token 9 then a closing EOB.
        let mut c = [0i16; 64];
        c[0] = 1;
        let plan = plan_block_tokens(&c).unwrap();
        assert_eq!(plan[0].token, 9);
        assert_eq!(plan.last().unwrap().token, 0);
        // Total advance covers all 64 positions.
        let total: u16 = plan.iter().map(|p| p.advance as u16).sum();
        assert_eq!(total, 64);
    }

    /// The planner folds a zero gap plus its terminating coefficient
    /// into the correct §7.7.2 combined run+value token (23..=31), uses
    /// the 3-bit zero-run token 7 for short uncombinable gaps, and only
    /// falls back to the 6-bit token 8 for long ones.
    #[test]
    fn plan_block_tokens_combined_run_value_tokens() {
        // (gap length, trailing value, expected token). One combined
        // token covers the pair, so the plan is exactly [combined, EOB].
        let cases: &[(usize, i16, u8)] = &[
            (1, 1, 23),
            (2, -1, 24),
            (3, 1, 25),
            (4, -1, 26),
            (5, 1, 27),
            (6, 1, 28),
            (9, -1, 28),
            (10, 1, 29),
            (17, -1, 29),
            (1, 2, 30),
            (1, -3, 30),
            (2, 2, 31),
            (3, -3, 31),
        ];
        for &(gap, v, want) in cases {
            let mut c = [0i16; 64];
            c[gap] = v;
            let plan = plan_block_tokens(&c).unwrap();
            assert_eq!(plan.len(), 2, "gap={gap} v={v}: combined + EOB only");
            assert_eq!(plan[0].token, want, "gap={gap} v={v}");
            assert_eq!(plan[0].advance as usize, gap + 1, "gap={gap} v={v}");
            assert_eq!(plan[1].token, 0);
            let total: u16 = plan.iter().map(|p| p.advance as u16).sum();
            assert_eq!(total, 64, "gap={gap} v={v}");
        }

        // No combined token covers (run 4, |v| = 4): short gap → token
        // 7 (3-bit RLEN), then the ±4 single-coefficient token.
        let mut c = [0i16; 64];
        c[4] = 4;
        let plan = plan_block_tokens(&c).unwrap();
        assert_eq!(plan[0].token, 7);
        assert_eq!(plan[0].advance, 4);
        assert_eq!(plan[1].token, 14);

        // Run 18 with a trailing ±1 exceeds token 29's reach → token 8
        // (6-bit RLEN) then the single coefficient.
        let mut c = [0i16; 64];
        c[18] = 1;
        let plan = plan_block_tokens(&c).unwrap();
        assert_eq!(plan[0].token, 8);
        assert_eq!(plan[0].advance, 18);
        assert_eq!(plan[1].token, 9);

        // Run 9 with a trailing ±2 (tokens 30/31 reach only runs
        // 1..=3) → longer-than-8 gap uses token 8.
        let mut c = [0i16; 64];
        c[9] = 2;
        let plan = plan_block_tokens(&c).unwrap();
        assert_eq!(plan[0].token, 8);
        assert_eq!(plan[1].token, 11);
    }

    /// Every combined run+value token (23..=31) and the short zero-run
    /// token 7 survive a full frame encode → §7.7.3 decode round trip
    /// bit-exactly.
    #[test]
    fn encode_dct_coefficients_combined_tokens_round_trip() {
        let setup = SetupHeaderTables::vp3_defaults();
        let hts = &setup.huffman_tables[..];

        // One block per combined-token case, plus the token-7 and
        // token-8 fallback shapes, across luma and chroma.
        let patterns: &[(usize, i16)] = &[
            (1, 1),
            (2, -1),
            (3, 1),
            (4, -1),
            (5, 1),
            (6, 1),
            (9, -1),
            (10, 1),
            (17, -1),
            (1, 2),
            (1, -3),
            (2, 2),
            (3, -3),
            (4, 4),  // token 7 + single.
            (18, 1), // token 8 + single.
            (9, 2),  // token 8 + single.
        ];
        let nbs = patterns.len() as u32;
        let nmbs = 2u32; // nlbs = 8: first 8 blocks luma, rest chroma.
        let bcoded = vec![1u8; nbs as usize];
        let mut coeffs = vec![[0i16; 64]; nbs as usize];
        for (bi, &(gap, v)) in patterns.iter().enumerate() {
            coeffs[bi][gap] = v;
            // A trailing coefficient too, so the combined token is
            // mid-block for half the cases (exercises TIS advance).
            if bi % 2 == 0 {
                coeffs[bi][40] = -2;
            }
        }

        let mut w = super::BitWriter::new();
        encode_dct_coefficients_inner(&mut w, nbs, nmbs, &bcoded, &coeffs, hts).unwrap();
        let bytes = w.into_bytes();

        let (decoded, _n) = decode_dct_coefficients(&bytes, nbs, nmbs, &bcoded, hts).unwrap();
        for bi in 0..nbs as usize {
            assert_eq!(decoded[bi], coeffs[bi], "block {bi} coefficients differ");
        }
    }

    /// Consecutive block-end visits coalesce into cross-block §7.7.1
    /// EOB-run tokens (1..=6), the run's tail visits write nothing, and
    /// the coalesced stream decodes bit-exactly — including runs that
    /// cross the luma / chroma boundary and the ti = 1 selector
    /// refresh.
    #[test]
    fn encode_dct_coefficients_cross_block_eob_runs() {
        let setup = SetupHeaderTables::vp3_defaults();
        let hts = &setup.huffman_tables[..];

        // 24 coded blocks (8 luma, 16 chroma): block 0 carries one DC
        // coefficient, blocks 1..24 are all-zero. Pass 0 visits every
        // block: block 0 writes its DC token, then 23 consecutive
        // end-visits follow — one token 5 (16-run) + one token 3
        // (7-run) after greedy chunking... the exact chunking is
        // asserted below from the plan, the wire from the round trip.
        let nbs = 24u32;
        let nmbs = 2u32; // nlbs = 8.
        let bcoded = vec![1u8; nbs as usize];
        let mut coeffs = vec![[0i16; 64]; nbs as usize];
        coeffs[0][0] = 5;
        // Block 0 ends at ti = 1 (after its DC token) — its own end
        // visit is *not* adjacent to the pass-0 run of blocks 1..24.
        let plan = plan_frame_tokens(nbs, nmbs, &bcoded, &coeffs).unwrap();

        // Visit order: (ti=0, bi=0 DC token), (ti=0, bi=1..23 ends),
        // (ti=1, bi=0 end).
        assert_eq!(plan.visits.len(), 25);
        assert_eq!(plan.visits[0].ti, 0);
        assert!(plan.visits[0].write.is_some());
        assert_eq!(plan.visits[0].write.as_ref().unwrap().token, 15); // ±5.

        // The end-visits are: blocks 1..24 at ti = 0, then block 0 at
        // ti = 1 — 24 *consecutive* visits, so they coalesce into ONE
        // run that crosses the ti = 1 pass boundary: token 5 (16..=31
        // with 4-bit payload) at the first end, nothing at the other
        // 23.
        let first_end = plan.visits[1].write.as_ref().unwrap();
        assert_eq!(first_end.token, 5);
        assert_eq!(first_end.extra[0], (24 - 16, 4));
        for (k, v) in plan.visits[2..25].iter().enumerate() {
            assert!(v.write.is_none(), "run tail visit {k} must be silent");
        }
        // The run crosses the luma / chroma boundary (blocks 8.. are
        // chroma; visits[k] is block k's end for k in 1..24) — assert
        // the recorded planes really straddle it — and the ti = 1 pass
        // boundary (block 0's own end, the run's final visit).
        assert_eq!(plan.visits[7].plane, 0);
        assert_eq!(plan.visits[8].plane, 1);
        assert_eq!(plan.visits[23].ti, 0);
        assert_eq!(plan.visits[24].ti, 1);

        // The coalesced stream decodes bit-exactly.
        let mut w = super::BitWriter::new();
        encode_dct_coefficients_inner(&mut w, nbs, nmbs, &bcoded, &coeffs, hts).unwrap();
        let bytes = w.into_bytes();
        let (decoded, _n) = decode_dct_coefficients(&bytes, nbs, nmbs, &bcoded, hts).unwrap();
        for bi in 0..nbs as usize {
            assert_eq!(decoded[bi], coeffs[bi], "block {bi}");
        }

        // And it is strictly smaller than 24 blocks of per-block EOB
        // termination could ever be: 23 EOB codes (≥ 1 bit each) were
        // replaced by one token-5 code + 4 payload bits.
        // (Loose structural bound: the packet must fit in fewer bits
        // than the DC token + 24 individual shortest-possible codes.)
        assert!(bytes.len() <= 8, "got {} bytes", bytes.len());
    }

    /// Every §7.7.1 EOB-run token reach (2, 3, 4..=7, 8..=15, 16..=31,
    /// 32..=4095) and the > 4095 greedy split are chosen correctly and
    /// round-trip through the decoder.
    #[test]
    fn encode_dct_coefficients_eob_run_token_reaches() {
        let setup = SetupHeaderTables::vp3_defaults();
        let hts = &setup.huffman_tables[..];

        // (number of consecutive all-zero blocks, expected first token,
        //  expected extra field or None).
        type EobReachCase = (u32, u8, Option<(u32, u32)>);
        let cases: &[EobReachCase] = &[
            (2, 1, None),
            (3, 2, None),
            (5, 3, Some((1, 2))),
            (12, 4, Some((4, 3))),
            (20, 5, Some((4, 4))),
            (40, 6, Some((40, 12))),
        ];
        for &(n, want_token, want_extra) in cases {
            let nbs = n;
            let nmbs = n / 4; // any nlbs <= nbs split works.
            let bcoded = vec![1u8; nbs as usize];
            let coeffs = vec![[0i16; 64]; nbs as usize];
            let plan = plan_frame_tokens(nbs, nmbs, &bcoded, &coeffs).unwrap();
            assert_eq!(plan.visits.len(), n as usize);
            let first = plan.visits[0].write.as_ref().unwrap();
            assert_eq!(first.token, want_token, "n={n}");
            match want_extra {
                Some(e) => {
                    assert_eq!(first.n_extra, 1, "n={n}");
                    assert_eq!(first.extra[0], e, "n={n}");
                }
                None => assert_eq!(first.n_extra, 0, "n={n}"),
            }
            for v in &plan.visits[1..] {
                assert!(v.write.is_none(), "n={n}: tail visits are silent");
            }

            let mut w = super::BitWriter::new();
            encode_dct_coefficients_inner(&mut w, nbs, nmbs, &bcoded, &coeffs, hts).unwrap();
            let bytes = w.into_bytes();
            let (decoded, _nc) = decode_dct_coefficients(&bytes, nbs, nmbs, &bcoded, hts).unwrap();
            for (bi, blk) in decoded.iter().enumerate() {
                assert_eq!(blk, &[0i16; 64], "n={n} block {bi}");
            }
        }

        // A run longer than token 6's 12-bit payload splits greedily:
        // 4095 + remainder, the second chunk's token carried by the
        // 4096th end-visit.
        let nbs = 5000u32;
        let nmbs = 1250u32;
        let bcoded = vec![1u8; nbs as usize];
        let coeffs = vec![[0i16; 64]; nbs as usize];
        let plan = plan_frame_tokens(nbs, nmbs, &bcoded, &coeffs).unwrap();
        let first = plan.visits[0].write.as_ref().unwrap();
        assert_eq!(first.token, 6);
        assert_eq!(first.extra[0], (4095, 12));
        let second = plan.visits[4095].write.as_ref().unwrap();
        assert_eq!(second.token, 6);
        assert_eq!(second.extra[0], (905, 12));
        for (i, v) in plan.visits.iter().enumerate() {
            if i != 0 && i != 4095 {
                assert!(v.write.is_none(), "visit {i}");
            }
        }
        let mut w = super::BitWriter::new();
        encode_dct_coefficients_inner(&mut w, nbs, nmbs, &bcoded, &coeffs, hts).unwrap();
        let bytes = w.into_bytes();
        let (decoded, _nc) = decode_dct_coefficients(&bytes, nbs, nmbs, &bcoded, hts).unwrap();
        assert!(decoded.iter().all(|c| c == &[0i16; 64]));
    }

    /// `HuffmanTable::from_token_counts` builds a complete (Kraft
    /// equality), all-32-token, deterministic codebook that is never
    /// costlier than the VP3 default table for the counts it was built
    /// from, and caps code lengths at 16 bits under extreme skew.
    #[test]
    fn huffman_from_token_counts_properties() {
        // A skew resembling a real frame: EOB and small-value tokens
        // dominate, large-magnitude tokens are rare.
        let mut counts = [0u64; 32];
        counts[0] = 900;
        counts[9] = 700;
        counts[10] = 650;
        counts[23] = 400;
        counts[7] = 120;
        counts[13] = 60;
        counts[22] = 2;
        let table = HuffmanTable::from_token_counts(0, &counts).unwrap();

        // All 32 tokens present, exactly once each.
        assert_eq!(table.len(), 32);
        let mut seen = [false; 32];
        for e in &table.entries {
            assert!(!seen[e.token as usize], "duplicate token {}", e.token);
            seen[e.token as usize] = true;
        }
        assert!(seen.iter().all(|&s| s));

        // Kraft equality — the code set is a full binary tree.
        let kraft: u64 = table.entries.iter().map(|e| 1u64 << (32 - e.len)).sum();
        assert_eq!(kraft, 1u64 << 32);

        // Never costlier than the VP3 default group-0 table on the
        // counts it was tuned for.
        let vp3 = SetupHeaderTables::vp3_defaults();
        let cost = |t: &HuffmanTable| -> u64 {
            counts
                .iter()
                .enumerate()
                .map(|(tok, &c)| c * u64::from(huffman_code_for_token(t, tok as u8).unwrap().1))
                .sum()
        };
        assert!(cost(&table) <= cost(&vp3.huffman_tables[0]));

        // Deterministic: same counts, same codebook.
        let again = HuffmanTable::from_token_counts(0, &counts).unwrap();
        assert_eq!(table, again);

        // Extreme skew (Fibonacci-ish weights would push the longest
        // code far past 16 bits without the cap): all lengths <= 16.
        let mut fib = [0u64; 32];
        let (mut a, mut b) = (1u64, 1u64);
        for slot in fib.iter_mut() {
            *slot = a;
            let next = a + b;
            a = b;
            b = next;
        }
        let capped = HuffmanTable::from_token_counts(0, &fib).unwrap();
        assert_eq!(capped.len(), 32);
        assert!(capped.entries.iter().all(|e| e.len <= 16));
        let kraft: u64 = capped.entries.iter().map(|e| 1u64 << (32 - e.len)).sum();
        assert_eq!(kraft, 1u64 << 32);
    }

    /// A tuned setup-table set serializes through the §6.4 setup-header
    /// round trip like any other: the tuned codebooks land in selector
    /// slots 0 (luma) / 1 (chroma) of each group, the other 14 slots
    /// keep the base tables, and decode returns the identical set.
    #[test]
    fn tuned_setup_header_round_trips() {
        let base = SetupHeaderTables::vp3_defaults();
        let mut stats = TokenStatistics::new();
        stats.counts[0][0][0] = 500;
        stats.counts[0][0][9] = 300;
        stats.counts[0][2][23] = 250;
        stats.counts[1][1][10] = 200;
        stats.counts[1][4][8] = 100;
        let tuned = base.with_tuned_huffman_tables(&stats).unwrap();

        // Exactly two selector slots are sacrificed (discovered by
        // diffing): one carries the luma-tuned codebooks, the other the
        // chroma-tuned ones, across every group; the other 14 slots
        // keep the base tables.
        let changed: Vec<usize> = (0..16)
            .filter(|&s| tuned.huffman_tables[s] != base.huffman_tables[s])
            .collect();
        assert_eq!(changed.len(), 2, "exactly two slots replaced");
        let s_l = *changed
            .iter()
            .find(|&&s| {
                tuned.huffman_tables[s]
                    == HuffmanTable::from_token_counts(s, &stats.counts[0][0]).unwrap()
            })
            .expect("one changed slot holds the luma-tuned group-0 codebook");
        let s_c = *changed.iter().find(|&&s| s != s_l).unwrap();
        for hg in 0..5 {
            assert_eq!(
                tuned.huffman_tables[16 * hg + s_l],
                HuffmanTable::from_token_counts(16 * hg + s_l, &stats.counts[0][hg]).unwrap()
            );
            assert_eq!(
                tuned.huffman_tables[16 * hg + s_c],
                HuffmanTable::from_token_counts(16 * hg + s_c, &stats.counts[1][hg]).unwrap()
            );
            for s in 0..16 {
                if s == s_l || s == s_c {
                    continue;
                }
                assert_eq!(
                    tuned.huffman_tables[16 * hg + s],
                    base.huffman_tables[16 * hg + s],
                    "fallback slot {s} of group {hg} must keep the base table"
                );
            }
        }
        assert_eq!(tuned.loop_filter_limits, base.loop_filter_limits);
        assert_eq!(tuned.quantization_parameters, base.quantization_parameters);

        let packet = encode_setup_header(&tuned).unwrap();
        let back = decode_setup_header(&packet).unwrap();
        assert_eq!(back, tuned, "tuned setup must survive the §6.4 round trip");
    }

    /// The four-column GOP tuner replaces one distinct slot per
    /// non-empty statistics column (intra-luma, intra-chroma,
    /// inter-luma, inter-chroma), skips all-zero columns without
    /// burning their slot, and the result survives the §6.4 setup
    /// round trip.
    #[test]
    fn gop_tuned_huffman_tables_replace_four_distinct_slots() {
        let base = SetupHeaderTables::vp3_defaults();
        let mut intra = TokenStatistics::new();
        intra.counts[0][0][0] = 500;
        intra.counts[0][2][15] = 220;
        intra.counts[1][1][10] = 130;
        let mut inter = TokenStatistics::new();
        inter.counts[0][0][6] = 400;
        inter.counts[0][3][23] = 90;
        inter.counts[1][4][8] = 60;

        let tuned = base.with_gop_tuned_huffman_tables(&intra, &inter).unwrap();
        let changed: Vec<usize> = (0..16)
            .filter(|&s| tuned.huffman_tables[s] != base.huffman_tables[s])
            .collect();
        assert_eq!(
            changed.len(),
            4,
            "four non-empty columns → four distinct slots replaced (got {changed:?})"
        );
        assert_eq!(tuned.quantization_parameters, base.quantization_parameters);

        // An empty inter tally leaves its two slots untouched.
        let empty = TokenStatistics::new();
        let intra_only = base.with_gop_tuned_huffman_tables(&intra, &empty).unwrap();
        let changed2: Vec<usize> = (0..16)
            .filter(|&s| intra_only.huffman_tables[s] != base.huffman_tables[s])
            .collect();
        assert_eq!(
            changed2.len(),
            2,
            "empty inter columns must be skipped (got {changed2:?})"
        );

        let packet = encode_setup_header(&tuned).unwrap();
        let back = decode_setup_header(&packet).unwrap();
        assert_eq!(
            back, tuned,
            "GOP-tuned setup must survive the §6.4 round trip"
        );
    }

    /// Two-pass Huffman tuning end-to-end: statistics collected from a
    /// frame, tuned tables built from them, the same frame re-encoded
    /// against the tuned setup — the packet is strictly smaller and the
    /// decoder (fed the tuned setup, as a real stream's setup header
    /// would carry) reconstructs the *identical* pixels.
    #[test]
    fn tuned_huffman_tables_shrink_intra_frame() {
        let ident = decode_identification_header(&fixture_data::KI30_IDENT_PACKET).unwrap();
        let base = SetupHeaderTables::vp3_defaults();
        let qi = 48u8;

        let enc = FrameEncoder::new(ident.clone(), base.clone(), qi).unwrap();
        let g = enc.geometry();
        let w_y = g.dims_y.width;
        let mut samples_y = vec![0u8; (g.dims_y.width * g.dims_y.height) as usize];
        for y in 0..g.dims_y.height {
            for x in 0..w_y {
                let tex = if (x / 4 + y / 4) % 2 == 0 { 24 } else { 0 };
                samples_y[(y * w_y + x) as usize] = (16 + (x * 5 + y * 3) % 200 + tex) as u8;
            }
        }
        let w_c = g.dims_c.width;
        let len_c = (g.dims_c.width * g.dims_c.height) as usize;
        let mut samples_cb = vec![0u8; len_c];
        let mut samples_cr = vec![0u8; len_c];
        for y in 0..g.dims_c.height {
            for x in 0..w_c {
                samples_cb[(y * w_c + x) as usize] = (110 + (x * 3) % 40) as u8;
                samples_cr[(y * w_c + x) as usize] = (140 + (y * 3) % 40) as u8;
            }
        }
        let source = SourceFrame {
            samples_y,
            samples_cb,
            samples_cr,
        };

        // Pass 1: collect statistics; pass 2: encode with tuned tables.
        let mut stats = TokenStatistics::new();
        enc.intra_token_statistics(&source, &mut stats).unwrap();
        assert!(
            stats.counts[0].iter().flatten().any(|&c| c > 0),
            "sampling must record luma tokens"
        );
        let tuned = base.with_tuned_huffman_tables(&stats).unwrap();
        let enc_tuned = FrameEncoder::new(ident.clone(), tuned.clone(), qi).unwrap();

        let packet_base = enc.encode_intra_frame(&source).unwrap();
        let packet_tuned = enc_tuned.encode_intra_frame(&source).unwrap();
        assert!(
            packet_tuned.len() < packet_base.len(),
            "tuned {} B must beat default {} B",
            packet_tuned.len(),
            packet_base.len()
        );

        // Identical reconstruction: the tuned tables only re-spell the
        // same quantized coefficients.
        let mut dec_base = FrameDecoder::new(ident.clone(), base).unwrap();
        let mut dec_tuned = FrameDecoder::new(ident, tuned).unwrap();
        let out_base = dec_base.decode_frame(&packet_base).unwrap();
        let out_tuned = dec_tuned.decode_frame(&packet_tuned).unwrap();
        assert_eq!(out_base.frame, out_tuned.frame, "identical pixels");
    }

    /// A coefficient beyond the single-coefficient token range is
    /// rejected at plan time (and surfaces as
    /// `EncodeCoefficientOutOfRange` from the frame writer).
    #[test]
    fn encode_dct_coefficients_rejects_out_of_range_coeff() {
        let setup = decode_setup_header(&fixture_data::FIXTURE_SETUP_PACKET).unwrap();
        let hts = &setup.huffman_tables[..];
        let bcoded = vec![1u8];
        let mut coeffs = vec![[0i16; 64]];
        coeffs[0][0] = 1000; // > 580
        let mut w = super::BitWriter::new();
        let err = encode_dct_coefficients_inner(&mut w, 1, 1, &bcoded, &coeffs, hts).unwrap_err();
        assert_eq!(err, Error::EncodeCoefficientOutOfRange { bi: 0 });
    }

    /// `BitWriter` round-trips every full integer through `BitReader`.
    #[test]
    fn bit_writer_round_trips_through_bit_reader() {
        let mut w = super::BitWriter::new();
        let fields: &[(u32, u32)] = &[(1, 1), (0, 1), (0b101, 3), (0xABCD, 16), (7, 6), (0, 4)];
        for &(v, n) in fields {
            w.write_bits(v, n);
        }
        let bytes = w.into_bytes();
        let mut r = BitReader::new(&bytes);
        for &(v, n) in fields {
            assert_eq!(r.read_bits(n, "test").unwrap(), v);
        }
    }

    /// A coded block whose TOKEN stream runs out of tokens before
    /// TIS hits 64 triggers the §7.7.3 closing-paragraph guard. We
    /// build a degenerate setup: a table mapping to TOKEN=7 with a
    /// 3-bit RLEN payload that the driver will keep reading until
    /// the bit reader runs dry — TruncatedHeader surfaces first
    /// (before the closing-paragraph check), which is the spec-
    /// preferred error (a truncated token stream is the proximate
    /// cause).
    #[test]
    fn dct_coefficients_truncation_during_token_payload() {
        // TOKEN=7 → 3-bit RLEN. Provide only the 16 bits of table
        // indices, no token payload — the very first token decode at
        // ti=0 immediately tries to read RLEN and trips
        // TruncatedHeader from the §7.7.2 RLEN read.
        let hts = make_uniform_hts(7);
        let packet = [0u8, 0u8];
        let bcoded = vec![1u8];
        let r = decode_dct_coefficients(&packet, 1, 0, &bcoded, &hts);
        match r {
            Err(Error::TruncatedHeader { .. }) => {}
            other => panic!("expected TruncatedHeader, got {other:?}"),
        }
    }

    /// Walk-off-tree surfaces when the table has interior branches
    /// pointing past the allocated node array. Constructing such a
    /// table by hand simulates a corrupt setup header reaching the
    /// driver. (Conformant Theora streams cannot produce this from
    /// §6.4.4 because the decode builds the tree breadth-first and
    /// always allocates both children before pushing them — but the
    /// public driver still has to fail closed on the case rather
    /// than panic.)
    #[test]
    fn dct_coefficients_huffman_walk_off_tree() {
        // Hand-crafted table whose only interior node points at
        // child indices well past the node array.
        let table = HuffmanTable {
            entries: vec![HuffmanEntry {
                code: 0,
                len: 1,
                token: 0,
            }],
            nodes: vec![HuffmanNode::Branch {
                zero: 999,
                one: 999,
            }],
        };
        let mut hts = vec![
            HuffmanTable {
                entries: vec![HuffmanEntry {
                    code: 0,
                    len: 0,
                    token: 0,
                }],
                nodes: vec![HuffmanNode::Leaf { token: 0 }],
            };
            NUM_HUFFMAN_TABLES
        ];
        // HG=0, htiL=0 ⇒ hti=0 at ti=0 picks this corrupt table.
        hts[0] = table;
        // Pack htiL=0, htiC=0 at ti=0 and ti=1 (16 bits) then a single
        // 0-bit so the read_token walk consumes one bit and dives into
        // the bogus child index.
        let packet = [0u8, 0u8, 0u8];
        let bcoded = vec![1u8];
        let r = decode_dct_coefficients(&packet, 1, 0, &bcoded, &hts);
        match r {
            Err(Error::DctCoefficientHuffmanWalkOffTree { hti }) => {
                assert_eq!(hti, 0);
            }
            other => panic!("expected DctCoefficientHuffmanWalkOffTree, got {other:?}"),
        }
    }

    /// Empty-table case: an 80-element set in which slot 0 has zero
    /// entries trips the validation gate when ti=0 / hti=0 is reached
    /// for a coded block.
    #[test]
    fn dct_coefficients_empty_huffman_table_rejected() {
        let mut hts = make_uniform_hts(0);
        hts[0] = HuffmanTable {
            entries: vec![],
            nodes: vec![],
        };
        // 8 bits for htiL/htiC at ti=0 then we hit the per-block path.
        let packet = [0u8];
        let bcoded = vec![1u8];
        let r = decode_dct_coefficients(&packet, 1, 0, &bcoded, &hts);
        match r {
            Err(Error::DctCoefficientEmptyHuffmanTable { hti }) => assert_eq!(hti, 0),
            other => panic!("expected DctCoefficientEmptyHuffmanTable, got {other:?}"),
        }
    }

    /// `nbs = 0` short-circuits cleanly: the driver still reads the
    /// 16 bits of htiL/htiC (steps 4(a) at ti=0 and ti=1 are
    /// unconditional on coded-block count per the spec text), and
    /// the closure check is vacuous.
    #[test]
    fn dct_coefficients_zero_nbs_short_circuit() {
        let hts = make_uniform_hts(0);
        let packet = [0u8, 0u8];
        let (coeffs, ncoeffs) = decode_dct_coefficients(&packet, 0, 0, &[], &hts).unwrap();
        assert!(coeffs.is_empty());
        assert!(ncoeffs.is_empty());
    }

    /// `htiL` and `htiC` are read at ti=0 and ti=1 — only. Subsequent
    /// ti values reuse the cached pair without consuming bits. The
    /// test packs htiL=3 and htiC=5 at ti=0, then htiL=3 and htiC=5
    /// at ti=1 (16 bits total), then 0 bytes — yet the driver
    /// completes via the EOB run because TOKEN=0 closes the block.
    #[test]
    fn dct_coefficients_table_indices_only_at_ti_0_and_1() {
        let hts = make_uniform_hts(0); // TOKEN=0 — fixed EOB-run-1.
                                       // Pack htiL=3 (4 bits) + htiC=5 (4 bits) at ti=0; htiL=3 + htiC=5
                                       // at ti=1: 0011_0101 0011_0101 = 0x35 0x35.
        let packet = [0x35, 0x35];
        let bcoded = vec![1u8];
        let (coeffs, ncoeffs) = decode_dct_coefficients(&packet, 1, 0, &bcoded, &hts).unwrap();
        // Block fully zero-filled; closure check satisfied.
        assert_eq!(coeffs[0], [0i16; 64]);
        assert_eq!(ncoeffs[0], 0);
    }

    /// Inner driver shares the bit reader with whatever sits after
    /// §7.7.3 in the frame payload. The test confirms a sentinel byte
    /// read off the same reader after the driver returns is intact.
    #[test]
    fn dct_coefficients_inner_shares_bit_reader() {
        let hts = make_uniform_hts(0); // TOKEN=0 closes the block.
                                       // 8 bits (htiL/htiC at ti=0) + 8 bits (htiL/htiC at ti=1) + 8
                                       // sentinel bits set to 0xA5.
        let packet = [0u8, 0u8, 0xA5u8];
        let bcoded = vec![1u8];
        let mut r = BitReader::new(&packet);
        let (_coeffs, _ncoeffs) =
            decode_dct_coefficients_inner(&mut r, 1, 0, &bcoded, &hts).unwrap();
        let sentinel = r.read_bits(8, "sentinel").unwrap();
        assert_eq!(sentinel, 0xA5);
    }

    /// Two coded blocks: bi=0 in luma (NLBS=4, so bi<NLBS), bi=4
    /// would be chroma. With NMBS=1 ⇒ NLBS=4. Block 0 takes htiL=0,
    /// block 4 takes htiC=0. We use a fresh 5-block frame with only
    /// bi=0 and bi=4 coded, both with the EOB-run-1 token, and
    /// confirm both blocks close.
    #[test]
    fn dct_coefficients_luma_vs_chroma_split() {
        let hts = make_uniform_hts(0);
        let packet = [0u8, 0u8];
        // NBS=5, NMBS=1 ⇒ NLBS=4: bi 0..=3 are luma, bi=4 is chroma.
        let mut bcoded = vec![0u8; 5];
        bcoded[0] = 1; // luma
        bcoded[4] = 1; // chroma
        let (coeffs, ncoeffs) = decode_dct_coefficients(&packet, 5, 1, &bcoded, &hts).unwrap();
        // Both coded blocks are zero (TOKEN=0 EOB run).
        assert_eq!(coeffs[0], [0i16; 64]);
        assert_eq!(coeffs[4], [0i16; 64]);
        // Uncoded blocks stay at default zero.
        for bi in [1usize, 2, 3] {
            assert_eq!(coeffs[bi], [0i16; 64]);
            assert_eq!(ncoeffs[bi], 0);
        }
    }

    /// EOB-run residue at end of frame: TOKEN=6 with a 12-bit payload
    /// of 4095 produces an EOB run far longer than any frame's coded-
    /// block count. The driver decodes it on the first coded block,
    /// then exhausts the per-ti loop without further per-block work
    /// (nothing left to consume the run); the closing-paragraph guard
    /// fires with the residue.
    #[test]
    fn dct_coefficients_leftover_eobs_rejected() {
        let hts = make_uniform_hts(6);
        // TOKEN=6 reads 12 bits of payload. Pack 8 bits of htiL/htiC=0
        // at ti=0 then 12 bits of payload = 0xFFF then 4 bits of
        // htiL/htiC=0 at ti=1 (driver only reaches ti=1 if blocks
        // remain open, but EOBS pin them; ti=1 still reads htiL/htiC
        // unconditionally per step 4(a)).
        // Bit layout (MSb-first): hti_at_0(8) + payload(12) + hti_at_1(8)
        //   = 0000_0000 1111_1111 1111_0000 0000_0000 = 0x00 0xFF 0xF0 0x00
        let packet = [0x00, 0xFF, 0xF0, 0x00];
        let bcoded = vec![1u8];
        let r = decode_dct_coefficients(&packet, 1, 0, &bcoded, &hts);
        match r {
            Err(Error::DctCoefficientLeftoverEobs { residual }) => {
                // TOKEN=6 payload 4095 means EOBS=4095 pre-step-11,
                // then -=1 once for our single coded block ⇒ 4094.
                assert_eq!(residual, 4094);
            }
            other => panic!("expected DctCoefficientLeftoverEobs, got {other:?}"),
        }
    }

    /// `Display` rendering carries the section tag for every new
    /// §7.7.3 error variant.
    #[test]
    fn dct_coefficients_error_display_carries_section_tag() {
        for s in [
            format!(
                "{}",
                Error::DctCoefficientNlbsExceedsNbs { nmbs: 2, nbs: 4 }
            ),
            format!("{}", Error::DctCoefficientEmptyHuffmanTable { hti: 7 }),
            format!("{}", Error::DctCoefficientHuffmanWalkOffTree { hti: 7 }),
            format!("{}", Error::DctCoefficientLeftoverEobs { residual: 3 }),
            format!("{}", Error::DctCoefficientBlockNotClosed { bi: 2, tis: 17 }),
        ] {
            assert!(s.contains("§7.7.3"), "missing §7.7.3 tag in: {s}");
        }
    }

    // -----------------------------------------------------------------
    // §7.8.1 Computing the DC Predictor — round 18 tests
    // -----------------------------------------------------------------

    /// Helper: build a 1-block coeffs array with the given DC value.
    fn coeffs_with_dc(dcs: &[i16]) -> Vec<[i16; 64]> {
        dcs.iter()
            .map(|&dc| {
                let mut row = [0i16; 64];
                row[0] = dc;
                row
            })
            .collect()
    }

    /// Table 7.46 — every coding mode maps to the spec-printed
    /// reference-frame index.
    #[test]
    fn reference_frame_table_7_46_round_trip() {
        use MacroBlockMode::*;
        use ReferenceFrame::*;
        let cases = [
            (InterNoMv, Previous),
            (Intra, None),
            (InterMv, Previous),
            (InterMvLast, Previous),
            (InterMvLast2, Previous),
            (InterGoldenNoMv, Golden),
            (InterGoldenMv, Golden),
            (InterMvFour, Previous),
        ];
        for (mode, rfi) in cases {
            assert_eq!(reference_frame_for_mb_mode(mode), rfi);
            assert_eq!(
                rfi.index(),
                match rfi {
                    None => 0,
                    Previous => 1,
                    Golden => 2,
                }
            );
        }
    }

    /// Table 7.47 — every non-zero `(P[0], P[1], P[2], P[3])` bitmask
    /// returns the spec's weights/divisor. Spot-check a handful of
    /// rows including the signed-weight entry and the all-ones row.
    #[test]
    fn table_7_47_known_rows() {
        assert_eq!(dc_predictor_weights(0), None);
        assert_eq!(
            dc_predictor_weights(0b0001).unwrap(),
            DcPredictorWeights {
                w: [1, 0, 0, 0],
                pdiv: 1
            }
        );
        assert_eq!(
            dc_predictor_weights(0b0111).unwrap(),
            DcPredictorWeights {
                w: [29, -26, 29, 0],
                pdiv: 32
            }
        );
        assert_eq!(
            dc_predictor_weights(0b1001).unwrap(),
            DcPredictorWeights {
                w: [75, 0, 0, 53],
                pdiv: 128
            }
        );
        assert_eq!(
            dc_predictor_weights(0b1110).unwrap(),
            DcPredictorWeights {
                w: [0, 3, 10, 3],
                pdiv: 16
            }
        );
        assert_eq!(
            dc_predictor_weights(0b1111).unwrap(),
            DcPredictorWeights {
                w: [29, -26, 29, 0],
                pdiv: 32
            }
        );
        assert_eq!(dc_predictor_weights(16), None);
    }

    /// Step 11 fallback — when no neighbours qualify, the predictor
    /// is `LASTDC[rfi]` for the current block's reference frame.
    #[test]
    fn dc_predictor_step_11_lastdc_fallback() {
        let bcoded = vec![1u8];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32];
        let neighbors = vec![DcPredictorNeighbors::default()];
        let mut lastdc = DcLastDc::zero();
        lastdc.intra = 42;
        lastdc.previous = -17;
        lastdc.golden = 99;
        let c = coeffs_with_dc(&[0]);
        // Intra mode → rfi = None → LASTDC[0] = 42.
        let dcpred =
            compute_dc_predictor(0, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 42);

        // Repeat with InterGoldenMv → rfi = Golden → LASTDC[2] = 99.
        let mbmodes2 = vec![MacroBlockMode::InterGoldenMv];
        let dcpred =
            compute_dc_predictor(0, &bcoded, &mbmodes2, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 99);

        // And with InterMv → rfi = Previous → LASTDC[1] = -17.
        let mbmodes3 = vec![MacroBlockMode::InterMv];
        let dcpred =
            compute_dc_predictor(0, &bcoded, &mbmodes3, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, -17);
    }

    /// Single-left-neighbour predictor: P=0b0001 → DCPRED = W[0]*DC0
    /// / PDIV = 1 * DC0 / 1 = DC0.
    #[test]
    fn dc_predictor_single_left_neighbour_copies_dc() {
        // 2-block frame, both Intra, both coded. bi=1's left neighbour
        // is bi=0 with DC=33.
        let bcoded = vec![1u8, 1u8];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32, 0u32];
        let mut neighbors = vec![DcPredictorNeighbors::default(); 2];
        neighbors[1].left = Some(0);
        let lastdc = DcLastDc::zero();
        let c = coeffs_with_dc(&[33, 0]);
        let dcpred =
            compute_dc_predictor(1, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 33);
    }

    /// Neighbour exists in the table but is not coded → P[k] stays
    /// zero → falls through to step 11 LASTDC.
    #[test]
    fn dc_predictor_uncoded_neighbour_treated_as_absent() {
        let bcoded = vec![0u8, 1u8]; // bi=0 uncoded; bi=1 coded.
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32, 0u32];
        let mut neighbors = vec![DcPredictorNeighbors::default(); 2];
        neighbors[1].left = Some(0);
        let mut lastdc = DcLastDc::zero();
        lastdc.intra = 7;
        let c = coeffs_with_dc(&[999, 0]);
        let dcpred =
            compute_dc_predictor(1, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 7, "uncoded neighbour must not contribute");
    }

    /// Neighbour is coded but uses a different reference frame →
    /// same-rfi check zeros it out → fallback to LASTDC[rfi].
    #[test]
    fn dc_predictor_different_reference_frame_ignored() {
        let bcoded = vec![1u8, 1u8];
        // Two macroblocks, one Intra (rfi=None), one Golden (rfi=Golden).
        let mbmodes = vec![MacroBlockMode::InterGoldenMv, MacroBlockMode::Intra];
        // bi=0 in mb 0 (Golden), bi=1 in mb 1 (Intra).
        let b2m = vec![0u32, 1u32];
        let mut neighbors = vec![DcPredictorNeighbors::default(); 2];
        neighbors[1].left = Some(0);
        let mut lastdc = DcLastDc::zero();
        lastdc.intra = -5;
        let c = coeffs_with_dc(&[100, 0]);
        // bi=1 is Intra (rfi=None); left neighbour bi=0 is Golden.
        // RFI mismatch → P[0] = 0 → step 11 returns LASTDC[None] = -5.
        let dcpred =
            compute_dc_predictor(1, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, -5);
    }

    /// Three-neighbour case with P=0b0111 (L + DL + D) and signed
    /// weights `[29, -26, 29]`, PDIV=32. Walks the full step 12
    /// weighted-sum path including signed division.
    #[test]
    fn dc_predictor_three_neighbours_signed_weights() {
        // 4-block frame, all Intra, all coded.
        let bcoded = vec![1u8; 4];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32; 4];
        // bi=3 has L=2, DL=0, D=1, DR=None.
        let mut neighbors = vec![DcPredictorNeighbors::default(); 4];
        neighbors[3].left = Some(2);
        neighbors[3].lower_left = Some(0);
        neighbors[3].lower = Some(1);
        let lastdc = DcLastDc::zero();
        let c = coeffs_with_dc(&[10, 20, 30, 0]);
        // P = 0b0111 → row [29, -26, 29, 0], PDIV=32.
        // DCPRED = (29*30 + -26*10 + 29*20 + 0) / 32
        //        = (870 - 260 + 580) / 32
        //        = 1190 / 32 = 37 (truncated toward zero).
        // Outranging guard fires (P[0]/P[1]/P[2] all set):
        //   |37 - 20| = 17 ≤ 128 — skip DC2 swap.
        //   |37 - 30| = 7 ≤ 128 — skip DC0 swap.
        //   |37 - 10| = 27 ≤ 128 — skip DC1 swap.
        // So DCPRED stays 37.
        let dcpred =
            compute_dc_predictor(3, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 37);
    }

    /// The step 12(h) outranging guard fires when the weighted estimate
    /// strays > 128 from one of the three full-neighbour DC values. The
    /// spec orders the checks as DC2 → DC0 → DC1 (first match wins).
    /// Here DCPRED is far from DC2 → swap to DC2 first.
    #[test]
    fn dc_predictor_outranging_prefers_dc2_first() {
        let bcoded = vec![1u8; 4];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32; 4];
        let mut neighbors = vec![DcPredictorNeighbors::default(); 4];
        // PBI[0] = bi=2 (left), PBI[1] = bi=0 (DL), PBI[2] = bi=1 (D).
        neighbors[3].left = Some(2);
        neighbors[3].lower_left = Some(0);
        neighbors[3].lower = Some(1);
        let lastdc = DcLastDc::zero();
        // coeffs[bi][0]: bi=0 → -500 (=DC1), bi=1 → 0 (=DC2),
        // bi=2 → 100 (=DC0).
        // DCPRED = 29*100 + -26*-500 + 29*0 = 2900 + 13000 = 15900.
        // 15900 / 32 = 496 (truncated). |496-0|=496 > 128 → swap to
        // DC2 = 0 first (spec checks DC2 before DC0 / DC1).
        let c = coeffs_with_dc(&[-500, 0, 100, 0]);
        let dcpred =
            compute_dc_predictor(3, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 0);
    }

    /// Outranging guard does NOT fire when the weighted estimate is
    /// within 128 of all three neighbour DCs — DCPRED is returned
    /// unchanged. This covers the no-swap path of step 12(h).
    #[test]
    fn dc_predictor_outranging_no_swap_in_range() {
        let bcoded = vec![1u8; 4];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32; 4];
        let mut neighbors = vec![DcPredictorNeighbors::default(); 4];
        // PBI[0]=2 (left), PBI[1]=0 (DL), PBI[2]=1 (D).
        neighbors[3].left = Some(2);
        neighbors[3].lower_left = Some(0);
        neighbors[3].lower = Some(1);
        let lastdc = DcLastDc::zero();
        // coeffs DC: bi=0 → 50, bi=1 → 50, bi=2 → 50.
        // DC0=coeffs[2][0]=50, DC1=coeffs[0][0]=50, DC2=coeffs[1][0]=50.
        // DCPRED = 29*50 + -26*50 + 29*50 = (29 - 26 + 29) * 50 = 1600.
        // 1600 / 32 = 50. |50 - 50| = 0 for every guard branch → stays.
        let c = coeffs_with_dc(&[50, 50, 50, 0]);
        let dcpred =
            compute_dc_predictor(3, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 50);
    }

    /// Outranging guard is gated on P[0] && P[1] && P[2]; with only
    /// P[0] + P[3] (mask 0b1001, weights [75, 0, 0, 53], PDIV=128)
    /// the guard MUST NOT fire even if DCPRED ends up far from DC0.
    #[test]
    fn dc_predictor_outranging_skipped_when_p2_missing() {
        // 4-block frame: bi=3 has L=0 and DR=2 only.
        let bcoded = vec![1u8; 4];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32; 4];
        let mut neighbors = vec![DcPredictorNeighbors::default(); 4];
        neighbors[3].left = Some(0);
        neighbors[3].lower_right = Some(2);
        let lastdc = DcLastDc::zero();
        // DC0=400, DC2=100. P[1]=P[2]=0, so guard skipped.
        // 75*400 + 53*100 = 30000 + 5300 = 35300. / 128 = 275.
        let c = coeffs_with_dc(&[400, 0, 100, 0]);
        let dcpred =
            compute_dc_predictor(3, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, 275, "guard MUST NOT fire when P[2]==0");
    }

    /// Negative DC values + spec's truncated-toward-zero `//` division.
    /// P=0b0001 with DC0 = -7 → DCPRED = 1*-7 / 1 = -7 (exact).
    /// With P=0b0010 weights `[0, 1, 0, 0]` PDIV=1 → DCPRED = DC1.
    #[test]
    fn dc_predictor_negative_dc_round_to_zero() {
        let bcoded = vec![1u8; 2];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32, 0u32];
        let mut neighbors = vec![DcPredictorNeighbors::default(); 2];
        neighbors[1].lower_left = Some(0);
        let lastdc = DcLastDc::zero();
        let c = coeffs_with_dc(&[-7, 0]);
        // bi=1 has only DL set → mask 0b0010 → weights [0,1,0,0] PDIV=1.
        let dcpred =
            compute_dc_predictor(1, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c).unwrap();
        assert_eq!(dcpred, -7);
    }

    /// `bi >= nbs` rejects fail-closed.
    #[test]
    fn dc_predictor_rejects_bi_out_of_range() {
        let bcoded = vec![1u8];
        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32];
        let neighbors = vec![DcPredictorNeighbors::default()];
        let lastdc = DcLastDc::zero();
        let c = coeffs_with_dc(&[0]);
        match compute_dc_predictor(1, &bcoded, &mbmodes, &b2m, &neighbors, &lastdc, &c) {
            Err(Error::DcPredictorBlockIndexOutOfRange { bi: 1, nbs: 1 }) => {}
            other => panic!("expected DcPredictorBlockIndexOutOfRange, got {other:?}"),
        }
    }

    /// All three paired-length mismatches surface a typed reject with
    /// the correct field discriminator.
    #[test]
    fn dc_predictor_rejects_paired_length_mismatches() {
        let bcoded = vec![1u8, 1u8];
        let mbmodes = vec![MacroBlockMode::Intra];
        let lastdc = DcLastDc::zero();
        let c = coeffs_with_dc(&[0, 0]);

        // block_to_macro_block too short.
        let b2m_short = vec![0u32];
        let n2 = vec![DcPredictorNeighbors::default(); 2];
        match compute_dc_predictor(0, &bcoded, &mbmodes, &b2m_short, &n2, &lastdc, &c) {
            Err(Error::DcPredictorBcodedLenMismatch {
                which: DcPredictorLenField::BlockToMacroBlock,
                got: 1,
                nbs: 2,
            }) => {}
            other => panic!("expected b2m mismatch, got {other:?}"),
        }

        // neighbors too long.
        let b2m_ok = vec![0u32, 0u32];
        let n_long = vec![DcPredictorNeighbors::default(); 3];
        match compute_dc_predictor(0, &bcoded, &mbmodes, &b2m_ok, &n_long, &lastdc, &c) {
            Err(Error::DcPredictorBcodedLenMismatch {
                which: DcPredictorLenField::Neighbors,
                got: 3,
                nbs: 2,
            }) => {}
            other => panic!("expected neighbors mismatch, got {other:?}"),
        }

        // coeffs too short.
        let c_short = coeffs_with_dc(&[0]);
        let n_ok = vec![DcPredictorNeighbors::default(); 2];
        match compute_dc_predictor(0, &bcoded, &mbmodes, &b2m_ok, &n_ok, &lastdc, &c_short) {
            Err(Error::DcPredictorBcodedLenMismatch {
                which: DcPredictorLenField::Coeffs,
                got: 1,
                nbs: 2,
            }) => {}
            other => panic!("expected coeffs mismatch, got {other:?}"),
        }
    }

    /// `block_to_macro_block[bi] >= nmbs` and a neighbour's
    /// `block_to_macro_block[bj] >= nmbs` both surface the
