        let mbmodes = vec![MacroBlockMode::Intra];
        let b2m = vec![0u32, 0u32];
        let neighbors = vec![DcPredictorNeighbors::default(); 2];
        let mut coeffs = coeffs_with_dc(&[0, 0]);
