    /// §7.9.4 Table 7.75 `(rfi, pli)` lookups via `pick`:
    /// `ReferencePlaneSet::pick(Previous, 0..=2)` and
    /// `pick(Golden, 0..=2)` each select the right plane.
    /// `pick(None, _)` is the intra-routing-mismatch reject.
    #[test]
    fn reference_plane_set_pick_table_7_75() {
        let planes = [
            ramp_plane(8, 8, 100),
            ramp_plane(8, 8, 101),
            ramp_plane(8, 8, 102),
            ramp_plane(8, 8, 103),
            ramp_plane(8, 8, 104),
            ramp_plane(8, 8, 105),
        ];
        let refs = make_refs(&planes, 8, 8);
        // The (Previous, Y) plane has bias 100, so samples[0] is
        // ((0+0+100) % 256) = 100.
        assert_eq!(
            refs.pick(ReferenceFrame::Previous, 0).unwrap().samples[0],
            100
        );
        assert_eq!(
            refs.pick(ReferenceFrame::Previous, 1).unwrap().samples[0],
            101
        );
        assert_eq!(
            refs.pick(ReferenceFrame::Previous, 2).unwrap().samples[0],
            102
        );
        assert_eq!(
            refs.pick(ReferenceFrame::Golden, 0).unwrap().samples[0],
            103
        );
        assert_eq!(
            refs.pick(ReferenceFrame::Golden, 1).unwrap().samples[0],
            104
        );
        assert_eq!(
            refs.pick(ReferenceFrame::Golden, 2).unwrap().samples[0],
            105
        );
        // pli out-of-range
        assert_eq!(
            refs.pick(ReferenceFrame::Previous, 3).unwrap_err(),
            Error::ReconstructPlaneIndexOutOfRange { pli: 3 },
        );
        // Intra at any pli is a router mismatch
        assert_eq!(
            refs.pick(ReferenceFrame::None, 0).unwrap_err(),
            Error::ReconstructIntraInterBranchMismatch,
        );
    }

    /// §7.9.4 step 2(d)vii.B literal — pin the DC-only formula.
    /// With COEFFS[0] = 32, the DC quantization matrix entry
    /// `qmat_dc[0]` for (qti=0, pli=0, qi=10) is reproducible from
    /// §6.4.3 against the same params; we compute it explicitly,
    /// pin DC = (COEFFS[0] * qmat_dc[0] + 15) >> 5, and assert the
    /// reconstructed cell equals 128 + DC.
    #[test]
    fn reconstruct_dc_only_formula_matches_2d_vii_b() {
        let params = make_recon_params();
        let planes = [
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
        ];
        let refs = make_refs(&planes, 16, 16);
        let mut coeffs = [0i16; 64];
        coeffs[0] = 32;
        let inputs = ReconstructBlockInputs {
            bcoded: true,
            mb_mode: MacroBlockMode::Intra,
            mvect: MotionVector::ZERO,
            coeffs_zz: coeffs,
            ncoeffs: 1,
            qii: 0,
            hsub: false,
            vsub: false,
        };
        let qi0 = 10usize;
        let qis = [qi0 as u8];
        let qmat_dc = compute_quantization_matrix(&params, 0, 0, qi0).unwrap();
        let expected_dc = ((32i32 * qmat_dc.values[0] as i32) + 15) >> 5;
        let expected_dc_i16 = expected_dc as i16;
        let expected_pixel = (128i32 + expected_dc_i16 as i32).clamp(0, 255) as u8;
        let out = reconstruct_block(&inputs, 0, 0, 0, &qis, &params, &refs).unwrap();
        assert_eq!(out.samples[0][0], expected_pixel);
        // All cells should match because PRED is constant and RES
        // is the constant DC.
        for row in out.samples.iter() {
            for &v in row.iter() {
                assert_eq!(v, expected_pixel);
            }
        }
    }

    /// §7.9.4 Display rendering of the four new error variants
    /// should each carry a stable, distinct §7.9.4 tag — useful
    /// when end-to-end traces surface a reconstruction reject.
    #[test]
    fn reconstruct_error_display_tags() {
        let e = Error::ReconstructPlaneIndexOutOfRange { pli: 7 };
        let s = e.to_string();
        assert!(s.contains("§7.9.4"), "missing §7.9.4 tag: {s}");
        assert!(s.contains("pli=7"));
        let e = Error::ReconstructEmptyQis;
        let s = e.to_string();
        assert!(s.contains("§7.9.4"));
        assert!(s.contains("QIS"));
        let e = Error::ReconstructQiiIndexOutOfRange { qii: 9, nqis: 3 };
        let s = e.to_string();
        assert!(s.contains("§7.9.4"));
        assert!(s.contains("qii=9"));
        assert!(s.contains("NQIS=3"));
        let e = Error::ReconstructIntraInterBranchMismatch;
        let s = e.to_string();
        assert!(s.contains("§7.9.4"));
        assert!(s.contains("Intra"));
    }

    /// §7.9.4 step 2(f) determinism — calling [`reconstruct_block`]
    /// twice with the same inputs yields byte-identical output.
    /// This catches accidental mutable state leaking through the
    /// quant-matrix / IDCT helpers.
    #[test]
    fn reconstruct_is_deterministic() {
        let params = make_recon_params();
        let planes = [
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 10),
            ramp_plane(16, 16, 20),
            ramp_plane(16, 16, 30),
            ramp_plane(16, 16, 40),
            ramp_plane(16, 16, 50),
        ];
        let refs = make_refs(&planes, 16, 16);
        let mut coeffs = [0i16; 64];
        coeffs[0] = 42;
        coeffs[1] = -17;
        coeffs[5] = 8;
        let inputs = ReconstructBlockInputs {
            bcoded: true,
            mb_mode: MacroBlockMode::InterMv,
            mvect: MotionVector::new(1, -1),
            coeffs_zz: coeffs,
            ncoeffs: 8,
            qii: 0,
            hsub: false,
            vsub: false,
        };
        let qis = [20u8, 30u8];
        let a = reconstruct_block(&inputs, 0, 4, 4, &qis, &params, &refs).unwrap();
        let b = reconstruct_block(&inputs, 0, 4, 4, &qis, &params, &refs).unwrap();
        assert_eq!(a, b);
    }

    // ---- §7.9.4 frame-level driver (round 233) ----

    /// Build a small four-block test geometry: an intra frame with a
    /// 16×16 Y plane (four 8×8 luma blocks at corners) plus 8×8 Cb /
    /// Cr planes (one chroma block each), 4:2:0 layout. Total NBS=6,
    /// NMBS=1, all blocks coded.
    #[allow(clippy::type_complexity)]
    fn four_block_geometry() -> (
        Vec<bool>,
        Vec<MacroBlockMode>,
        Vec<MotionVector>,
        Vec<[i16; 64]>,
        Vec<u32>,
        Vec<u8>,
        Vec<u8>,
        Vec<u32>,
        Vec<u32>,
        Vec<u32>,
    ) {
        let nbs = 6usize;
        let bcoded = vec![true; nbs];
        let mb_modes = vec![MacroBlockMode::Intra];
        let mvects = vec![MotionVector::ZERO; nbs];
        let coeffs = vec![[0i16; 64]; nbs];
        let ncoeffs = vec![0u32; nbs];
        let qiis = vec![0u8; nbs];
        // §2.3 coded-order indexing is continuous from Y → Cb → Cr.
        // 4 luma blocks (pli=0), then 1 Cb (pli=1), then 1 Cr (pli=2).
        let pli_of_block = vec![0u8, 0, 0, 0, 1, 2];
        // (BX, BY) in plane-local lower-left coordinates. Luma plane
        // is 16×16 → four 8×8 corners. Chroma plane is 8×8 → one
        // block at the origin.
        let bx_of_block = vec![0u32, 8, 0, 8, 0, 0];
        let by_of_block = vec![0u32, 0, 8, 8, 0, 0];
        // One macro block contains all four luma blocks + the chroma
        // co-located blocks.
        let mbi_of_block = vec![0u32; nbs];
        (
            bcoded,
            mb_modes,
            mvects,
            coeffs,
            ncoeffs,
            qiis,
            pli_of_block,
            bx_of_block,
            by_of_block,
            mbi_of_block,
        )
    }

    /// §7.9.4 frame driver — an all-intra all-zero-coefficient frame
    /// at a 16×16 luma + 8×8 chroma geometry should produce three
    /// planes of all-128 (the §7.9.1.1 intra predictor + step 2(f)).
    #[test]
    fn reconstruct_frame_all_intra_zero_coeffs_is_all_128() {
        let params = make_recon_params();
        let planes = [
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
            ramp_plane(16, 16, 0),
        ];
        let refs = make_refs(&planes, 16, 16);
        let (bcoded, mb_modes, mvects, coeffs, ncoeffs, qiis, pli, bx, by, mbi) =
            four_block_geometry();
        let qis = [10u8];
        let out = reconstruct_frame(
            &bcoded,
            &mb_modes,
            &mvects,
            &coeffs,
            &ncoeffs,
            &qiis,
            &pli,
            &bx,
            &by,
            &mbi,
            &qis,
            &params,
            &refs,
            PlaneDimensions {
                width: 16,
                height: 16,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PixelFormat::Yuv420,
        )
        .unwrap();
        assert_eq!(out.samples_y.len(), 256);
        assert_eq!(out.samples_cb.len(), 64);
        assert_eq!(out.samples_cr.len(), 64);
        for &v in out.samples_y.iter() {
            assert_eq!(v, 128);
        }
        for &v in out.samples_cb.iter() {
            assert_eq!(v, 128);
        }
        for &v in out.samples_cr.iter() {
            assert_eq!(v, 128);
        }
    }

    /// §7.9.4 frame driver — an uncoded block samples the Previous
    /// reference (step 2(e)i, rfi=1) at its co-located 8×8 footprint
    /// with the zero MV. With ramp reference planes the output for
    /// the uncoded block should match the ramp slice at `(BX, BY)`.
    #[test]
    fn reconstruct_frame_uncoded_block_copies_previous_reference() {
        let params = make_recon_params();
        // Four distinct ramps so the test can tell which plane was
        // sampled. PREV* / GOLD* both differ from each other.
        let planes = [
            ramp_plane(16, 16, 0),  // PREV Y
            ramp_plane(8, 8, 100),  // PREV Cb (constant offset)
            ramp_plane(8, 8, 110),  // PREV Cr
            ramp_plane(16, 16, 50), // GOLD Y
            ramp_plane(8, 8, 120),  // GOLD Cb
            ramp_plane(8, 8, 130),  // GOLD Cr
        ];
        let prev_y_ref = ReferencePlane::new(16, 16, &planes[0]).unwrap();
        let refs = ReferencePlaneSet {
            previous_y: prev_y_ref,
            previous_cb: ReferencePlane::new(8, 8, &planes[1]).unwrap(),
            previous_cr: ReferencePlane::new(8, 8, &planes[2]).unwrap(),
            golden_y: ReferencePlane::new(16, 16, &planes[3]).unwrap(),
            golden_cb: ReferencePlane::new(8, 8, &planes[4]).unwrap(),
            golden_cr: ReferencePlane::new(8, 8, &planes[5]).unwrap(),
        };
        let (mut bcoded, mb_modes, mvects, coeffs, ncoeffs, qiis, pli, bx, by, mbi) =
            four_block_geometry();
        // Mark the first luma block (BX=0, BY=0) uncoded; the rest
        // remain coded (intra all-zero → predict to 128).
        bcoded[0] = false;
        let qis = [10u8];
        let out = reconstruct_frame(
            &bcoded,
            &mb_modes,
            &mvects,
            &coeffs,
            &ncoeffs,
            &qiis,
            &pli,
            &bx,
            &by,
            &mbi,
            &qis,
            &params,
            &refs,
            PlaneDimensions {
                width: 16,
                height: 16,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PixelFormat::Yuv420,
        )
        .unwrap();
        // The uncoded luma block at (BX=0, BY=0) should equal the
        // PREVREFY ramp slice at the same coordinates.
        for ry in 0..8u32 {
            for rx in 0..8u32 {
                let expected = ((rx + ry) % 256) as u8;
                let idx = (ry * 16 + rx) as usize;
                assert_eq!(
                    out.samples_y[idx], expected,
                    "uncoded luma block at (BX=0, BY=0) should sample PREVREFY"
                );
            }
        }
        // The other three luma blocks are coded intra with zero
        // residual — all 128.
        let coded_origins = [(8u32, 0u32), (0, 8), (8, 8)];
        for (bx0, by0) in coded_origins {
            for ry in 0..8u32 {
                for rx in 0..8u32 {
                    let idx = ((by0 + ry) * 16 + (bx0 + rx)) as usize;
                    assert_eq!(out.samples_y[idx], 128);
                }
            }
        }
    }

    /// §7.9.4 frame driver — a fully-coded frame whose single
    /// macroblock is `INTER_GOLDEN_NOMV` (Table 7.46 `rfi = 2`) must
    /// sample the **golden** reference, not the previous one. This
    /// exercises the golden-reference branch through the complete
    /// `reconstruct_frame` driver (the block-level golden test
    /// `reconstruct_inter_golden_samples_golden_reference` covers only
    /// a single `reconstruct_block` call). Previous and golden planes
    /// carry distinct biases so a wrong reference pick is detectable on
    /// every plane.
    #[test]
    fn reconstruct_frame_golden_mode_samples_golden_reference() {
        let params = make_recon_params();
        // PREV* biases differ from GOLD* biases on every plane.
        let prev_y_bias = 0u32;
        let prev_cb_bias = 100u32;
        let prev_cr_bias = 110u32;
        let gold_y_bias = 50u32;
        let gold_cb_bias = 120u32;
        let gold_cr_bias = 130u32;
        let prev_y = ramp_plane(16, 16, prev_y_bias);
        let prev_cb = ramp_plane(8, 8, prev_cb_bias);
        let prev_cr = ramp_plane(8, 8, prev_cr_bias);
        let gold_y = ramp_plane(16, 16, gold_y_bias);
        let gold_cb = ramp_plane(8, 8, gold_cb_bias);
        let gold_cr = ramp_plane(8, 8, gold_cr_bias);
        let refs = ReferencePlaneSet {
            previous_y: ReferencePlane::new(16, 16, &prev_y).unwrap(),
            previous_cb: ReferencePlane::new(8, 8, &prev_cb).unwrap(),
            previous_cr: ReferencePlane::new(8, 8, &prev_cr).unwrap(),
            golden_y: ReferencePlane::new(16, 16, &gold_y).unwrap(),
            golden_cb: ReferencePlane::new(8, 8, &gold_cb).unwrap(),
            golden_cr: ReferencePlane::new(8, 8, &gold_cr).unwrap(),
        };
        let (bcoded, mut mb_modes, mvects, coeffs, ncoeffs, qiis, pli, bx, by, mbi) =
            four_block_geometry();
        // The single macroblock is golden-no-MV. Zero MV + zero
        // residual means each block is a verbatim copy of the golden
        // plane at its own (BX, BY).
        mb_modes[0] = MacroBlockMode::InterGoldenNoMv;
        let qis = [10u8];
        let out = reconstruct_frame(
            &bcoded,
            &mb_modes,
            &mvects,
            &coeffs,
            &ncoeffs,
            &qiis,
            &pli,
            &bx,
            &by,
            &mbi,
            &qis,
            &params,
            &refs,
            PlaneDimensions {
                width: 16,
                height: 16,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PixelFormat::Yuv420,
        )
        .unwrap();
        // Every luma sample equals the GOLDEN-Y ramp (bias 50), not the
        // PREVIOUS-Y ramp (bias 0).
        for ry in 0..16u32 {
            for rx in 0..16u32 {
                let idx = (ry * 16 + rx) as usize;
                let expected = ((rx + ry + gold_y_bias) % 256) as u8;
                assert_eq!(
                    out.samples_y[idx], expected,
                    "luma ({rx},{ry}) must sample GOLDEN-Y"
                );
            }
        }
        // Chroma planes equally sample the golden Cb / Cr ramps.
        for ry in 0..8u32 {
            for rx in 0..8u32 {
                let idx = (ry * 8 + rx) as usize;
                assert_eq!(
                    out.samples_cb[idx],
                    ((rx + ry + gold_cb_bias) % 256) as u8,
                    "Cb ({rx},{ry}) must sample GOLDEN-Cb"
                );
                assert_eq!(
                    out.samples_cr[idx],
                    ((rx + ry + gold_cr_bias) % 256) as u8,
                    "Cr ({rx},{ry}) must sample GOLDEN-Cr"
                );
            }
        }
    }

    /// §7.9.4 frame driver — an `INTER_MV_FOUR` macroblock carries an
    /// independent motion vector for each of its four luma blocks
    /// (resolved upstream into the per-block `MVECTS` array) and a
    /// single averaged MV for the chroma blocks. The driver must apply
    /// each block's own MV against the **previous** reference (Table
    /// 7.46 `rfi = 1`). With even (whole-pixel) MV components and zero
    /// residual, block `(BX, BY)` with MV `(mx, my)` is a verbatim copy
    /// of the previous plane at `(BX + mx/2, BY + my/2)`.
    #[test]
    fn reconstruct_frame_four_mv_applies_per_block_luma_mvs() {
        let params = make_recon_params();
        // Distinct previous-plane biases; golden planes carry other
        // biases so a wrong-reference pick (golden instead of previous)
        // would be caught.
        let prev_y = ramp_plane(16, 16, 0);
        let prev_cb = ramp_plane(8, 8, 100);
        let prev_cr = ramp_plane(8, 8, 110);
        let gold_y = ramp_plane(16, 16, 50);
        let gold_cb = ramp_plane(8, 8, 120);
        let gold_cr = ramp_plane(8, 8, 130);
        let refs = ReferencePlaneSet {
            previous_y: ReferencePlane::new(16, 16, &prev_y).unwrap(),
            previous_cb: ReferencePlane::new(8, 8, &prev_cb).unwrap(),
            previous_cr: ReferencePlane::new(8, 8, &prev_cr).unwrap(),
            golden_y: ReferencePlane::new(16, 16, &gold_y).unwrap(),
            golden_cb: ReferencePlane::new(8, 8, &gold_cb).unwrap(),
            golden_cr: ReferencePlane::new(8, 8, &gold_cr).unwrap(),
        };
        let (bcoded, mut mb_modes, mut mvects, coeffs, ncoeffs, qiis, pli, bx, by, mbi) =
            four_block_geometry();
        mb_modes[0] = MacroBlockMode::InterMvFour;
        // Per-block luma MVs (doubled / half-pixel units). All even so
        // each halves to a clean whole-pixel offset, keeping these
        // predictions a pure copy. Block order matches four_block_geometry:
        //   block 0 = (BX=0,  BY=0)
        //   block 1 = (BX=8,  BY=0)
        //   block 2 = (BX=0,  BY=8)
        //   block 3 = (BX=8,  BY=8)
        // Offsets are chosen so every clamped read stays inside the
        // 16×16 plane (no edge clamping), making each block a clean,
        // un-clamped copy whose expected value is the ramp at the
        // shifted coordinate. Blocks on the right/bottom edge (BX=8 /
        // BY=8) take a zero offset on the edge-facing axis so the
        // 8-pixel footprint cannot run past pixel 15.
        //
        // Chroma blocks 4 (Cb) / 5 (Cr) consume MVECTS[4]/[5] as their
        // stored value: the frame driver does not recompute the §7.5.2
        // four-MV chroma average — that resolution happened upstream in
        // decode_macroblock_motion_vectors. We set the chroma entries
        // explicitly and assert the driver applies the §7.5.1
        // quarter-pixel interpretation when converting them to
        // whole-pixel reference offsets (divide-by-4 in 4:2:0).
        let mv0 = MotionVector::new(0, 2);
        let mv1 = MotionVector::new(0, 0);
        let mv2 = MotionVector::new(2, 0);
        let mv3 = MotionVector::new(0, 0);
        let chroma_mv = MotionVector::new(2, 2);
        mvects[0] = mv0;
        mvects[1] = mv1;
        mvects[2] = mv2;
        mvects[3] = mv3;
        mvects[4] = chroma_mv;
        mvects[5] = chroma_mv;
        let qis = [10u8];
        let out = reconstruct_frame(
            &bcoded,
            &mb_modes,
            &mvects,
            &coeffs,
            &ncoeffs,
            &qiis,
            &pli,
            &bx,
            &by,
            &mbi,
            &qis,
            &params,
            &refs,
            PlaneDimensions {
                width: 16,
                height: 16,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PlaneDimensions {
                width: 8,
                height: 8,
            },
            PixelFormat::Yuv420,
        )
        .unwrap();
        // Each luma block is the previous-Y ramp shifted by its own
        // whole-pixel MV offset (mx/2, my/2). prev_y[v][u] = u + v.
        let luma_blocks = [(0u32, 0u32, mv0), (8, 0, mv1), (0, 8, mv2), (8, 8, mv3)];
        for (bx0, by0, mv) in luma_blocks {
            let ox = (mv.x / 2) as i32;
            let oy = (mv.y / 2) as i32;
            for ly in 0..8u32 {
                for lx in 0..8u32 {
                    let idx = ((by0 + ly) * 16 + (bx0 + lx)) as usize;
                    // prev_y read coordinate (all in-bounds → no clamp);
                    // prev_y[v][u] = u + v (bias 0), and u+v ≤ 30 < 256.
                    let u = (bx0 as i32) + ox + lx as i32;
                    let v = (by0 as i32) + oy + ly as i32;
                    let expected = (u + v) as u8;
                    assert_eq!(
                        out.samples_y[idx], expected,
                        "luma block ({bx0},{by0}) MV ({},{}) at ({lx},{ly})",
                        mv.x, mv.y
                    );
                }
            }
        }
        // Chroma blocks use the averaged MV (2,2). In 4:2:0 *both*
        // chroma axes are sub-sampled, so each component is interpreted
        // at quarter-pixel resolution (§7.5.1) and §7.9.4 step 2(d)vi
        // divides it by 4 (not 2) to reach whole-pixel reference
        // offsets: MVX = ⌊2/4⌋ = 0 (toward zero), MVX2 = ⌈2/4⌉ = 1
        // (away from zero), likewise for y. The two offsets differ, so
        // the §7.9.1.3 half-pixel predictor runs, averaging the
        // co-located sample (offset 0,0) with the +1,+1-shifted sample
        // (clamped at the plane edge) via (s1 + s2) >> 1. The previous
        // Cb ramp is bias 100, Cr bias 110, value = (u + v + bias).
        let half_pixel_chroma = |bias: u32| -> [[u8; 8]; 8] {
            let mut exp = [[0u8; 8]; 8];
            for (cy, row) in exp.iter_mut().enumerate() {
                for (cx, cell) in row.iter_mut().enumerate() {
                    // mv1 = (0,0): co-located. mv2 = (1,1): shifted,
                    // clamped to the 8×8 plane's last index 7.
                    let u1 = cx;
                    let v1 = cy;
                    let u2 = (cx + 1).min(7);
                    let v2 = (cy + 1).min(7);
                    let s1 = (u1 + v1) as u32 + bias;
                    let s2 = (u2 + v2) as u32 + bias;
                    *cell = (((s1 + s2) >> 1) % 256) as u8;
                }
            }
            exp
        };
        let exp_cb = half_pixel_chroma(100);
        let exp_cr = half_pixel_chroma(110);
        for cy in 0..8u32 {
            for cx in 0..8u32 {
                let idx = (cy * 8 + cx) as usize;
                assert_eq!(
                    out.samples_cb[idx], exp_cb[cy as usize][cx as usize],
                    "Cb ({cx},{cy}) must sample previous Cb at the quarter-pel averaged MV"
                );
                assert_eq!(
                    out.samples_cr[idx], exp_cr[cy as usize][cx as usize],
                    "Cr ({cx},{cy}) must sample previous Cr at the quarter-pel averaged MV"
                );
            }
        }
    }

