    /// Display formatting for each new error variant renders a
    /// stable, distinct §7.10.3 tag.
    #[test]
    fn loop_filter_frame_error_display_includes_section() {
        let e = Error::LoopFilterFrameQisEmpty;
        let s = format!("{e}");
        assert!(s.contains("§7.10.3"));
        assert!(s.contains("QIS"));

        let e = Error::LoopFilterFrameQiOutOfRange { qi0: 64 };
        let s = format!("{e}");
        assert!(s.contains("§7.10.3"));
        assert!(s.contains("64"));

        let e = Error::LoopFilterFrameBlockLenMismatch {
            which: LoopFilterFrameBlockSlice::Bcoded,
            got: 5,
            nbs: 4,
        };
        let s = format!("{e}");
        assert!(s.contains("§7.10.3"));
        assert!(s.contains("BCODED"));

        let e = Error::LoopFilterFramePliOutOfRange { bi: 7, pli: 9 };
        let s = format!("{e}");
        assert!(s.contains("§7.10.3"));
        assert!(s.contains("7"));
        assert!(s.contains("9"));

        let e = Error::LoopFilterFrameBlockOutOfPlane {
            bi: 1,
            pli: 0,
            bx: 8,
            by: 0,
            plane_w: 8,
            plane_h: 8,
        };
        let s = format!("{e}");
        assert!(s.contains("§7.10.3"));
        assert!(s.contains("escapes plane"));

        let e = Error::LoopFilterFrameRasterEntryOutOfRange {
            pli: 1,
            raster_idx: 3,
            bi: 99,
            nbs: 10,
        };
        let s = format!("{e}");
        assert!(s.contains("§7.10.3"));
        assert!(s.contains("99"));

        let e = Error::LoopFilterFrameRasterLenMismatch {
            pli: 2,
            got: 8,
            expected: 4,
        };
        let s = format!("{e}");
        assert!(s.contains("§7.10.3"));
        assert!(s.contains("pli=2"));
    }

    /// `LoopFilterFrameBlockSlice` Display matches its on-wire enum
    /// names, which is what error messages quote.
    #[test]
    fn loop_filter_frame_block_slice_display_names() {
        assert_eq!(format!("{}", LoopFilterFrameBlockSlice::Bcoded), "BCODED");
        assert_eq!(
            format!("{}", LoopFilterFrameBlockSlice::PliOfBlock),
            "pli_of_block"
        );
        assert_eq!(
            format!("{}", LoopFilterFrameBlockSlice::BxOfBlock),
            "bx_of_block"
        );
        assert_eq!(
            format!("{}", LoopFilterFrameBlockSlice::ByOfBlock),
            "by_of_block"
        );
    }

    // ----------------------------------------------------------------
    // §7.11 reference-plane geometry + packet classifier (round 250).
    // ----------------------------------------------------------------

    /// Build a minimal [`TheoraIdentHeader`] for the §7.11 helpers.
    /// The §7.11 step 3 / 4 derivations consult only `fmbw`, `fmbh`,
    /// and `pf`; the other fields carry deterministic defaults so the
    /// helper-under-test is isolated from unrelated header fields.
    fn ident_geometry(fmbw: u16, fmbh: u16, pf: PixelFormat) -> TheoraIdentHeader {
        TheoraIdentHeader {
            vmaj: 3,
            vmin: 2,
            vrev: 1,
            fmbw,
            fmbh,
            picw: (fmbw as u32) * 16,
            pich: (fmbh as u32) * 16,
            picx: 0,
            picy: 0,
            frn: 25,
            frd: 1,
            parn: 1,
            pard: 1,
            cs: ColorSpace::Undefined,
            nombr: 0,
            qual: 0,
            kfgshift: 0,
            pf,
        }
    }

    /// §7.11 step 3: `RPYW = 16 * FMBW`, `RPYH = 16 * FMBH` regardless
    /// of `PF`. Tested across all three legal `PF` values.
    #[test]
    fn reference_plane_dims_luma_is_macroblock_extent() {
        for pf in [
            PixelFormat::Yuv420,
            PixelFormat::Yuv422,
            PixelFormat::Yuv444,
        ] {
            let h = ident_geometry(2, 2, pf);
            let d = reference_plane_dimensions_from_ident(&h);
            assert_eq!(d.rpyw, 32, "{pf:?}: rpyw");
            assert_eq!(d.rpyh, 32, "{pf:?}: rpyh");
        }
    }

    /// §7.11 step 4 / Table 7.89: `PF = 0` (4:2:0) → chroma halved on
    /// both axes.
    #[test]
    fn reference_plane_dims_chroma_pf_420() {
        let h = ident_geometry(4, 6, PixelFormat::Yuv420);
        let d = reference_plane_dimensions_from_ident(&h);
        assert_eq!(d.rpyw, 64);
        assert_eq!(d.rpyh, 96);
        assert_eq!(d.rpcw, 32);
        assert_eq!(d.rpch, 48);
    }

    /// §7.11 step 4 / Table 7.89: `PF = 2` (4:2:2) → chroma halved
    /// horizontally, full vertical extent.
    #[test]
    fn reference_plane_dims_chroma_pf_422() {
        let h = ident_geometry(4, 6, PixelFormat::Yuv422);
        let d = reference_plane_dimensions_from_ident(&h);
        assert_eq!(d.rpyw, 64);
        assert_eq!(d.rpyh, 96);
        assert_eq!(d.rpcw, 32);
        assert_eq!(d.rpch, 96);
    }

    /// §7.11 step 4 / Table 7.89: `PF = 3` (4:4:4) → chroma matches
    /// luma.
    #[test]
    fn reference_plane_dims_chroma_pf_444() {
        let h = ident_geometry(4, 6, PixelFormat::Yuv444);
        let d = reference_plane_dimensions_from_ident(&h);
        assert_eq!(d.rpyw, 64);
        assert_eq!(d.rpyh, 96);
        assert_eq!(d.rpcw, 64);
        assert_eq!(d.rpch, 96);
    }

    /// Verify the largest legal `FMBW` / `FMBH` (`u16::MAX`) does not
    /// overflow `u32` when multiplied by 16. The result is
    /// `16 * 0xFFFF = 0x000F_FFF0`.
    #[test]
    fn reference_plane_dims_max_fmbw_fmbh_no_overflow() {
        let h = ident_geometry(u16::MAX, u16::MAX, PixelFormat::Yuv444);
        let d = reference_plane_dimensions_from_ident(&h);
        assert_eq!(d.rpyw, 16 * (u16::MAX as u32));
        assert_eq!(d.rpyh, 16 * (u16::MAX as u32));
        assert_eq!(d.rpcw, 16 * (u16::MAX as u32));
        assert_eq!(d.rpch, 16 * (u16::MAX as u32));
    }

    /// The reference-plane dimensions are intentionally distinct from
    /// the picture region (`picw` / `pich`). A header whose visible
    /// region is smaller than the macroblock extent still yields
    /// macroblock-aligned reference planes.
    #[test]
    fn reference_plane_dims_independent_of_picture_region() {
        // Coded 32×32, visible 26×18 — the picture-region-non-mb-aligned
        // fixture shape.
        let mut h = ident_geometry(2, 2, PixelFormat::Yuv420);
        h.picw = 26;
        h.pich = 18;
        h.picx = 0;
        h.picy = 14;
        let d = reference_plane_dimensions_from_ident(&h);
        // RPYW/RPYH stay 32×32 — the macroblock extent.
        assert_eq!(d.rpyw, 32);
        assert_eq!(d.rpyh, 32);
        assert_eq!(d.rpcw, 16);
        assert_eq!(d.rpch, 16);
    }

    /// §7.11 step 1 / step 2 branch: a zero-byte packet classifies as
    /// [`FrameDecodePacket::Empty`].
    #[test]
    fn classify_frame_decode_packet_zero_bytes_is_empty() {
        let p = classify_frame_decode_packet(&[]);
        assert_eq!(p, FrameDecodePacket::Empty);
        assert!(p.is_empty());
        assert_eq!(p.data(), None);
    }

    /// §7.11 step 1 / step 2 branch: a non-empty packet classifies as
    /// [`FrameDecodePacket::Data`] carrying the packet bytes.
    #[test]
    fn classify_frame_decode_packet_nonempty_is_data() {
        let bytes: &[u8] = &[0x00, 0x01, 0x02];
        let p = classify_frame_decode_packet(bytes);
        assert!(!p.is_empty());
        assert_eq!(p.data(), Some(bytes));
        match p {
            FrameDecodePacket::Data(b) => assert_eq!(b, bytes),
            _ => panic!("expected Data, got {p:?}"),
        }
    }

    /// §7.11 step 1 / step 2 branch: a single-byte packet still
    /// classifies as `Data`. Only `len == 0` triggers the step 2 path
    /// per the spec wording "If the size of the data packet is
    /// non-zero".
    #[test]
    fn classify_frame_decode_packet_one_byte_is_data() {
        let p = classify_frame_decode_packet(&[0x55]);
        assert!(!p.is_empty());
        assert_eq!(p.data(), Some(&[0x55][..]));
    }

    // -----------------------------------------------------------------
    // §7.11 step 2 — empty-packet (zero-byte) state synthesis
    // -----------------------------------------------------------------

    /// §7.11 step 2(a)+(b)+(c): a synthesised state carries
    /// `FTYPE=Inter`, `NQIS=1`, `QIS=[63]` regardless of `nbs`.
    #[test]
    fn synth_empty_state_has_step2_hardcoded_values() {
        for nbs in [1usize, 24, 48960] {
            let state = synthesize_empty_packet_frame_state(nbs).unwrap();
            assert_eq!(state.ftype, FrameType::Inter, "nbs={nbs}: ftype");
            assert_eq!(state.nqis, 1, "nbs={nbs}: nqis");
            assert_eq!(state.qis, vec![63u8], "nbs={nbs}: qis");
            assert_eq!(state.qi0(), 63, "nbs={nbs}: qi0()");
        }
    }

    /// §7.11 step 2(d): `BCODED` is all-zero and exactly `nbs` long.
    #[test]
    fn synth_empty_state_bcoded_is_all_zero_sized_nbs() {
        for nbs in [1usize, 7, 24, 48960] {
            let state = synthesize_empty_packet_frame_state(nbs).unwrap();
            assert_eq!(state.bcoded.len(), nbs, "nbs={nbs}: len");
            assert_eq!(state.nbs(), nbs, "nbs={nbs}: nbs()");
            assert!(
                state.bcoded.iter().all(|&b| b == 0),
                "nbs={nbs}: not all zero"
            );
        }
    }

    /// `synthesize_empty_packet_frame_state(0)` is a structural
    /// reject — §6.2 step 23 derives `NBS >= 1` for any well-formed
    /// Theora stream.
    #[test]
    fn synth_empty_state_rejects_zero_nbs() {
        let err = synthesize_empty_packet_frame_state(0).unwrap_err();
        assert!(matches!(err, Error::EmptyPacketFrameStateZeroNbs));
    }

    /// The `From<&EmptyPacketFrameState>` conversion projects the
    /// `FTYPE` + `QIS` slice into a [`TheoraFrameHeader`] view,
    /// dropping the `BCODED` array. The frame-header view is
    /// indistinguishable from one parsed from a §7.1 inter-frame
    /// packet whose `NQIS=1`, `QIS[0]=63`.
    #[test]
    fn synth_empty_state_projects_to_frame_header() {
        let state = synthesize_empty_packet_frame_state(24).unwrap();
        let header: TheoraFrameHeader = (&state).into();
        assert_eq!(header.ftype, FrameType::Inter);
        assert_eq!(header.qis, vec![63u8]);
        assert_eq!(header.nqis(), 1);
    }

    /// The classifier-then-synthesiser chain models the §7.11 entry
    /// step end-to-end for the step 2 branch: an empty packet
    /// classifies as `Empty`, which the driver feeds to the
    /// synthesiser along with the identification-header's `NBS`.
    #[test]
    fn synth_empty_state_threads_off_classifier_empty_branch() {
        let packet: &[u8] = &[];
        let cls = classify_frame_decode_packet(packet);
        assert_eq!(cls, FrameDecodePacket::Empty);
        // The §6.2-derived NBS for the tiny-i-only-16x16 fixture is
        // 24 (coded 32×32 → 2×2 macroblocks → 4 super-blocks's worth
        // of luma + 4:2:0 chroma).
        let nbs_tiny = 24usize;
        let state = synthesize_empty_packet_frame_state(nbs_tiny).unwrap();
        assert_eq!(state.bcoded.len(), nbs_tiny);
        assert!(state.bcoded.iter().all(|&b| b == 0));
    }

    /// `qi0()` reflects post-construction mutation of the `qis`
    /// vector, confirming it reads from the field rather than
    /// hardcoding `63`. This guards against a future refactor that
    /// might inline the constant.
    #[test]
    fn synth_empty_state_qi0_tracks_qis_mutation() {
        let mut state = synthesize_empty_packet_frame_state(7).unwrap();
        assert_eq!(state.qi0(), 63);
        state.qis[0] = 12;
        assert_eq!(state.qi0(), 12);
    }

    // -----------------------------------------------------------------
    // §7.11 step 1(a) + step 1(b) — header + coded-block-flags chain
    // -----------------------------------------------------------------

    /// §7.11 step 1 intra path through all seven sub-steps: a one-shot
    /// decode of an intra frame header followed by §7.3's all-coded
    /// short-circuit (1(b)), §7.4's all-`INTRA` short-circuit (1(c)),
    /// the 1(d) gate ("If FTYPE is non-zero") skipping §7.5.2 (no
    /// `MVMODE` bit consumed, every `MVECTS` entry `(0, 0)`), §7.6's
    /// `NQIS=1` zero-bit short-circuit (1(e)), the §7.7.3 coefficient
    /// decode off the shared reader (1(f)), and the §7.8.2
    /// DC-prediction inversion (1(g)). The single-leaf token-9 table
    /// set fills every coefficient of every coded block with `+1`
    /// while consuming only the four `htiL` / `htiC` nibbles, so the
    /// 1(g) inversion is observable: with all-default (`None`)
    /// neighbours every block's predictor is `LASTDC[0]` (§7.8.1 step
    /// 11), which chains 1 → 2 → 3 → … down each plane's raster walk
    /// and resets at each plane boundary (§7.8.2 steps 1(a)–(c)).
    #[test]
    fn data_header_and_blocks_intra_all_coded() {
        // 3 super blocks, 8 blocks each → NBS=24 (the tiny-i fixture
        // shape used elsewhere in the §7.3 tests): 16 luma blocks
        // (4 MBs × 4), 4 Cb, 4 Cr per the 4:2:0 uniform layout.
        let nsbs = 3u32;
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        // Token 9 is the fixed `+1` single-coefficient token
        // (Table 7.38, zero extra bits); a single-leaf table consumes
        // no Huffman bits, so §7.7.3 reads exactly the 16 htiL/htiC
        // bits at ti ∈ {0, 1} and fills all 64 slots of all 24 blocks.
        let hts = make_uniform_hts(9);
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(0, 1); // FTYPE = intra
        w.put(12, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
        w.put(0, 3); // §7.1 step 7 reserved trailer
                     // 1(b) / 1(c) / 1(d) / 1(e) all read zero bits on this frame
                     // (intra short-circuits; NQIS=1). §7.7.3 resumes on the SAME
                     // bitstream, mid-byte: htiL + htiC at ti=0 and ti=1.
        w.put(0, 4); // htiL at ti=0
        w.put(0, 4); // htiC at ti=0
        w.put(0, 4); // htiL at ti=1
        w.put(0, 4); // htiC at ti=1
        let packet = w.finish();
        let out = decode_data_packet_header_and_blocks(
            &packet,
            true,
            PixelFormat::Yuv420,
            nsbs,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap();
        assert_eq!(out.ftype(), FrameType::Intra);
        assert_eq!(out.header.qis, vec![12]);
        assert_eq!(out.nqis(), 1);
        // §7.3 step 1: every block coded on an intra frame.
        assert_eq!(out.bcoded, vec![1u8; 24]);
        assert_eq!(out.nbs(), 24);
        // §7.4 step 1: every macro block INTRA on an intra frame, no
        // bits read.
        assert_eq!(out.mbmodes, vec![MacroBlockMode::Intra; 4]);
        assert_eq!(out.nmbs(), 4);
        // §7.11 step 1(d) gate: intra frame → no §7.5.2 bits, all-zero
        // MVECTS sized NBS.
        assert_eq!(out.mvects, vec![MotionVector::ZERO; 24]);
        // Step 1(e): NQIS=1 → §7.6's main loop is empty; QIIS all 0.
        assert_eq!(out.qiis, vec![0u8; 24]);
        // Step 1(f): every block fully populated by token 9.
        assert_eq!(out.ncoeffs, vec![64u8; 24]);
        // Step 1(g): the §7.7.3 residual DC of every block is +1; with
        // all-`None` neighbours the predictor for the k-th block of a
        // plane's raster walk is the (k-1)-th block's reconstructed DC
        // (carried through LASTDC[0]), so DCs run 1..=16 across the Y
        // plane and 1..=4 across each chroma plane. AC coefficients
        // are untouched by §7.8.2 and stay +1.
        for bi in 0..24usize {
            let plane_pos = if bi < 16 { bi } else { (bi - 16) % 4 };
            assert_eq!(
                out.coeffs[bi][0],
                (plane_pos + 1) as i16,
                "DC of block {bi}"
            );
            assert_eq!(out.coeffs[bi][1..], [1i16; 63], "AC of block {bi}");
        }
    }

    /// §7.11 step 1(a)+(b)+(c)+(d) inter path: the shared-reader
    /// contract — §7.3's run-length streams must resume at the bit
    /// position immediately after the §7.1 header, §7.4's mode stream
    /// after §7.3's, and §7.5.2's `MVMODE` + MV stream after §7.4's,
    /// with no re-alignment anywhere. The test writes all four
    /// sections into one `BitWriter` (a single bitstream, byte-aligned
    /// only at the very end), then confirms the composed driver
    /// recovers the header, an all-coded `BCODED`, the modes, and the
    /// motion vectors — including `INTER_MV_FOUR`'s four per-luma MVs
    /// plus the 4:2:0 chroma average.
    #[test]
    fn data_header_and_blocks_inter_shared_reader_all_coded() {
        // 4 MBs × 4 luma + 4 Cb + 4 Cr = NBS 24 over 3 super blocks.
        let nsbs = 3u32;
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let mut w = BitWriter::new();
        // §7.1 inter header (FTYPE=1, NQIS=1, QIS=[7]); no reserved
        // trailer on an inter frame.
        w.put(0, 1); // data-packet flag
        w.put(1, 1); // FTYPE = inter
        w.put(7, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
                     // §7.3 resumes on the SAME bitstream, mid-byte: every super
                     // block fully coded (SBPCODED=0, SBFCODED=1), no per-block
                     // stream.
        encode_long_run_runs(&mut w, &[0, 0, 0]);
        encode_long_run_runs(&mut w, &[1, 1, 1]);
        // §7.4 resumes on the SAME bitstream: MSCHEME=7 (direct 3-bit
        // modes). Every MB has coded luma blocks, so one mode is read
        // per MB.
        let modes = [
            MacroBlockMode::InterMv,
            MacroBlockMode::InterNoMv,
            MacroBlockMode::InterMvFour,
            MacroBlockMode::InterGoldenNoMv,
        ];
        w.put(7, 3); // MSCHEME = 7
        for m in &modes {
            w.put(m.to_index() as u32, 3);
        }
        // §7.5.2 resumes on the SAME bitstream: MVMODE=1 (5+1-bit
        // fixed-length components). MB 0 (INTER_MV) reads one MV;
        // MB 1 (INTER_NOMV) reads none; MB 2 (INTER_MV_FOUR) reads
        // four (all four luma blocks coded); MB 3 (INTER_GOLDEN_NOMV)
        // reads none.
        w.put(1, 1); // MVMODE = 1
        write_mv_fixed_component(&mut w, 2); // MB 0 MVX
        write_mv_fixed_component(&mut w, -3); // MB 0 MVY
        let four = [
            MotionVector { x: 1, y: 1 },
            MotionVector { x: 3, y: 1 },
            MotionVector { x: 5, y: 3 },
            MotionVector { x: 7, y: 3 },
        ];
        for mv in &four {
            write_mv_fixed_component(&mut w, mv.x);
            write_mv_fixed_component(&mut w, mv.y);
        }
        // §7.6 reads zero bits (NQIS=1). §7.7.3 resumes on the SAME
        // bitstream: htiL/htiC at ti=0 and ti=1; the single-leaf
        // token-0 tables close every coded block at ti=0 with no
        // further bits (EOB run of one block each).
        w.put(0, 4); // htiL at ti=0
        w.put(0, 4); // htiC at ti=0
        w.put(0, 4); // htiL at ti=1
        w.put(0, 4); // htiC at ti=1
        let packet = w.finish();
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let out = decode_data_packet_header_and_blocks(
            &packet,
            false,
            PixelFormat::Yuv420,
            nsbs,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap();
        assert_eq!(out.ftype(), FrameType::Inter);
        assert_eq!(out.header.qis, vec![7]);
        assert_eq!(out.bcoded, vec![1u8; 24]);
        assert_eq!(out.mbmodes, modes.to_vec());
        assert_eq!(out.nmbs(), 4);
        // Step 1(d) output. MB 0's MV propagates to its luma (0..4) +
        // chroma (Cb 16, Cr 20). MB 1 / MB 3 carry (0, 0). MB 2's four
        // luma MVs land per block (8..12); its 4:2:0 chroma average is
        // (round(16/4), round(8/4)) = (4, 2) at Cb 18 / Cr 22.
        let mv0 = MotionVector { x: 2, y: -3 };
        let avg = MotionVector { x: 4, y: 2 };
        let z = MotionVector::ZERO;
        let expected = vec![
            mv0, mv0, mv0, mv0, // MB 0 luma
            z, z, z, z, // MB 1 luma (INTER_NOMV)
            four[0], four[1], four[2], four[3], // MB 2 luma
            z, z, z, z, // MB 3 luma (INTER_GOLDEN_NOMV)
            mv0, z, avg, z, // Cb plane, MBs 0..4
            mv0, z, avg, z, // Cr plane, MBs 0..4
        ];
        assert_eq!(out.mvects, expected);
        // Step 1(e): NQIS=1 → all-zero QIIS, no bits read.
        assert_eq!(out.qiis, vec![0u8; 24]);
        // Step 1(f): token 0 closes each block at ti=0 — all-zero
        // residuals, NCOEFFS=0. Step 1(g): zero residual + zero
        // predictor (LASTDC stays 0 on every reference row) leaves
        // every DC at zero.
        assert_eq!(out.coeffs, vec![[0i16; 64]; 24]);
        assert_eq!(out.ncoeffs, vec![0u8; 24]);
    }

    /// §7.11 step 1(a)+(b)+(c)+(d) inter path with a genuinely mixed
    /// `BCODED`, confirming the per-block short-run stream is decoded
    /// off the shared reader after the two long-run passes, and that
    /// §7.5.2's step 3(g) writes the decoded MV only to the *coded*
    /// blocks of each macro block — the bit cursor stays continuous
    /// across all of §7.1 + §7.3 + §7.4 + §7.5.2.
    #[test]
    fn data_header_and_blocks_inter_shared_reader_mixed_bcoded() {
        // 3 super blocks of 8 blocks each → NBS=24 (16 luma + 4 Cb +
        // 4 Cr). SB 0 is partially coded, SBs 1 and 2 fully coded.
        let nsbs = 3u32;
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        // The per-block bits inside the partially-coded SB 0.
        let sb0_blocks = [1u8, 1, 0, 0, 1, 0, 1, 1];
        let mut w = BitWriter::new();
        // §7.1 inter header (three qi values to push the §7.3 start
        // well off a byte boundary).
        w.put(0, 1); // data-packet flag
        w.put(1, 1); // FTYPE = inter
        w.put(5, 6); // QIS[0]
        w.put(1, 1); // MOREQIS = 1
        w.put(9, 6); // QIS[1]
        w.put(1, 1); // MOREQIS = 1
        w.put(40, 6); // QIS[2]
                      // §7.3: SBPCODED = [1, 0, 0] (SB 0 partial), SBFCODED over
                      // the non-partial subset = [1, 1] (SBs 1 and 2 fully
                      // coded), then the per-block short-run stream for SB 0.
        encode_long_run_runs(&mut w, &[1, 0, 0]);
        encode_long_run_runs(&mut w, &[1, 1]);
        encode_short_run_runs(&mut w, &sb0_blocks);
        // §7.4 resumes on the SAME bitstream after the short-run
        // stream. With BCODED = sb0_blocks ++ [1;16] every MB owns at
        // least one coded luma block, so all four read modes.
        // MSCHEME=7 → direct 3-bit modes.
        let modes = [
            MacroBlockMode::InterMvLast,
            MacroBlockMode::InterMv,
            MacroBlockMode::Intra,
            MacroBlockMode::InterGoldenMv,
        ];
        w.put(7, 3); // MSCHEME = 7
        for m in &modes {
            w.put(m.to_index() as u32, 3);
        }
        // §7.5.2 resumes on the SAME bitstream. MVMODE=1. MB 0
        // (INTER_MV_LAST) reuses LAST1 = (0, 0), no bits. MB 1
        // (INTER_MV) reads one MV. MB 2 (INTRA) emits zero, no bits.
        // MB 3 (INTER_GOLDEN_MV) reads one MV without a LAST update.
        w.put(1, 1); // MVMODE = 1
        write_mv_fixed_component(&mut w, -5); // MB 1 MVX
        write_mv_fixed_component(&mut w, 6); // MB 1 MVY
        write_mv_fixed_component(&mut w, 1); // MB 3 MVX
        write_mv_fixed_component(&mut w, 0); // MB 3 MVY
                                             // §7.6 resumes on the SAME bitstream. NQIS=3 → two §7.2.1
                                             // long-run passes. The 21 coded blocks (5 in SB 0 + 16 in
                                             // SBs 1/2) are visited in ascending bi; pass 0 promotes the
                                             // first two (bi 0 and 1) to qii=1, pass 1 (NBITS=2, only the
                                             // promoted pair) promotes bi 0 again to qii=2.
        let mut qi_pass0 = vec![0u8; 21];
        qi_pass0[0] = 1;
        qi_pass0[1] = 1;
        encode_long_run_runs(&mut w, &qi_pass0);
        encode_long_run_runs(&mut w, &[1, 0]);
        // §7.7.3 resumes on the SAME bitstream: htiL/htiC at ti ∈
        // {0, 1}; single-leaf token-0 tables close every coded block
        // at ti=0 with no further bits.
        w.put(0, 4); // htiL at ti=0
        w.put(0, 4); // htiC at ti=0
        w.put(0, 4); // htiL at ti=1
        w.put(0, 4); // htiC at ti=1
        let packet = w.finish();
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let out = decode_data_packet_header_and_blocks(
            &packet,
            false,
            PixelFormat::Yuv420,
            nsbs,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap();
        assert_eq!(out.ftype(), FrameType::Inter);
        assert_eq!(out.header.qis, vec![5, 9, 40]);
        assert_eq!(out.nqis(), 3);
        let mut expected = sb0_blocks.to_vec();
        expected.extend_from_slice(&[1u8; 16]); // SBs 1 + 2 fully coded
        assert_eq!(out.bcoded, expected);
        assert_eq!(out.nbs(), 24);
        assert_eq!(out.mbmodes, modes.to_vec());
        // Step 1(d) output. MB 1's MV lands on its coded luma blocks
        // only (4, 6, 7 — block 5 is uncoded and keeps (0, 0)) plus
        // its coded chroma (Cb 17, Cr 21). MB 3's MV covers blocks
        // 12..16 + Cb 19 / Cr 23. MB 0 (LAST1 = (0, 0)) and MB 2
        // (INTRA) leave zeros.
        let mv1 = MotionVector { x: -5, y: 6 };
        let mv3 = MotionVector { x: 1, y: 0 };
        let z = MotionVector::ZERO;
        let expected_mvs = vec![
            z, z, z, z, // MB 0 luma (INTER_MV_LAST reusing zero LAST1)
            mv1, z, mv1, mv1, // MB 1 luma — block 5 uncoded stays zero
            z, z, z, z, // MB 2 luma (INTRA)
            mv3, mv3, mv3, mv3, // MB 3 luma
            z, mv1, z, mv3, // Cb plane, MBs 0..4
            z, mv1, z, mv3, // Cr plane, MBs 0..4
        ];
        assert_eq!(out.mvects, expected_mvs);
        // Step 1(e): the two §7.6 passes ran mid-stream. Coded block
        // bi=0 took a 1 in both passes (qii=2), bi=1 only in pass 0
        // (qii=1); every other block (coded or not) stays at 0.
        let mut expected_qiis = vec![0u8; 24];
        expected_qiis[0] = 2;
        expected_qiis[1] = 1;
        assert_eq!(out.qiis, expected_qiis);
        // Step 1(f) + 1(g): token 0 closes each coded block at ti=0;
        // zero residuals + zero predictors keep every DC at zero.
        assert_eq!(out.coeffs, vec![[0i16; 64]; 24]);
        assert_eq!(out.ncoeffs, vec![0u8; 24]);
    }

    /// §7.11 step 1(a) reject: a header packet (high bit set)
    /// propagates §7.1's [`Error::NotDataPacket`] through the composed
    /// driver before §7.3 ever runs.
    #[test]
    fn data_header_and_blocks_rejects_header_packet() {
        let map = vec![0u32; 24];
        let mb_map = vec![[0u32; 4]; 4];
        let chroma = vec![&[0u32][..]; 4];
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(4, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let err = decode_data_packet_header_and_blocks(
            &[0x80],
            true,
            PixelFormat::Yuv420,
            3,
            24,
            4,
            &map,
            &mb_map,
            ChromaBlockLayout {
                cb: &chroma,
                cr: &chroma,
            },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap_err();
        assert!(matches!(err, Error::NotDataPacket));
    }

    /// §7.11 step 1(a) reject: the first frame must be intra
    /// (§7.1 step 2). An inter header with `first_frame = true`
    /// surfaces [`Error::FirstFrameMustBeIntra`] from the §7.1 link.
    #[test]
    fn data_header_and_blocks_rejects_inter_first_frame() {
        let packet = build_frame_header(1, &[7], 0);
        let map = vec![0u32; 16];
        let mb_map = vec![[0u32; 4]; 4];
        let chroma = vec![&[0u32][..]; 4];
        let hts = make_uniform_hts(0);
        let b2m = vec![0u32; 16];
        let neigh = vec![DcPredictorNeighbors::default(); 16];
        let y_plane: Vec<u32> = (0..16).collect();
        let planes: Vec<&[u32]> = vec![&y_plane, &[], &[]];
        let err = decode_data_packet_header_and_blocks(
            &packet,
            true,
            PixelFormat::Yuv420,
            2,
            16,
            4,
            &map,
            &mb_map,
            ChromaBlockLayout {
                cb: &chroma,
                cr: &chroma,
            },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap_err();
        assert!(matches!(err, Error::FirstFrameMustBeIntra { ftype: 1 }));
    }

    /// §7.11 step 1(b) reject: a malformed block→super-block map
    /// (wrong length) propagates §7.3's
    /// [`Error::BlockSuperBlockMapLenMismatch`] — the header decodes
    /// fine but the §7.3 link rejects the geometry.
    #[test]
    fn data_header_and_blocks_propagates_block_map_len_mismatch() {
        let packet = build_frame_header(0, &[3], 0);
        // Map is one short of NBS.
        let map = vec![0u32; 23];
        let mb_map = vec![[0u32; 4]; 4];
        let chroma = vec![&[0u32][..]; 4];
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(4, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let err = decode_data_packet_header_and_blocks(
            &packet,
            true,
            PixelFormat::Yuv420,
            3,
            24,
            4,
            &map,
            &mb_map,
            ChromaBlockLayout {
                cb: &chroma,
                cr: &chroma,
            },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap_err();
        assert!(matches!(
            err,
            Error::BlockSuperBlockMapLenMismatch {
                map_len: 23,
                nbs: 24
            }
        ));
    }

    /// `ftype()` / `nqis()` / `nbs()` / `nmbs()` accessors mirror the
    /// underlying header + `BCODED` + `MBMODES` state for an intra
    /// decode, and the `mvects` / `qiis` / `coeffs` / `ncoeffs`
    /// arrays are sized `NBS` like `bcoded`. With `NQIS=2` on an
    /// intra frame the §7.6 link reads one long-run pass over all 24
    /// (all-coded) blocks — this also pins that step 1(e) is *not*
    /// gated on `FTYPE` (only 1(d) is): intra frames with `NQIS > 1`
    /// carry block-level qi bits.
    #[test]
    fn data_header_and_blocks_accessors_match_state() {
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(0, 1); // FTYPE = intra
        w.put(1, 6); // QIS[0]
        w.put(1, 1); // MOREQIS = 1
        w.put(2, 6); // QIS[1]
        w.put(0, 1); // MOREQIS = 0
        w.put(0, 3); // §7.1 step 7 reserved trailer
                     // §7.6 (step 1(e)): one pass over the 24 coded blocks;
                     // promote block 5 to qii=1.
        let mut qi_pass0 = vec![0u8; 24];
        qi_pass0[5] = 1;
        encode_long_run_runs(&mut w, &qi_pass0);
        // §7.7.3 (step 1(f)): htiL/htiC at ti ∈ {0, 1}.
        w.put(0, 4);
        w.put(0, 4);
        w.put(0, 4);
        w.put(0, 4);
        let packet = w.finish();
        let out = decode_data_packet_header_and_blocks(
            &packet,
            true,
            PixelFormat::Yuv420,
            3,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap();
        assert_eq!(out.ftype(), out.header.ftype);
        assert_eq!(out.nqis(), out.header.qis.len());
        assert_eq!(out.nbs(), out.bcoded.len());
        assert_eq!(out.nmbs(), out.mbmodes.len());
        assert_eq!(out.mvects.len(), out.bcoded.len());
        assert_eq!(out.qiis.len(), out.bcoded.len());
        assert_eq!(out.coeffs.len(), out.bcoded.len());
        assert_eq!(out.ncoeffs.len(), out.bcoded.len());
        assert_eq!(out.nqis(), 2);
        assert_eq!(out.nbs(), 24);
        assert_eq!(out.nmbs(), 4);
        let mut expected_qiis = vec![0u8; 24];
        expected_qiis[5] = 1;
        assert_eq!(out.qiis, expected_qiis);
    }

    /// §7.11 step 1(c) reject: a §7.4 luma-block map of the wrong
    /// length propagates [`Error::MacroBlockLumaMapLenMismatch`] — the
    /// §7.1 header and §7.3 flags decode fine, but the §7.4 link
    /// rejects the macro-block geometry. Uses an inter frame so §7.4
    /// actually reaches its argument checks (the intra path validates
    /// the map too, but exercising it on an inter frame confirms the
    /// reject fires before any mode bit is consumed).
    #[test]
    fn data_header_and_blocks_propagates_mb_luma_map_len_mismatch() {
        let nsbs = 2u32;
        let nbs = 16u32;
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(1, 1); // FTYPE = inter
        w.put(7, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
        encode_long_run_runs(&mut w, &[0, 0]); // SBPCODED all 0
        encode_long_run_runs(&mut w, &[1, 1]); // SBFCODED all coded
        let packet = w.finish();
        // NMBS claimed as 4 but the map carries only 3 entries.
        let mb_map = vec![[0u32, 1, 2, 3]; 3];
        let chroma = vec![&[0u32][..]; 4];
        let hts = make_uniform_hts(0);
        let b2m = vec![0u32; 16];
        let neigh = vec![DcPredictorNeighbors::default(); 16];
        let y_plane: Vec<u32> = (0..16).collect();
        let planes: Vec<&[u32]> = vec![&y_plane, &[], &[]];
        let err = decode_data_packet_header_and_blocks(
            &packet,
            false,
            PixelFormat::Yuv420,
            nsbs,
            nbs,
            4,
            &map,
            &mb_map,
            ChromaBlockLayout {
                cb: &chroma,
                cr: &chroma,
            },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap_err();
        assert!(matches!(
            err,
            Error::MacroBlockLumaMapLenMismatch {
                map_len: 3,
                nmbs: 4
            }
        ));
    }

    /// §7.11 step 1(c) inter path exercising §7.4 step 2(d)ii: a macro
    /// block whose four luma blocks are all uncoded gets
    /// [`MacroBlockMode::InterNoMv`] with **no** mode bits read, while
    /// its coded neighbours read a mode each. Confirms the shared
    /// reader stays aligned when §7.4 skips bits for an uncoded MB —
    /// the §7.5.2 stream that follows decodes correctly, including the
    /// `INTER_MV_FOUR` chroma rounding (`round(2/4) = 1`, ties away
    /// from zero).
    #[test]
    fn data_header_and_blocks_inter_uncoded_mb_reads_no_mode_bits() {
        // 3 super blocks of 8 blocks → NBS=24 (16 luma + 4 Cb + 4 Cr).
        // SB 0 partially coded so that MB 0's luma blocks (0..4) are
        // all uncoded.
        let nsbs = 3u32;
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        // BCODED for SB 0: blocks 0..4 uncoded, 4..8 coded. SBs 1 + 2
        // fully coded. So MB 0 (blocks 0..4) is wholly uncoded →
        // step 2(d)ii.
        let sb0_blocks = [0u8, 0, 0, 0, 1, 1, 1, 1];
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(1, 1); // FTYPE = inter
        w.put(7, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
        encode_long_run_runs(&mut w, &[1, 0, 0]); // SBPCODED = [1, 0, 0]
        encode_long_run_runs(&mut w, &[1, 1]); // SBFCODED for SBs 1 + 2
        encode_short_run_runs(&mut w, &sb0_blocks);
        // §7.4: MSCHEME=7. MB 0 is wholly uncoded → no bits, INTER_NOMV.
        // MBs 1, 2, 3 each read a direct 3-bit mode.
        let coded_modes = [
            MacroBlockMode::InterMv,
            MacroBlockMode::InterMvFour,
            MacroBlockMode::InterGoldenMv,
        ];
        w.put(7, 3); // MSCHEME = 7
        for m in &coded_modes {
            w.put(m.to_index() as u32, 3);
        }
        // §7.5.2 resumes on the SAME bitstream. MVMODE=1. MB 0
        // (INTER_NOMV) emits zero, no bits. MB 1 (INTER_MV) reads one
        // MV. MB 2 (INTER_MV_FOUR) reads four (all four luma coded).
        // MB 3 (INTER_GOLDEN_MV) reads one.
        w.put(1, 1); // MVMODE = 1
        write_mv_fixed_component(&mut w, 3); // MB 1 MVX
        write_mv_fixed_component(&mut w, 3); // MB 1 MVY
        let four = [
            MotionVector { x: 2, y: 0 },
            MotionVector { x: 2, y: 0 },
            MotionVector { x: 2, y: 0 },
            MotionVector { x: 2, y: 2 },
        ];
        for mv in &four {
            write_mv_fixed_component(&mut w, mv.x);
            write_mv_fixed_component(&mut w, mv.y);
        }
        write_mv_fixed_component(&mut w, 0); // MB 3 MVX
        write_mv_fixed_component(&mut w, -1); // MB 3 MVY
                                              // §7.6 reads zero bits (NQIS=1); §7.7.3 reads htiL/htiC at
                                              // ti ∈ {0, 1} and token-0-closes the 20 coded blocks.
        w.put(0, 4);
        w.put(0, 4);
        w.put(0, 4);
        w.put(0, 4);
        let packet = w.finish();
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let out = decode_data_packet_header_and_blocks(
            &packet,
            false,
            PixelFormat::Yuv420,
            nsbs,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap();
        let mut expected_bcoded = sb0_blocks.to_vec();
        expected_bcoded.extend_from_slice(&[1u8; 16]);
        assert_eq!(out.bcoded, expected_bcoded);
        assert_eq!(
            out.mbmodes,
            vec![
                MacroBlockMode::InterNoMv, // step 2(d)ii, no bits read
                MacroBlockMode::InterMv,
                MacroBlockMode::InterMvFour,
                MacroBlockMode::InterGoldenMv,
            ]
        );
        // Step 1(d) output. MB 2's 4:2:0 chroma average is
        // (round(8/4), round(2/4)) = (2, 1) — the y component
        // exercises the spec's ties-away-from-zero `round()`.
        let mv1 = MotionVector { x: 3, y: 3 };
        let avg = MotionVector { x: 2, y: 1 };
        let mv3 = MotionVector { x: 0, y: -1 };
        let z = MotionVector::ZERO;
        let expected_mvs = vec![
            z, z, z, z, // MB 0 luma (uncoded, INTER_NOMV)
            mv1, mv1, mv1, mv1, // MB 1 luma
            four[0], four[1], four[2], four[3], // MB 2 luma
            mv3, mv3, mv3, mv3, // MB 3 luma
            z, mv1, avg, mv3, // Cb plane, MBs 0..4
            z, mv1, avg, mv3, // Cr plane, MBs 0..4
        ];
        assert_eq!(out.mvects, expected_mvs);
        // Steps 1(e)/(f)/(g): NQIS=1 → all-zero QIIS; token 0 closes
        // every coded block with zero residuals; zero predictors keep
        // every DC at zero. Uncoded blocks 0..4 are never visited.
        assert_eq!(out.qiis, vec![0u8; 24]);
        assert_eq!(out.coeffs, vec![[0i16; 64]; 24]);
        assert_eq!(out.ncoeffs, vec![0u8; 24]);
    }

    /// §7.11 step 1(d) reject: a §7.5.2 chroma-block map of the wrong
    /// outer length propagates [`Error::MotionVectorChromaMapLenMismatch`]
    /// — the §7.1 / §7.3 / §7.4 links decode fine, but the §7.5.2 link
    /// rejects the chroma geometry before reading the `MVMODE` bit
    /// (the packet deliberately ends right after the §7.4 modes; any
    /// §7.5.2 bit read would surface as truncation instead).
    #[test]
    fn data_header_and_blocks_propagates_chroma_map_len_mismatch() {
        let nsbs = 3u32;
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        // Cb outer map is one short of NMBS; Cr is correct.
        let cb_full = slice_outer(&cb_o);
        let cb = &cb_full[..3];
        let cr = slice_outer(&cr_o);
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(1, 1); // FTYPE = inter
        w.put(7, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
        encode_long_run_runs(&mut w, &[0, 0, 0]); // SBPCODED all 0
        encode_long_run_runs(&mut w, &[1, 1, 1]); // SBFCODED all coded
        w.put(7, 3); // MSCHEME = 7
        for _ in 0..4 {
            w.put(MacroBlockMode::InterNoMv.to_index() as u32, 3);
        }
        let packet = w.finish();
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let err = decode_data_packet_header_and_blocks(
            &packet,
            false,
            PixelFormat::Yuv420,
            nsbs,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap_err();
        assert!(matches!(
            err,
            Error::MotionVectorChromaMapLenMismatch {
                plane: 0,
                map_len: 3,
                expected: 4
            }
        ));
    }

    /// §7.11 step 1(d) inter path pinning the §7.5.2 `LAST1` / `LAST2`
    /// register file through the composed driver, with `MVMODE=0`
    /// Table 7.23 Huffman MV components on the shared reader:
    /// `INTER_MV` seeds `LAST1`, `INTER_MV_LAST` reuses it with no
    /// bits, `INTER_MV_LAST2` swaps in the older register (still
    /// `(0, 0)`), and a final `INTER_MV` reads a fresh MV.
    #[test]
    fn data_header_and_blocks_inter_mv_last_registers_on_shared_reader() {
        let nsbs = 3u32;
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(1, 1); // FTYPE = inter
        w.put(7, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
        encode_long_run_runs(&mut w, &[0, 0, 0]); // SBPCODED all 0
        encode_long_run_runs(&mut w, &[1, 1, 1]); // SBFCODED all coded
        let modes = [
            MacroBlockMode::InterMv,
            MacroBlockMode::InterMvLast,
            MacroBlockMode::InterMvLast2,
            MacroBlockMode::InterMv,
        ];
        w.put(7, 3); // MSCHEME = 7
        for m in &modes {
            w.put(m.to_index() as u32, 3);
        }
        // §7.5.2: MVMODE=0 (Table 7.23 Huffman). Only MBs 0 and 3 read
        // MV bits; MBs 1 and 2 work the LAST registers.
        w.put(0, 1); // MVMODE = 0
        write_mv_huffman_component(&mut w, 4); // MB 0 MVX
        write_mv_huffman_component(&mut w, 1); // MB 0 MVY
        write_mv_huffman_component(&mut w, 7); // MB 3 MVX
        write_mv_huffman_component(&mut w, -7); // MB 3 MVY
                                                // §7.6 reads zero bits (NQIS=1); §7.7.3 reads htiL/htiC at
                                                // ti ∈ {0, 1} and token-0-closes the 24 coded blocks.
        w.put(0, 4);
        w.put(0, 4);
        w.put(0, 4);
        w.put(0, 4);
        let packet = w.finish();
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let out = decode_data_packet_header_and_blocks(
            &packet,
            false,
            PixelFormat::Yuv420,
            nsbs,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap();
        assert_eq!(out.mbmodes, modes.to_vec());
        // MB 0: (4, 1), LAST1 = (4, 1). MB 1 (INTER_MV_LAST): reuses
        // LAST1 = (4, 1). MB 2 (INTER_MV_LAST2): swaps LAST1/LAST2 →
        // emits the pre-MB-0 LAST2 = (0, 0). MB 3: fresh (7, -7).
        let mv0 = MotionVector { x: 4, y: 1 };
        let mv3 = MotionVector { x: 7, y: -7 };
        let z = MotionVector::ZERO;
        let expected = vec![
            mv0, mv0, mv0, mv0, // MB 0 luma
            mv0, mv0, mv0, mv0, // MB 1 luma (LAST1 reuse)
            z, z, z, z, // MB 2 luma (LAST2 = (0, 0))
            mv3, mv3, mv3, mv3, // MB 3 luma
            mv0, mv0, z, mv3, // Cb plane, MBs 0..4
            mv0, mv0, z, mv3, // Cr plane, MBs 0..4
        ];
        assert_eq!(out.mvects, expected);
        // Steps 1(e)/(f)/(g) ride the same reader after the MV bits.
        assert_eq!(out.qiis, vec![0u8; 24]);
        assert_eq!(out.coeffs, vec![[0i16; 64]; 24]);
        assert_eq!(out.ncoeffs, vec![0u8; 24]);
    }

    /// §7.11 step 1(e) is genuinely wired to the bitstream: an intra
    /// frame with `NQIS=2` requires a §7.6 long-run pass over all 24
    /// coded blocks, and a packet that ends right after the §7.1
    /// header (only `finish()` byte-padding follows) runs the reader
    /// dry mid-pass — surfacing §7.2.1's truncation reject through
    /// the composed driver. Were 1(e) not consuming bits, this packet
    /// would decode (1(f) would also have nothing to read, but the
    /// §7.6 pass dries the reader first).
    #[test]
    fn data_header_and_blocks_truncated_in_qi_pass() {
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(0, 1); // FTYPE = intra
        w.put(1, 6); // QIS[0]
        w.put(1, 1); // MOREQIS = 1
        w.put(2, 6); // QIS[1]
        w.put(0, 1); // MOREQIS = 0
        w.put(0, 3); // reserved trailer — 19 bits; finish() pads to 24
        let packet = w.finish();
        let err = decode_data_packet_header_and_blocks(
            &packet,
            true,
            PixelFormat::Yuv420,
            3,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap_err();
        assert!(matches!(err, Error::TruncatedHeader { .. }));
    }

    /// §7.11 step 1(f) reject path + shared-cursor `htiL` selection:
    /// the packet's `htiL` nibble (read mid-byte, straight after the
    /// intra header) selects Huffman table 3 for the first luma block
    /// at ti=0, and an empty `HTS[3]` surfaces
    /// [`Error::DctCoefficientEmptyHuffmanTable`] with the selected
    /// index through the composed driver — pinning both that 1(f) is
    /// wired and that its table index came off the shared reader at
    /// the right bit offset.
    #[test]
    fn data_header_and_blocks_propagates_empty_huffman_table() {
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let mut hts = make_uniform_hts(0);
        hts[3] = HuffmanTable {
            entries: vec![],
            nodes: vec![],
        };
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes = slice_outer(&planes_o);
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(0, 1); // FTYPE = intra
        w.put(9, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
        w.put(0, 3); // reserved trailer
        w.put(3, 4); // htiL at ti=0 → HG=0 ⇒ hti = 3 for luma blocks
        w.put(0, 4); // htiC at ti=0
        let packet = w.finish();
        let err = decode_data_packet_header_and_blocks(
            &packet,
            true,
            PixelFormat::Yuv420,
            3,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: &planes,
            },
        )
        .unwrap_err();
        assert!(matches!(
            err,
            Error::DctCoefficientEmptyHuffmanTable { hti: 3 }
        ));
    }

    /// §7.11 step 1(g) reject path: a `plane_raster_order` with only
    /// two plane slices propagates §7.8.2's
    /// [`Error::DcInversionPlaneCount`] through the composed driver —
    /// the bitstream work of steps 1(a)..1(f) completes, then the
    /// no-bit 1(g) link rejects the malformed geometry.
    #[test]
    fn data_header_and_blocks_propagates_dc_plane_count() {
        let nmbs = 4u32;
        let (nbs, mb_map, cb_o, cr_o) = build_uniform_layout(nmbs, PixelFormat::Yuv420);
        let map: Vec<u32> = (0..nbs).map(|bi| bi / 8).collect();
        let cb = slice_outer(&cb_o);
        let cr = slice_outer(&cr_o);
        let hts = make_uniform_hts(0);
        let (b2m, neigh, planes_o) = build_uniform_dc_geometry(nmbs, PixelFormat::Yuv420);
        let planes_full = slice_outer(&planes_o);
        let planes_two = &planes_full[..2];
        let mut w = BitWriter::new();
        w.put(0, 1); // data-packet flag
        w.put(0, 1); // FTYPE = intra
        w.put(9, 6); // QIS[0]
        w.put(0, 1); // MOREQIS = 0
        w.put(0, 3); // reserved trailer
        w.put(0, 4); // htiL at ti=0
        w.put(0, 4); // htiC at ti=0
        w.put(0, 4); // htiL at ti=1
        w.put(0, 4); // htiC at ti=1
        let packet = w.finish();
        let err = decode_data_packet_header_and_blocks(
            &packet,
            true,
            PixelFormat::Yuv420,
            3,
            nbs,
            nmbs,
            &map,
            &mb_map,
            ChromaBlockLayout { cb: &cb, cr: &cr },
            &hts,
            DcPredictionGeometry {
                block_to_macro_block: &b2m,
                neighbors: &neigh,
                plane_raster_order: planes_two,
            },
        )
        .unwrap_err();
        assert!(matches!(err, Error::DcInversionPlaneCount { got: 2 }));
    }

    // -----------------------------------------------------------------
    // §7.11 step 7 + step 8 — reference-frame promotion
    // -----------------------------------------------------------------

    /// Build a `ReconstructedFrame` of the given shape with each
    /// plane filled by a per-plane fill byte so the §7.11 step 7 /
    /// step 8 copy can be checked byte-for-byte.
    fn synth_reconstructed(
        dims_y: PlaneDimensions,
        dims_c: PlaneDimensions,
        fill_y: u8,
        fill_cb: u8,
        fill_cr: u8,
    ) -> ReconstructedFrame {
        let len_y = (dims_y.width as usize) * (dims_y.height as usize);
        let len_c = (dims_c.width as usize) * (dims_c.height as usize);
        ReconstructedFrame {
            samples_y: vec![fill_y; len_y],
            samples_cb: vec![fill_cb; len_c],
            samples_cr: vec![fill_cr; len_c],
            dims_y,
            dims_cb: dims_c,
            dims_cr: dims_c,
        }
    }

    /// `frame_type_from_ftype` round-trips both spec values and
    /// rejects everything else.
    #[test]
    fn frame_type_from_ftype_round_trips() {
        assert_eq!(frame_type_from_ftype(0).unwrap(), FrameType::Intra);
        assert_eq!(frame_type_from_ftype(1).unwrap(), FrameType::Inter);
        assert_eq!(frame_type_as_ftype(FrameType::Intra), 0);
        assert_eq!(frame_type_as_ftype(FrameType::Inter), 1);
        for ftype in 2u8..=255 {
            match frame_type_from_ftype(ftype) {
                Err(Error::FrameTypeOutOfRange { ftype: got }) => assert_eq!(got, ftype),
                other => panic!("expected FrameTypeOutOfRange for {ftype}, got {other:?}"),
            }
        }
    }

    /// `ReferenceFrameStore::zeroed` allocates all six plane buffers
    /// at the declared dimensions and zero-fills them.
    #[test]
    fn reference_frame_store_zeroed_allocates_correct_sizes() {
        let dims_y = PlaneDimensions {
            width: 32,
            height: 32,
        };
        let dims_c = PlaneDimensions {
            width: 16,
            height: 16,
        };
        let store = ReferenceFrameStore::zeroed(dims_y, dims_c).unwrap();
        assert_eq!(store.dims_y, dims_y);
        assert_eq!(store.dims_c, dims_c);
        assert_eq!(store.golden_y.len(), 32 * 32);
        assert_eq!(store.previous_y.len(), 32 * 32);
        assert_eq!(store.golden_cb.len(), 16 * 16);
        assert_eq!(store.golden_cr.len(), 16 * 16);
        assert_eq!(store.previous_cb.len(), 16 * 16);
        assert_eq!(store.previous_cr.len(), 16 * 16);
        assert!(store.golden_y.iter().all(|&b| b == 0));
        assert!(store.previous_y.iter().all(|&b| b == 0));
        assert!(store.golden_cb.iter().all(|&b| b == 0));
        assert!(store.golden_cr.iter().all(|&b| b == 0));
        assert!(store.previous_cb.iter().all(|&b| b == 0));
        assert!(store.previous_cr.iter().all(|&b| b == 0));
    }

    /// `from_reference_plane_dimensions` mirrors the Table 7.89 4:2:0
    /// row: chroma planes are halved on both axes.
    #[test]
    fn reference_frame_store_from_ref_dims_4_2_0() {
        let ref_dims = ReferencePlaneDimensions {
            rpyw: 32,
            rpyh: 32,
            rpcw: 16,
            rpch: 16,
        };
        let store = ReferenceFrameStore::from_reference_plane_dimensions(ref_dims).unwrap();
        assert_eq!(store.dims_y.width, 32);
        assert_eq!(store.dims_y.height, 32);
        assert_eq!(store.dims_c.width, 16);
        assert_eq!(store.dims_c.height, 16);
        assert_eq!(store.golden_y.len(), 32 * 32);
        assert_eq!(store.golden_cb.len(), 16 * 16);
    }

    /// `ReferenceFrameStore::new` rejects a Y-plane buffer that's the
    /// wrong size.
    #[test]
    fn reference_frame_store_new_rejects_wrong_y_len() {
        let dims_y = PlaneDimensions {
            width: 32,
            height: 32,
        };
        let dims_c = PlaneDimensions {
            width: 16,
            height: 16,
        };
        let bad_y = vec![0u8; 100]; // not 32*32 = 1024
        let ok_y = vec![0u8; 32 * 32];
        let ok_c = vec![0u8; 16 * 16];
        let err = ReferenceFrameStore::new(
            bad_y,
            ok_c.clone(),
            ok_c.clone(),
            ok_y.clone(),
            ok_c.clone(),
            ok_c.clone(),
            dims_y,
            dims_c,
        )
        .unwrap_err();
        match err {
            Error::ReferenceFrameStorePlaneLenMismatch {
                plane,
                got,
                expected,
            } => {
                assert_eq!(plane, "golden_y");
                assert_eq!(got, 100);
                assert_eq!(expected, 1024);
            }
            other => panic!("unexpected error: {other:?}"),
        }
    }

    /// `ReferenceFrameStore::new` rejects a chroma-plane buffer
    /// mismatch on the second slot (`golden_cb`).
