        // FRAME trace event: qis=44,32,50 nqps=3.
        assert_eq!(out.qis, vec![44, 32, 50]);
        assert_eq!(out.frame.dims_y.width, 32);
        assert_eq!(out.frame.dims_y.height, 32);
        assert_eq!(out.frame.dims_cb.width, 16);
